function extractManualPdfProviderIdFromPort(port) {
  const name = typeof port?.name === 'string' ? port.name.trim() : '';
  const prefix = 'manual-pdf-provider:';
  if (!name || !name.startsWith(prefix)) return '';
  const providerId = name.slice(prefix.length).trim();
  return providerId || '';
}

async function waitForManualPdfProviderPort(providerId, timeoutMs = 5000) {
  const safeProviderId = typeof providerId === 'string' ? providerId.trim() : '';
  if (!safeProviderId) return false;
  if (manualPdfProviderPorts.has(safeProviderId)) return true;
  const startedAt = Date.now();
  const maxWaitMs = Math.max(500, Math.min(15000, Number.isInteger(timeoutMs) ? timeoutMs : 5000));
  while (Date.now() - startedAt < maxWaitMs) {
    if (manualPdfProviderPorts.has(safeProviderId)) return true;
    await sleep(100);
  }
  return manualPdfProviderPorts.has(safeProviderId);
}

function normalizeComposerThinkingEffort(value) {
  const normalized = typeof value === 'string' ? value.trim().toLowerCase() : '';
  if (!normalized) return '';
  if (normalized === 'light' || normalized === 'standard' || normalized === 'extended' || normalized === 'heavy') {
    return normalized;
  }
  return '';
}

async function getStoredResumeComposerThinkingEffort() {
  try {
    const stored = await chrome.storage.local.get(RESUME_COMPOSER_THINKING_EFFORT_STORAGE_KEY);
    return normalizeComposerThinkingEffort(stored?.[RESUME_COMPOSER_THINKING_EFFORT_STORAGE_KEY]);
  } catch (error) {
    console.warn('[resume-effort] get stored value failed:', error?.message || error);
    return '';
  }
}

async function setStoredResumeComposerThinkingEffort(value) {
  const normalized = normalizeComposerThinkingEffort(value);
  try {
    if (normalized) {
      await chrome.storage.local.set({
        [RESUME_COMPOSER_THINKING_EFFORT_STORAGE_KEY]: normalized
      });
    } else {
      await chrome.storage.local.remove(RESUME_COMPOSER_THINKING_EFFORT_STORAGE_KEY);
    }
  } catch (error) {
    console.warn('[resume-effort] set stored value failed:', error?.message || error);
  }
  return normalized;
}

function isClosedProcessStatus(status) {
  return CLOSED_PROCESS_STATUSES.has(String(status || '').toLowerCase());
}

function normalizeProcessStatus(status) {
  if (typeof status !== 'string') return 'running';
  const normalized = status.trim().toLowerCase();
  return normalized || 'running';
}

function normalizePromptCounters(status, currentPrompt, totalPrompts, stageIndex) {
  let total = Number.isInteger(totalPrompts) ? totalPrompts : 0;
  let current = Number.isInteger(currentPrompt) ? currentPrompt : 0;
  const stage = Number.isInteger(stageIndex) ? stageIndex : null;

  if (total < 0) total = 0;
  if (current < 0) current = 0;

  if (total === 0 && Number.isInteger(stage) && stage >= 0) {
    total = stage + 1;
  }
  if (current === 0 && Number.isInteger(stage) && stage >= 0) {
    current = stage + 1;
  }
  if (total === 0 && current > 0) {
    total = current;
  }
  if (total > 0 && current > total) {
    current = total;
  }
  if (isClosedProcessStatus(status) && current === 0 && total > 0) {
    current = total;
  }
  if (status === 'completed' && total > 0) {
    current = total;
  }

  return { currentPrompt: current, totalPrompts: total };
}

function normalizeAutoRecoveryState(rawState) {
  if (!rawState || typeof rawState !== 'object') return null;

  const normalized = {};
  if (Number.isInteger(rawState.attempt) && rawState.attempt >= 0) {
    normalized.attempt = rawState.attempt;
  }
  if (Number.isInteger(rawState.maxAttempts) && rawState.maxAttempts > 0) {
    normalized.maxAttempts = rawState.maxAttempts;
  }
  if (Number.isInteger(rawState.delayMs) && rawState.delayMs >= 0) {
    normalized.delayMs = rawState.delayMs;
  }
  if (typeof rawState.reason === 'string' && rawState.reason.trim()) {
    normalized.reason = rawState.reason.trim();
  }
  if (Number.isInteger(rawState.currentPrompt) && rawState.currentPrompt >= 0) {
    normalized.currentPrompt = rawState.currentPrompt;
  }
  if (Number.isInteger(rawState.stageIndex) && rawState.stageIndex >= 0) {
    normalized.stageIndex = rawState.stageIndex;
  }
  if (Number.isInteger(rawState.updatedAt) && rawState.updatedAt > 0) {
    normalized.updatedAt = rawState.updatedAt;
  }

  if (Object.keys(normalized).length === 0) return null;
  if (!Number.isInteger(normalized.maxAttempts)) normalized.maxAttempts = AUTO_RECOVERY_MAX_ATTEMPTS;
  if (!Number.isInteger(normalized.delayMs)) normalized.delayMs = AUTO_RECOVERY_DELAY_MS;
  if (!Number.isInteger(normalized.attempt)) normalized.attempt = 0;
  return normalized;
}

function isFailedProcessStatus(status) {
  const normalized = normalizeProcessStatus(status);
  return normalized === 'failed' || normalized === 'error';
}

function collectProcessRecordAnomalies(record) {
  if (!record || typeof record !== 'object') return [];
  const anomalies = [];
  const status = normalizeProcessStatus(record.status);
  const currentPrompt = Number.isInteger(record.currentPrompt) ? record.currentPrompt : null;
  const totalPrompts = Number.isInteger(record.totalPrompts) ? record.totalPrompts : null;
  const hasTabOrWindow = Number.isInteger(record.tabId) || Number.isInteger(record.windowId);

  if (Number.isInteger(currentPrompt) && Number.isInteger(totalPrompts) && currentPrompt > totalPrompts) {
    anomalies.push('current_gt_total');
  }
  if (isClosedProcessStatus(status) && record.needsAction) {
    anomalies.push('closed_with_needs_action');
  }
  if (!isClosedProcessStatus(status) && !hasTabOrWindow) {
    anomalies.push('running_without_tab_or_window');
  }
  if (isFailedProcessStatus(status) && !record.reason && !record.error) {
    anomalies.push('failed_without_reason');
  }
  return anomalies;
}

function collectNormalizationCorrections(next, patch) {
  const corrections = [];
  if (!next || !patch || typeof patch !== 'object') return corrections;

  if (Number.isInteger(patch.currentPrompt) && patch.currentPrompt !== next.currentPrompt) {
    corrections.push(`currentPrompt:${patch.currentPrompt}->${next.currentPrompt}`);
  }
  if (Number.isInteger(patch.totalPrompts) && patch.totalPrompts !== next.totalPrompts) {
    corrections.push(`totalPrompts:${patch.totalPrompts}->${next.totalPrompts}`);
  }
  if (typeof patch.needsAction === 'boolean' && patch.needsAction !== next.needsAction) {
    corrections.push(`needsAction:${patch.needsAction}->${next.needsAction}`);
  }
  if (Number.isInteger(patch.stageIndex)) {
    const normalizedStage = Number.isInteger(next.stageIndex) ? next.stageIndex : null;
    if (patch.stageIndex !== normalizedStage) {
      corrections.push(`stageIndex:${patch.stageIndex}->${normalizedStage}`);
    }
  }
  if (typeof patch.status === 'string') {
    const patchStatus = normalizeProcessStatus(patch.status);
    if (patchStatus !== next.status) {
      corrections.push(`status:${patchStatus}->${next.status}`);
    }
  }
  return corrections;
}

function logProcessTransition(runId, next, patch) {
  const anomalies = collectProcessRecordAnomalies(next);
  const corrections = collectNormalizationCorrections(next, patch);
  if (anomalies.length === 0 && corrections.length === 0) return;

  console.warn('[monitor] Skorygowano niespojne dane procesu', {
    runId,
    corrections,
    anomalies,
    status: next.status,
    currentPrompt: next.currentPrompt,
    totalPrompts: next.totalPrompts,
    stageIndex: Number.isInteger(next.stageIndex) ? next.stageIndex : null
  });
}

function normalizeProcessRecord(record) {
  if (!record || typeof record !== 'object') return null;
  const id = typeof record.id === 'string' ? record.id : String(record.id || '');
  if (!id) return null;

  const status = normalizeProcessStatus(record.status);
  const normalizedCounters = normalizePromptCounters(
    status,
    record.currentPrompt,
    record.totalPrompts,
    record.stageIndex
  );

  const normalized = {
    ...record,
    id,
    title: typeof record.title === 'string' && record.title.trim()
      ? record.title
      : 'Bez tytulu',
    analysisType: typeof record.analysisType === 'string' && record.analysisType.trim()
      ? record.analysisType
      : 'company',
    status,
    currentPrompt: normalizedCounters.currentPrompt,
    totalPrompts: normalizedCounters.totalPrompts,
    timestamp: Number.isInteger(record.timestamp) ? record.timestamp : Date.now(),
    startedAt: Number.isInteger(record.startedAt)
      ? record.startedAt
      : (Number.isInteger(record.timestamp) ? record.timestamp : Date.now()),
    needsAction: isClosedProcessStatus(status) ? false : !!record.needsAction,
    messages: Array.isArray(record.messages) ? record.messages : []
  };

  if (!Number.isInteger(normalized.windowId)) delete normalized.windowId;
  if (!Number.isInteger(normalized.tabId)) delete normalized.tabId;
  if (typeof normalized.reason !== 'string') delete normalized.reason;
  if (typeof normalized.statusText !== 'string') delete normalized.statusText;
  if (typeof normalized.stageName !== 'string') delete normalized.stageName;
  if (!Number.isInteger(normalized.stageIndex)) delete normalized.stageIndex;
  const normalizedChatUrl = normalizeChatConversationUrl(
    typeof normalized.chatUrl === 'string' ? normalized.chatUrl : ''
  );
  if (normalizedChatUrl) {
    normalized.chatUrl = normalizedChatUrl;
  } else {
    delete normalized.chatUrl;
  }
  const normalizedConversationUrls = normalizeConversationUrlList([
    ...(Array.isArray(normalized.conversationUrls) ? normalized.conversationUrls : []),
    normalized.chatUrl || ''
  ]);
  if (normalizedConversationUrls.length > 0) {
    normalized.conversationUrls = normalizedConversationUrls;
    if (!normalized.chatUrl) {
      normalized.chatUrl = normalizedConversationUrls[normalizedConversationUrls.length - 1];
    }
  } else {
    delete normalized.conversationUrls;
  }
  if (typeof normalized.sourceUrl !== 'string') delete normalized.sourceUrl;
  if (typeof normalized.error !== 'string') delete normalized.error;
  if (!Number.isInteger(normalized.finishedAt)) delete normalized.finishedAt;
  if (Number.isInteger(normalized.stageIndex) && normalized.totalPrompts > 0) {
    if (normalized.stageIndex < 0) {
      delete normalized.stageIndex;
    } else if (normalized.stageIndex >= normalized.totalPrompts) {
      normalized.stageIndex = normalized.totalPrompts - 1;
    }
  }
  if (Number.isInteger(normalized.stageIndex) && normalized.stageIndex >= 0) {
    const promptFromStage = normalized.stageIndex + 1;
    if (!Number.isInteger(normalized.currentPrompt) || normalized.currentPrompt < promptFromStage) {
      normalized.currentPrompt = promptFromStage;
    }
  }
  if (normalized.totalPrompts > 0 && normalized.currentPrompt === 0 && Number.isInteger(normalized.stageIndex)) {
    normalized.currentPrompt = Math.min(normalized.stageIndex + 1, normalized.totalPrompts);
  }
  if (normalized.totalPrompts > 0 && normalized.currentPrompt > normalized.totalPrompts) {
    normalized.currentPrompt = normalized.totalPrompts;
  }
  if (normalized.currentPrompt < 0) {
    normalized.currentPrompt = 0;
  }
  if (Number.isInteger(normalized.currentPrompt) && normalized.currentPrompt > 0) {
    const derivedStageIndex = normalized.currentPrompt - 1;
    if (!Number.isInteger(normalized.stageIndex) || normalized.stageIndex < derivedStageIndex) {
      normalized.stageIndex = derivedStageIndex;
    }
    if (normalized.totalPrompts > 0 && normalized.stageIndex >= normalized.totalPrompts) {
      normalized.stageIndex = normalized.totalPrompts - 1;
    }
  }
  if (normalized.startedAt > normalized.timestamp) {
    normalized.startedAt = normalized.timestamp;
  }
  if (Number.isInteger(normalized.finishedAt) && normalized.finishedAt < normalized.startedAt) {
    normalized.finishedAt = normalized.timestamp;
  }
  if (isClosedProcessStatus(status)) {
    delete normalized.autoRecovery;
  } else {
    const normalizedAutoRecovery = normalizeAutoRecoveryState(normalized.autoRecovery);
    if (normalizedAutoRecovery) {
      normalized.autoRecovery = normalizedAutoRecovery;
    } else {
      delete normalized.autoRecovery;
    }
  }

  return normalized;
}

function normalizeConversationUrlList(rawValues, limit = PROCESS_CONVERSATION_URL_HISTORY_LIMIT) {
  const values = Array.isArray(rawValues) ? rawValues : [];
  const dedup = [];
  const seen = new Set();
  for (const value of values) {
    const normalized = normalizeChatConversationUrl(typeof value === 'string' ? value : '');
    if (!normalized || seen.has(normalized)) continue;
    seen.add(normalized);
    dedup.push(normalized);
  }
  if (!Number.isInteger(limit) || limit <= 0 || dedup.length <= limit) return dedup;
  return dedup.slice(dedup.length - limit);
}

function mergeProcessConversationUrls(existingRecord, nextRecord) {
  if (!nextRecord || typeof nextRecord !== 'object') return;
  const merged = normalizeConversationUrlList([
    ...(Array.isArray(existingRecord?.conversationUrls) ? existingRecord.conversationUrls : []),
    typeof existingRecord?.chatUrl === 'string' ? existingRecord.chatUrl : '',
    ...(Array.isArray(nextRecord?.conversationUrls) ? nextRecord.conversationUrls : []),
    typeof nextRecord?.chatUrl === 'string' ? nextRecord.chatUrl : ''
  ]);
  if (merged.length === 0) {
    delete nextRecord.conversationUrls;
    return;
  }
  nextRecord.conversationUrls = merged;
  const latest = merged[merged.length - 1];
  if (!normalizeChatConversationUrl(nextRecord.chatUrl || '')) {
    nextRecord.chatUrl = latest;
  }
}

function pruneProcessRecords(records) {
  const normalized = (Array.isArray(records) ? records : [])
    .map(normalizeProcessRecord)
    .filter(Boolean);

  const byId = new Map();
  normalized.forEach((record) => {
    const existing = byId.get(record.id);
    if (!existing) {
      byId.set(record.id, record);
      return;
    }
    const existingTs = Number.isInteger(existing.timestamp) ? existing.timestamp : 0;
    const nextTs = Number.isInteger(record.timestamp) ? record.timestamp : 0;
    if (nextTs >= existingTs) {
      byId.set(record.id, record);
    }
  });

  const deduped = Array.from(byId.values());
  const active = [];
  const closedRecoverable = [];
  const closedHistory = [];
  for (const process of deduped) {
    if (isClosedProcessStatus(process.status)) {
      if (isRecoverableUnfinishedProcess(process)) {
        closedRecoverable.push(process);
      } else {
        closedHistory.push(process);
      }
    } else {
      active.push(process);
    }
  }

  active.sort((a, b) => (b.startedAt || b.timestamp || 0) - (a.startedAt || a.timestamp || 0));
  closedRecoverable.sort((a, b) => (b.timestamp || 0) - (a.timestamp || 0));
  closedHistory.sort((a, b) => (b.timestamp || 0) - (a.timestamp || 0));

  // Keep all recoverable unfinished runs; only completed/non-recoverable history is trimmed.
  return active.concat(closedRecoverable, closedHistory.slice(0, PROCESS_HISTORY_LIMIT));
}

function rehydrateProcessProblemLogState(records = []) {
  problemLogLastSignatureByRunId.clear();
  processLogLastEmitTsByRunId.clear();
  processStaleWarnLastEmitTsByRunId.clear();

  const sourceRecords = Array.isArray(records) ? records : [];
  const nowTs = Date.now();
  for (const record of sourceRecords) {
    if (!record || typeof record !== 'object') continue;
    const runId = typeof record.id === 'string' ? record.id.trim() : '';
    if (!runId) continue;
    if (isClosedProcessStatus(record.status)) continue;

    const entry = buildProcessProblemLogEntry(runId, record);
    const signature = typeof entry?.signature === 'string' ? entry.signature.trim() : '';
    if (!signature) continue;

    problemLogLastSignatureByRunId.set(runId, signature);
    const ts = Number.isInteger(record.timestamp) && record.timestamp > 0
      ? record.timestamp
      : nowTs;
    processLogLastEmitTsByRunId.set(runId, ts);
  }
}

async function ensureProcessRegistryReady() {
  if (!processRegistryReady) {
    processRegistryReady = (async () => {
      try {
        const stored = await chrome.storage.local.get([PROCESS_MONITOR_STORAGE_KEY]);
        const records = pruneProcessRecords(stored?.[PROCESS_MONITOR_STORAGE_KEY]);
        processRegistry.clear();
        records.forEach((record) => {
          processRegistry.set(record.id, record);
        });
        rehydrateProcessProblemLogState(records);
      } catch (error) {
        console.warn('[monitor] Failed to read process monitor state:', error);
        processRegistry.clear();
        problemLogLastSignatureByRunId.clear();
        processLogLastEmitTsByRunId.clear();
        processStaleWarnLastEmitTsByRunId.clear();
      }
    })();
  }
  return processRegistryReady;
}

async function persistProcessRegistry() {
  const records = pruneProcessRecords(Array.from(processRegistry.values()));
  processRegistry.clear();
  records.forEach((record) => {
    processRegistry.set(record.id, record);
  });
  await chrome.storage.local.set({ [PROCESS_MONITOR_STORAGE_KEY]: records });
  return records;
}

async function getProcessSnapshot() {
  await ensureProcessRegistryReady();
  return pruneProcessRecords(Array.from(processRegistry.values()));
}

async function broadcastProcessUpdate() {
  const processes = await getProcessSnapshot();
  try {
    await chrome.runtime.sendMessage({
      type: 'PROCESSES_UPDATE',
      processes
    });
  } catch (error) {
    // Ignore: no listeners currently connected.
  }
  return processes;
}

function ensureProcessMonitorHeartbeatAlarm() {
  if (!chrome?.alarms?.create) return;
  try {
    chrome.alarms.create(PROCESS_MONITOR_HEARTBEAT.alarmName, {
      periodInMinutes: PROCESS_MONITOR_HEARTBEAT.alarmPeriodMinutes
    });
  } catch (error) {
    console.warn('[monitor] process heartbeat alarm failed:', error);
  }
}

function pruneProcessStaleWarnMap(nowTs = Date.now()) {
  if (processStaleWarnLastEmitTsByRunId.size <= PROBLEM_LOG_MAX_ITEMS) return;
  const staleThreshold = nowTs - (PROCESS_MONITOR_HEARTBEAT.staleWarnCooldownMs * 8);
  for (const [key, value] of processStaleWarnLastEmitTsByRunId.entries()) {
    if (!Number.isInteger(value) || value < staleThreshold) {
      processStaleWarnLastEmitTsByRunId.delete(key);
    }
    if (processStaleWarnLastEmitTsByRunId.size <= PROBLEM_LOG_MAX_ITEMS) {
      return;
    }
  }
}

function shouldEmitProcessStaleWarning(runId, nowTs = Date.now()) {
  if (!runId) return false;
  const previousTs = processStaleWarnLastEmitTsByRunId.get(runId);
  if (
    Number.isInteger(previousTs)
    && (nowTs - previousTs) < PROCESS_MONITOR_HEARTBEAT.staleWarnCooldownMs
  ) {
    return false;
  }
  processStaleWarnLastEmitTsByRunId.set(runId, nowTs);
  return true;
}

async function appendProcessHeartbeatStaleWarning(process, staleMs, origin, nowTs) {
  if (!process || typeof process !== 'object') return false;
  const runId = typeof process.id === 'string' ? process.id : '';
  if (!runId) return false;
  const status = normalizeProcessStatus(process.status || '');
  const staleSeconds = Math.max(0, Math.round(staleMs / 1000));
  const safeCurrentPrompt = Number.isInteger(process.currentPrompt) ? process.currentPrompt : null;
  const safeTotalPrompts = Number.isInteger(process.totalPrompts) ? process.totalPrompts : null;
  const safeStageIndex = Number.isInteger(process.stageIndex) ? process.stageIndex : null;
  const stageName = typeof process.stageName === 'string' ? process.stageName : '';
  const statusText = `origin=${origin || 'heartbeat'} stale_for_s=${staleSeconds}`;
  const signatureBucket = Math.floor(nowTs / PROCESS_MONITOR_HEARTBEAT.staleWarnCooldownMs);

  const entry = await appendProblemLog({
    timestamp: nowTs,
    level: 'warn',
    source: 'process-monitor-heartbeat',
    category: 'process_state',
    runId,
    title: typeof process.title === 'string' ? process.title : '',
    analysisType: typeof process.analysisType === 'string' ? process.analysisType : '',
    status,
    reason: 'heartbeat_stale',
    statusText,
    message: `No process progress update for ${staleSeconds}s`,
    currentPrompt: safeCurrentPrompt,
    totalPrompts: safeTotalPrompts,
    stageIndex: safeStageIndex,
    stageName,
    tabId: Number.isInteger(process.tabId) ? process.tabId : null,
    windowId: Number.isInteger(process.windowId) ? process.windowId : null,
    chatUrl: typeof process.chatUrl === 'string' ? process.chatUrl : '',
    signature: [
      'process-monitor-heartbeat-stale',
      runId,
      status,
      Number.isInteger(safeCurrentPrompt) ? safeCurrentPrompt : '',
      Number.isInteger(safeTotalPrompts) ? safeTotalPrompts : '',
      Number.isInteger(safeStageIndex) ? safeStageIndex : '',
      stageName,
      signatureBucket
    ].join('|')
  });
  return !!entry;
}

async function runProcessMonitorHeartbeatSweep(origin = 'alarm') {
  if (processMonitorHeartbeatSweepInProgress) {
    return { success: false, skipped: true, reason: 'heartbeat_sweep_in_progress' };
  }
  processMonitorHeartbeatSweepInProgress = true;
  try {
    await ensureProcessRegistryReady();
    const snapshot = pruneProcessRecords(Array.from(processRegistry.values()));
    const nowTs = Date.now();
    const active = snapshot.filter((process) => process && !isClosedProcessStatus(process.status));

    let staleDetected = 0;
    let staleLogged = 0;
    let touched = 0;
    let fresh = 0;

    for (const process of active) {
      const runId = typeof process?.id === 'string' ? process.id : '';
      if (!runId) continue;

      const processTs = Number.isInteger(process.timestamp) ? process.timestamp : 0;
      const ageMs = processTs > 0 ? Math.max(0, nowTs - processTs) : Number.MAX_SAFE_INTEGER;

      if (ageMs >= PROCESS_MONITOR_HEARTBEAT.staleTtlMs) {
        staleDetected += 1;
        if (shouldEmitProcessStaleWarning(runId, nowTs)) {
          const appended = await appendProcessHeartbeatStaleWarning(process, ageMs, origin, nowTs);
          if (appended) staleLogged += 1;
        }
      } else {
        processStaleWarnLastEmitTsByRunId.delete(runId);
      }

      if (ageMs < PROCESS_MONITOR_HEARTBEAT.touchIntervalMs) {
        fresh += 1;
        continue;
      }

      const touchedRecord = await upsertProcess(runId, { timestamp: nowTs });
      if (touchedRecord) touched += 1;
    }

    pruneProcessStaleWarnMap(nowTs);
    return {
      success: true,
      origin,
      active: active.length,
      touched,
      fresh,
      staleDetected,
      staleLogged
    };
  } catch (error) {
    console.warn('[monitor] process heartbeat sweep failed:', error);
    return {
      success: false,
      origin,
      error: error?.message || String(error)
    };
  } finally {
    processMonitorHeartbeatSweepInProgress = false;
  }
}

function createReloadResumeMonitorSessionId(prefix = 'reload-resume') {
  const normalizedPrefix = typeof prefix === 'string' && prefix.trim()
    ? prefix.trim().toLowerCase().replace(/[^a-z0-9_-]+/g, '-').replace(/-+/g, '-')
    : 'reload-resume';
  const safePrefix = normalizedPrefix || 'reload-resume';
  return `${safePrefix}-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
}

function toNonNegativeInt(value, fallback = 0) {
  if (!Number.isFinite(value)) return fallback;
  const normalized = Math.trunc(value);
  if (normalized < 0) return fallback;
  return normalized;
}

const DATA_GAPS_STOP_COMMAND = 'DATA_GAPS_STOP__MISSING_CRITICAL_INPUTS__HALT_PROMPT_CHAIN';
const DATA_GAPS_STOP_COMMAND_REGEX = /SYSTEM_COMMAND:\s*DATA_GAPS_STOP__MISSING_CRITICAL_INPUTS__HALT_PROMPT_CHAIN/i;
const DATA_GAPS_CATEGORY_REGEX = /CATEGORY:\s*DATA_GAPS\b/i;
const DATA_GAPS_MISSING_INPUTS_REGEX = /MISSING_INPUTS:\s*([^\n\r]+)/i;
// Accept both standalone "DATA_GAP(S)" and suffixed variants like
// "data_gap_unresolved" used in runtime reason/status codes.
const DATA_GAPS_GENERIC_REGEX = /\bDATA[_\s-]?GAPS?(?:\b|[_-])/i;

function parseDataGapsStopFromText(text) {
  const normalized = typeof text === 'string' ? text.trim() : '';
  if (!normalized) {
    return {
      detected: false,
      hasCommand: false,
      hasCategory: false,
      missingInputsText: '',
      missingInputs: []
    };
  }
  const hasCommand = DATA_GAPS_STOP_COMMAND_REGEX.test(normalized);
  const hasCategory = DATA_GAPS_CATEGORY_REGEX.test(normalized);
  const hasDataGapToken = DATA_GAPS_GENERIC_REGEX.test(normalized);
  const missingInputsMatch = normalized.match(DATA_GAPS_MISSING_INPUTS_REGEX);
  const missingInputsText = missingInputsMatch?.[1]
    ? compactWhitespace(missingInputsMatch[1]).slice(0, 320)
    : '';
  const missingInputs = missingInputsText
    ? missingInputsText
        .split(',')
        .map((item) => item.trim())
        .filter((item) => item.length > 0)
        .slice(0, 12)
    : [];
  const detected = hasCommand || (hasCategory && hasDataGapToken);
  return {
    detected,
    hasCommand,
    hasCategory,
    missingInputsText,
    missingInputs
  };
}

function looksLikeDataGapMarker(value) {
  if (typeof value !== 'string' || !value.trim()) return false;
  return DATA_GAPS_GENERIC_REGEX.test(value);
}

function isDataGapMonitorRow(row) {
  if (!row || typeof row !== 'object') return false;
  if (row.dataGapDetected === true) return true;
  return [
    row.reason,
    row.restartDecisionReason,
    row.restartDispatchStatus,
    row.recognitionSummary,
    row.resumeDecisionSource,
    row.recognitionSource
  ].some((value) => looksLikeDataGapMarker(value));
}

function normalizeReloadResumeSummary(rawSummary) {
  const source = rawSummary && typeof rawSummary === 'object' ? rawSummary : {};
  return {
    started: toNonNegativeInt(source.started, 0),
    detect_failed: toNonNegativeInt(source.detect_failed, 0),
    reload_failed: toNonNegativeInt(source.reload_failed, 0),
    skipped_outside_invest: toNonNegativeInt(source.skipped_outside_invest, 0),
    final_stage_completed: toNonNegativeInt(source.final_stage_completed, 0),
    start_failed: toNonNegativeInt(source.start_failed, 0),
    reload_ok: toNonNegativeInt(source.reload_ok, 0),
    reload_total: toNonNegativeInt(source.reload_total, 0),
    prompt_blocks: toNonNegativeInt(source.prompt_blocks, 0),
    response_blocks: toNonNegativeInt(source.response_blocks, 0),
    missing_replies_detected: toNonNegativeInt(source.missing_replies_detected, 0),
    data_gaps_detected: toNonNegativeInt(source.data_gaps_detected, 0),
    detected_prompts: toNonNegativeInt(source.detected_prompts, 0),
    recognized_saved_stage: toNonNegativeInt(source.recognized_saved_stage, 0),
    recognized_chat_detection: toNonNegativeInt(source.recognized_chat_detection, 0),
    recognized_chat_counter_fallback: toNonNegativeInt(source.recognized_chat_counter_fallback, 0),
    recognized_progress_last_resort: toNonNegativeInt(source.recognized_progress_last_resort, 0),
    recognized_unresolved: toNonNegativeInt(source.recognized_unresolved, 0)
  };
}

function sanitizeReloadResumeRecognitionSteps(rawSteps) {
  if (!Array.isArray(rawSteps)) return [];
  return rawSteps
    .filter((item) => typeof item === 'string' && item.trim())
    .map((item) => item.trim().slice(0, 220))
    .slice(-24);
}

function sanitizeReloadResumeMonitorRow(rawRow) {
  if (!rawRow || typeof rawRow !== 'object') return null;
  return {
    key: typeof rawRow.key === 'string' ? rawRow.key : '',
    runId: typeof rawRow.runId === 'string' ? rawRow.runId : '',
    title: typeof rawRow.title === 'string' ? rawRow.title : '',
    analysisType: typeof rawRow.analysisType === 'string' ? rawRow.analysisType : '',
    tabId: Number.isInteger(rawRow.tabId) ? rawRow.tabId : null,
    windowId: Number.isInteger(rawRow.windowId) ? rawRow.windowId : null,
    progressPromptNumber: Number.isInteger(rawRow.progressPromptNumber) ? rawRow.progressPromptNumber : null,
    progressStageIndex: Number.isInteger(rawRow.progressStageIndex) ? rawRow.progressStageIndex : null,
    totalPrompts: Number.isInteger(rawRow.totalPrompts) ? rawRow.totalPrompts : null,
    progressStageName: typeof rawRow.progressStageName === 'string' ? rawRow.progressStageName : '',
    progressStatus: typeof rawRow.progressStatus === 'string' ? rawRow.progressStatus : '',
    progressNeedsAction: rawRow.progressNeedsAction === true,
    chatPromptNumber: Number.isInteger(rawRow.chatPromptNumber) ? rawRow.chatPromptNumber : null,
    chatPromptSource: typeof rawRow.chatPromptSource === 'string' ? rawRow.chatPromptSource : '',
    chatPromptMismatch: rawRow.chatPromptMismatch === true,
    resolvedPromptNumber: Number.isInteger(rawRow.resolvedPromptNumber) ? rawRow.resolvedPromptNumber : null,
    resolvedPromptSource: typeof rawRow.resolvedPromptSource === 'string' ? rawRow.resolvedPromptSource : '',
    resolvedPromptMismatch: rawRow.resolvedPromptMismatch === true,
    detectedPromptNumber: Number.isInteger(rawRow.detectedPromptNumber) ? rawRow.detectedPromptNumber : null,
    detectedStageName: typeof rawRow.detectedStageName === 'string' ? rawRow.detectedStageName : '',
    detectedMethod: typeof rawRow.detectedMethod === 'string' ? rawRow.detectedMethod : '',
    nextStartIndex: Number.isInteger(rawRow.nextStartIndex) ? rawRow.nextStartIndex : null,
    action: typeof rawRow.action === 'string' ? rawRow.action : '',
    reason: typeof rawRow.reason === 'string' ? rawRow.reason : '',
    resumeDecisionSource: typeof rawRow.resumeDecisionSource === 'string' ? rawRow.resumeDecisionSource : '',
    recognitionStage: typeof rawRow.recognitionStage === 'string' ? rawRow.recognitionStage : '',
    recognitionStatus: typeof rawRow.recognitionStatus === 'string' ? rawRow.recognitionStatus : '',
    recognitionSource: typeof rawRow.recognitionSource === 'string' ? rawRow.recognitionSource : '',
    recognitionSummary: typeof rawRow.recognitionSummary === 'string' ? rawRow.recognitionSummary : '',
    recognitionSteps: sanitizeReloadResumeRecognitionSteps(rawRow.recognitionSteps),
    attempts: toNonNegativeInt(rawRow.attempts, 0),
    reloadMethod: typeof rawRow.reloadMethod === 'string' ? rawRow.reloadMethod : '',
    stageConsistency: typeof rawRow.stageConsistency === 'string' ? rawRow.stageConsistency : '',
    stageDelta: Number.isInteger(rawRow.stageDelta) ? rawRow.stageDelta : null,
    restartPlannedStartIndex: Number.isInteger(rawRow.restartPlannedStartIndex) ? rawRow.restartPlannedStartIndex : null,
    restartPlannedStartPromptNumber: Number.isInteger(rawRow.restartPlannedStartPromptNumber) ? rawRow.restartPlannedStartPromptNumber : null,
    restartDispatchedStartIndex: Number.isInteger(rawRow.restartDispatchedStartIndex) ? rawRow.restartDispatchedStartIndex : null,
    restartDispatchedStartPromptNumber: Number.isInteger(rawRow.restartDispatchedStartPromptNumber) ? rawRow.restartDispatchedStartPromptNumber : null,
    restartDecisionReason: typeof rawRow.restartDecisionReason === 'string' ? rawRow.restartDecisionReason : '',
    restartDecisionSource: typeof rawRow.restartDecisionSource === 'string' ? rawRow.restartDecisionSource : '',
    restartDispatchStatus: typeof rawRow.restartDispatchStatus === 'string' ? rawRow.restartDispatchStatus : '',
    restartMissingAssistantReply: rawRow.restartMissingAssistantReply === true
      ? true
      : (rawRow.restartMissingAssistantReply === false ? false : null),
    dataGapDetected: rawRow.dataGapDetected === true,
    dataGapSignal: typeof rawRow.dataGapSignal === 'string' ? rawRow.dataGapSignal : '',
    dataGapMissingInputs: typeof rawRow.dataGapMissingInputs === 'string'
      ? rawRow.dataGapMissingInputs.slice(0, 320)
      : '',
    userMessageCount: Number.isInteger(rawRow.userMessageCount) ? rawRow.userMessageCount : null,
    assistantMessageCount: Number.isInteger(rawRow.assistantMessageCount) ? rawRow.assistantMessageCount : null,
    responseBlockCount: Number.isInteger(rawRow.responseBlockCount) ? rawRow.responseBlockCount : null,
    eligibleForReload: rawRow.eligibleForReload === true
  };
}

function sanitizeReloadResumeMonitorStage(rawStage) {
  if (!rawStage || typeof rawStage !== 'object') return null;
  return {
    runId: typeof rawStage.runId === 'string' ? rawStage.runId : '',
    title: typeof rawStage.title === 'string' ? rawStage.title : '',
    status: typeof rawStage.status === 'string' ? rawStage.status : '',
    currentPrompt: Number.isInteger(rawStage.currentPrompt) ? rawStage.currentPrompt : null,
    totalPrompts: Number.isInteger(rawStage.totalPrompts) ? rawStage.totalPrompts : null,
    stageIndex: Number.isInteger(rawStage.stageIndex) ? rawStage.stageIndex : null,
    stageName: typeof rawStage.stageName === 'string' ? rawStage.stageName : '',
    tabId: Number.isInteger(rawStage.tabId) ? rawStage.tabId : null,
    windowId: Number.isInteger(rawStage.windowId) ? rawStage.windowId : null
  };
}

function sanitizeReloadResumeMonitorEvent(rawEvent) {
  const source = rawEvent && typeof rawEvent === 'object' ? rawEvent : {};
  const ts = Number.isInteger(source.ts) && source.ts > 0 ? source.ts : Date.now();
  const level = source.level === 'warn' || source.level === 'error' ? source.level : 'info';
  const message = typeof source.message === 'string' ? source.message.trim() : '';
  let details = '';
  if (typeof source.details === 'string') {
    details = source.details.trim();
  } else if (source.details && typeof source.details === 'object') {
    try {
      details = JSON.stringify(source.details);
    } catch (error) {
      details = '';
    }
  }
  if (details.length > 420) details = `${details.slice(0, 417)}...`;
  return {
    id: typeof source.id === 'string' && source.id.trim() ? source.id.trim() : `evt-${ts}-${Math.random().toString(36).slice(2, 7)}`,
    ts,
    level,
    code: typeof source.code === 'string' ? source.code.trim() : '',
    message: message || (typeof source.code === 'string' ? source.code.trim() : 'event'),
    details
  };
}

function normalizeReloadResumeMonitorCounts(rawCounts) {
  const source = rawCounts && typeof rawCounts === 'object' ? rawCounts : {};
  const normalized = {};
  Object.entries(source).forEach(([key, value]) => {
    if (!key) return;
    if (Number.isFinite(value)) {
      normalized[key] = toNonNegativeInt(value, 0);
    }
  });
  return normalized;
}

function calculateReloadResumeSummaryFromRows(rows, reloadTotalHint = null) {
  const sourceRows = Array.isArray(rows) ? rows : [];
  const actionCounts = sourceRows.reduce((acc, row) => {
    const action = typeof row?.action === 'string' && row.action ? row.action : 'unknown';
    acc[action] = (acc[action] || 0) + 1;
    return acc;
  }, {});
  const promptBlocks = sourceRows.reduce((sum, row) => (
    sum + (Number.isInteger(row?.userMessageCount) ? row.userMessageCount : 0)
  ), 0);
  const responseBlocks = sourceRows.reduce((sum, row) => (
    sum + (
      Number.isInteger(row?.responseBlockCount)
        ? row.responseBlockCount
        : (Number.isInteger(row?.assistantMessageCount) ? row.assistantMessageCount : 0)
    )
  ), 0);
  const missingRepliesDetected = sourceRows.filter((row) => row?.restartMissingAssistantReply === true).length;
  const dataGapsDetected = sourceRows.filter((row) => isDataGapMonitorRow(row)).length;
  const detectedPrompts = sourceRows.reduce((sum, row) => (
    sum + (Number.isInteger(row?.detectedPromptNumber) ? 1 : 0)
  ), 0);
  const reloadOk = sourceRows.filter((row) => typeof row?.reloadMethod === 'string' && row.reloadMethod.trim()).length;
  const reloadTotal = Number.isInteger(reloadTotalHint)
    ? reloadTotalHint
    : sourceRows.filter((row) => row?.eligibleForReload === true).length;
  const recognitionCounts = {
    savedStage: 0,
    chatDetection: 0,
    chatCounterFallback: 0,
    progressLastResort: 0,
    unresolved: 0
  };
  const isRecognitionResolved = (source) => (
    source === 'saved_stage_snapshot'
    || source === 'chat_fallback_detection'
    || source === 'chat_counter_fallback'
    || source === 'progress_last_resort_fallback'
    || source === 'conversation_audit_match'
    || source === 'conversation_audit_counter_fallback'
  );

  sourceRows.forEach((row) => {
    const recognitionSource = (
      typeof row?.recognitionSource === 'string' && row.recognitionSource.trim()
    )
      ? row.recognitionSource.trim()
      : (typeof row?.resumeDecisionSource === 'string' ? row.resumeDecisionSource.trim() : '');
    if (recognitionSource === 'saved_stage_snapshot') recognitionCounts.savedStage += 1;
    if (recognitionSource === 'chat_fallback_detection' || recognitionSource === 'conversation_audit_match') {
      recognitionCounts.chatDetection += 1;
    }
    if (recognitionSource === 'chat_counter_fallback' || recognitionSource === 'conversation_audit_counter_fallback') {
      recognitionCounts.chatCounterFallback += 1;
    }
    if (recognitionSource === 'progress_last_resort_fallback') recognitionCounts.progressLastResort += 1;
    const unresolvedBySource = recognitionSource === 'chat_fallback_unresolved' || recognitionSource === 'detect_unresolved';
    const unresolvedByAction = (
      row?.eligibleForReload === true
      && row?.action === 'detect_failed'
      && !isRecognitionResolved(recognitionSource)
    );
    if (unresolvedBySource || unresolvedByAction) {
      recognitionCounts.unresolved += 1;
    }
  });

  return normalizeReloadResumeSummary({
    started: actionCounts.started || 0,
    detect_failed: actionCounts.detect_failed || 0,
    reload_failed: actionCounts.reload_failed || 0,
    skipped_outside_invest: actionCounts.skipped_outside_invest || 0,
    final_stage_completed: actionCounts.final_stage_already_sent || 0,
    start_failed: actionCounts.start_failed || 0,
    reload_ok: reloadOk,
    reload_total: reloadTotal,
    prompt_blocks: promptBlocks,
    response_blocks: responseBlocks,
    missing_replies_detected: missingRepliesDetected,
    data_gaps_detected: dataGapsDetected,
    detected_prompts: detectedPrompts,
    recognized_saved_stage: recognitionCounts.savedStage,
    recognized_chat_detection: recognitionCounts.chatDetection,
    recognized_chat_counter_fallback: recognitionCounts.chatCounterFallback,
    recognized_progress_last_resort: recognitionCounts.progressLastResort,
    recognized_unresolved: recognitionCounts.unresolved
  });
}

function verifyReloadResumeSummary(summary, rows, reloadTotalHint = null) {
  const expected = normalizeReloadResumeSummary(summary);
  const calculated = calculateReloadResumeSummaryFromRows(rows, reloadTotalHint);
  const mismatchKeys = Object.keys(expected).filter((key) => expected[key] !== calculated[key]);
  return {
    ok: mismatchKeys.length === 0,
    mismatches: mismatchKeys.map((key) => ({
      key,
      expected: expected[key],
      calculated: calculated[key]
    })),
    expected,
    calculated
  };
}

function sanitizeReloadResumeMonitorState(rawState) {
  const source = rawState && typeof rawState === 'object' ? rawState : {};
  const status = typeof source.status === 'string' ? source.status.trim().toLowerCase() : '';
  const normalizedStatus = (
    status === 'running'
    || status === 'completed'
    || status === 'failed'
    || status === 'idle'
  ) ? status : 'idle';
  const rows = (Array.isArray(source.rows) ? source.rows : [])
    .map(sanitizeReloadResumeMonitorRow)
    .filter(Boolean)
    .slice(0, RELOAD_RESUME_MONITOR_MAX_ROWS);
  const stageSnapshot = (Array.isArray(source.stageSnapshot) ? source.stageSnapshot : [])
    .map(sanitizeReloadResumeMonitorStage)
    .filter(Boolean)
    .slice(0, RELOAD_RESUME_MONITOR_MAX_ROWS);
  const events = (Array.isArray(source.events) ? source.events : [])
    .map(sanitizeReloadResumeMonitorEvent)
    .slice(-RELOAD_RESUME_MONITOR_MAX_EVENTS);
  const summaryCheck = source.summaryCheck && typeof source.summaryCheck === 'object'
    ? {
      ok: source.summaryCheck.ok !== false,
      mismatches: Array.isArray(source.summaryCheck.mismatches)
        ? source.summaryCheck.mismatches
            .map((item) => ({
              key: typeof item?.key === 'string' ? item.key : '',
              expected: Number.isFinite(item?.expected) ? Math.trunc(item.expected) : 0,
              calculated: Number.isFinite(item?.calculated) ? Math.trunc(item.calculated) : 0
            }))
            .filter((item) => item.key)
        : [],
      expected: normalizeReloadResumeSummary(source.summaryCheck.expected),
      calculated: normalizeReloadResumeSummary(source.summaryCheck.calculated)
    }
    : null;

  return {
    sessionId: typeof source.sessionId === 'string' ? source.sessionId : '',
    status: normalizedStatus,
    phase: typeof source.phase === 'string' ? source.phase : '',
    origin: typeof source.origin === 'string' ? source.origin : '',
    scope: typeof source.scope === 'string' ? source.scope : '',
    composerThinkingEffort: normalizeComposerThinkingEffort(source.composerThinkingEffort),
    forceRepeatLastPrompt: source.forceRepeatLastPrompt === true,
    startedAt: Number.isInteger(source.startedAt) ? source.startedAt : null,
    updatedAt: Number.isInteger(source.updatedAt) ? source.updatedAt : Date.now(),
    finishedAt: Number.isInteger(source.finishedAt) ? source.finishedAt : null,
    passCount: toNonNegativeInt(source.passCount, 0),
    pendingCount: toNonNegativeInt(source.pendingCount, 0),
    counts: normalizeReloadResumeMonitorCounts(source.counts),
    summary: normalizeReloadResumeSummary(source.summary),
    summaryCheck,
    stageSnapshot,
    rows,
    events,
    error: typeof source.error === 'string' ? source.error : ''
  };
}

function cloneReloadResumeMonitorState(state) {
  if (!state || typeof state !== 'object') return null;
  try {
    return structuredClone(state);
  } catch (error) {
    return JSON.parse(JSON.stringify(state));
  }
}

async function ensureReloadResumeMonitorReady() {
  if (!reloadResumeMonitorReady) {
    reloadResumeMonitorReady = (async () => {
      try {
        const stored = await chrome.storage.local.get([RELOAD_RESUME_MONITOR_STORAGE_KEY]);
        const existing = stored?.[RELOAD_RESUME_MONITOR_STORAGE_KEY];
        if (existing && typeof existing === 'object') {
          reloadResumeMonitorState = sanitizeReloadResumeMonitorState(existing);
          return;
        }
      } catch (error) {
        console.warn('[reload-monitor] Failed to load state:', error?.message || error);
      }
      reloadResumeMonitorState = sanitizeReloadResumeMonitorState({
        sessionId: '',
        status: 'idle',
        phase: 'idle',
        startedAt: null,
        updatedAt: Date.now(),
        finishedAt: null,
        counts: {},
        summary: normalizeReloadResumeSummary({}),
        summaryCheck: null,
        stageSnapshot: [],
        rows: [],
        events: [],
        error: ''
      });
    })();
  }
  await reloadResumeMonitorReady;
  return reloadResumeMonitorState;
}

async function setReloadResumeMonitorState(nextState) {
  await ensureReloadResumeMonitorReady();
  const normalized = sanitizeReloadResumeMonitorState(nextState);
  normalized.updatedAt = Date.now();
  reloadResumeMonitorState = normalized;
  await chrome.storage.local.set({
    [RELOAD_RESUME_MONITOR_STORAGE_KEY]: normalized
  });
  try {
    await chrome.runtime.sendMessage({
      type: 'RELOAD_RESUME_MONITOR_UPDATE',
      state: normalized
    });
  } catch (error) {
    // Ignore: no live listeners.
  }
  return normalized;
}

async function getReloadResumeMonitorState(sessionId = '') {
  await ensureReloadResumeMonitorReady();
  if (!sessionId) {
    return cloneReloadResumeMonitorState(reloadResumeMonitorState);
  }
  if (reloadResumeMonitorState?.sessionId && reloadResumeMonitorState.sessionId !== sessionId) {
    return null;
  }
  return cloneReloadResumeMonitorState(reloadResumeMonitorState);
}

async function startReloadResumeMonitorSession(payload = {}) {
  const sessionId = typeof payload.sessionId === 'string' && payload.sessionId.trim()
    ? payload.sessionId.trim()
    : createReloadResumeMonitorSessionId('reload-resume');
  const initialEvent = sanitizeReloadResumeMonitorEvent({
    level: 'info',
    code: 'session_started',
    message: 'Reload + resume session started'
  });
  return setReloadResumeMonitorState({
    sessionId,
    status: 'running',
    phase: 'init',
    origin: typeof payload.origin === 'string' ? payload.origin : '',
    scope: typeof payload.scope === 'string' ? payload.scope : '',
    composerThinkingEffort: normalizeComposerThinkingEffort(payload.composerThinkingEffort),
    forceRepeatLastPrompt: payload.forceRepeatLastPrompt === true,
    startedAt: Date.now(),
    updatedAt: Date.now(),
    finishedAt: null,
    passCount: 0,
    pendingCount: 0,
    counts: normalizeReloadResumeMonitorCounts(payload.counts),
    summary: normalizeReloadResumeSummary({}),
    summaryCheck: null,
    stageSnapshot: [],
    rows: [],
    events: [initialEvent],
    error: ''
  });
}

async function appendReloadResumeMonitorEvent(sessionId, rawEvent = {}) {
  if (!sessionId) return null;
  const current = await getReloadResumeMonitorState(sessionId);
  if (!current) return null;
  const nextEvents = current.events.concat([sanitizeReloadResumeMonitorEvent(rawEvent)]);
  return setReloadResumeMonitorState({
    ...current,
    events: nextEvents.slice(-RELOAD_RESUME_MONITOR_MAX_EVENTS)
  });
}

async function updateReloadResumeMonitorSession(sessionId, patch = {}) {
  if (!sessionId) return null;
  const current = await getReloadResumeMonitorState(sessionId);
  if (!current) return null;
  const next = {
    ...current,
    ...(patch && typeof patch === 'object' ? patch : {}),
    sessionId,
    counts: normalizeReloadResumeMonitorCounts({
      ...(current?.counts && typeof current.counts === 'object' ? current.counts : {}),
      ...(patch?.counts && typeof patch.counts === 'object' ? patch.counts : {})
    })
  };
  if (patch?.summary) {
    next.summary = normalizeReloadResumeSummary(patch.summary);
  }
  if (patch?.summaryCheck && typeof patch.summaryCheck === 'object') {
    next.summaryCheck = patch.summaryCheck;
  }
  return setReloadResumeMonitorState(next);
}

function createUnfinishedResumeBatchJobId(prefix = 'unfinished-resume') {
  const normalizedPrefix = typeof prefix === 'string' && prefix.trim()
    ? prefix.trim().toLowerCase().replace(/[^a-z0-9_-]+/g, '-').replace(/-+/g, '-')
    : 'unfinished-resume';
  const safePrefix = normalizedPrefix || 'unfinished-resume';
  return `${safePrefix}-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
}

function normalizeUnfinishedResumeBatchStatus(status) {
  const normalized = typeof status === 'string' ? status.trim().toLowerCase() : '';
  if (UNFINISHED_RESUME_BATCH_STATUSES.has(normalized)) return normalized;
  return 'idle';
}

function normalizeUnfinishedResumeRow(rawRow) {
  if (!rawRow || typeof rawRow !== 'object') return null;
  const outcomeRaw = typeof rawRow.outcome === 'string' ? rawRow.outcome.trim().toLowerCase() : '';
  const allowedOutcomes = new Set([
    'resumed',
    'skipped_missing_chat_url',
    'skipped_not_found',
    'skipped_already_completed',
    'failed'
  ]);
  const outcome = allowedOutcomes.has(outcomeRaw) ? outcomeRaw : 'failed';
  return {
    runId: typeof rawRow.runId === 'string' ? rawRow.runId : '',
    title: typeof rawRow.title === 'string' ? rawRow.title : '',
    startedAt: Number.isInteger(rawRow.startedAt) ? rawRow.startedAt : null,
    finishedAt: Number.isInteger(rawRow.finishedAt) ? rawRow.finishedAt : null,
    outcome,
    reason: typeof rawRow.reason === 'string' ? rawRow.reason : '',
    error: typeof rawRow.error === 'string' ? rawRow.error : '',
    detectedPromptNumber: Number.isInteger(rawRow.detectedPromptNumber) ? rawRow.detectedPromptNumber : null,
    startPromptNumber: Number.isInteger(rawRow.startPromptNumber) ? rawRow.startPromptNumber : null,
    detectedMethod: typeof rawRow.detectedMethod === 'string' ? rawRow.detectedMethod : '',
    retrySamePrompt: rawRow.retrySamePrompt === true,
    retryReason: typeof rawRow.retryReason === 'string' ? rawRow.retryReason : '',
    chatUrl: typeof rawRow.chatUrl === 'string' ? rawRow.chatUrl : ''
  };
}

function normalizeUnfinishedResumeBatchTotals(rawTotals) {
  const source = rawTotals && typeof rawTotals === 'object' ? rawTotals : {};
  return {
    total: toNonNegativeInt(source.total, 0),
    runnable: toNonNegativeInt(source.runnable, 0),
    skippedMissingUrl: toNonNegativeInt(source.skippedMissingUrl, 0),
    processed: toNonNegativeInt(source.processed, 0),
    resumed: toNonNegativeInt(source.resumed, 0),
    skipped_missing_chat_url: toNonNegativeInt(source.skipped_missing_chat_url, 0),
    skipped_not_found: toNonNegativeInt(source.skipped_not_found, 0),
    skipped_already_completed: toNonNegativeInt(source.skipped_already_completed, 0),
    failed: toNonNegativeInt(source.failed, 0)
  };
}

function normalizeUnfinishedResumeBatchSelection(rawSelection) {
  const source = rawSelection && typeof rawSelection === 'object' ? rawSelection : {};
  const sourceFilter = normalizeUnfinishedSourceFilter(source.sourceFilter);
  const limitRequested = normalizeUnfinishedResumeLimit(source.limitRequested);
  const limitApplied = normalizeUnfinishedResumeLimit(source.limitApplied);
  return {
    sourceFilter: sourceFilter || 'all',
    sourceLabel: typeof source.sourceLabel === 'string' ? source.sourceLabel : '',
    strategy: typeof source.strategy === 'string' ? source.strategy : '',
    limitRequested,
    limitApplied,
    filteredTotal: toNonNegativeInt(source.filteredTotal, 0)
  };
}

function sanitizeUnfinishedResumeBatchState(rawState) {
  const source = rawState && typeof rawState === 'object' ? rawState : {};
  const rows = (Array.isArray(source.rows) ? source.rows : [])
    .map(normalizeUnfinishedResumeRow)
    .filter(Boolean)
    .slice(-UNFINISHED_RESUME_BATCH_MAX_ROWS);
  return {
    jobId: typeof source.jobId === 'string' ? source.jobId : '',
    status: normalizeUnfinishedResumeBatchStatus(source.status),
    startedAt: Number.isInteger(source.startedAt) ? source.startedAt : null,
    finishedAt: Number.isInteger(source.finishedAt) ? source.finishedAt : null,
    updatedAt: Number.isInteger(source.updatedAt) ? source.updatedAt : Date.now(),
    origin: typeof source.origin === 'string' ? source.origin : '',
    totals: normalizeUnfinishedResumeBatchTotals(source.totals),
    selection: normalizeUnfinishedResumeBatchSelection(source.selection),
    rows,
    activeRunId: typeof source.activeRunId === 'string' ? source.activeRunId : '',
    error: typeof source.error === 'string' ? source.error : ''
  };
}

function cloneUnfinishedResumeBatchState(state) {
  if (!state || typeof state !== 'object') return null;
  try {
    return structuredClone(state);
  } catch (error) {
    return JSON.parse(JSON.stringify(state));
  }
}

async function ensureUnfinishedResumeBatchStateReady() {
  if (!unfinishedResumeBatchStateReady) {
    unfinishedResumeBatchStateReady = (async () => {
      try {
        const stored = await chrome.storage.local.get([UNFINISHED_RESUME_BATCH_STORAGE_KEY]);
        const existing = stored?.[UNFINISHED_RESUME_BATCH_STORAGE_KEY];
        if (existing && typeof existing === 'object') {
          unfinishedResumeBatchState = sanitizeUnfinishedResumeBatchState(existing);
        } else {
          unfinishedResumeBatchState = sanitizeUnfinishedResumeBatchState({
            status: 'idle',
            startedAt: null,
            finishedAt: null,
            totals: {},
            rows: [],
            activeRunId: '',
            error: ''
          });
        }
      } catch (error) {
        console.warn('[unfinished-resume] failed to load batch state:', error?.message || String(error));
        unfinishedResumeBatchState = sanitizeUnfinishedResumeBatchState({
          status: 'idle',
          startedAt: null,
          finishedAt: null,
          totals: {},
          rows: [],
          activeRunId: '',
          error: ''
        });
      }
      unfinishedResumeBatchInProgress = unfinishedResumeBatchState?.status === 'running';
      unfinishedResumeBatchActiveJobId = unfinishedResumeBatchInProgress
        ? (unfinishedResumeBatchState?.jobId || '')
        : '';
    })();
  }
  await unfinishedResumeBatchStateReady;
  return unfinishedResumeBatchState;
}

async function setUnfinishedResumeBatchState(nextState, options = {}) {
  await ensureUnfinishedResumeBatchStateReady();
  const normalized = sanitizeUnfinishedResumeBatchState(nextState);
  normalized.updatedAt = Date.now();
  unfinishedResumeBatchState = normalized;
  unfinishedResumeBatchInProgress = normalized.status === 'running';
  unfinishedResumeBatchActiveJobId = unfinishedResumeBatchInProgress ? (normalized.jobId || '') : '';
  await chrome.storage.local.set({
    [UNFINISHED_RESUME_BATCH_STORAGE_KEY]: normalized
  });
  if (options?.broadcast === false) {
    return normalized;
  }
  try {
    await chrome.runtime.sendMessage({
      type: 'UNFINISHED_RESUME_BATCH_UPDATED',
      state: normalized
    });
  } catch (error) {
    // Ignore: no active listeners.
  }
  return normalized;
}

async function getUnfinishedResumeBatchState(jobId = '') {
  await ensureUnfinishedResumeBatchStateReady();
  if (!jobId) {
    return cloneUnfinishedResumeBatchState(unfinishedResumeBatchState);
  }
  const currentJobId = typeof unfinishedResumeBatchState?.jobId === 'string'
    ? unfinishedResumeBatchState.jobId
    : '';
  if (currentJobId && currentJobId !== jobId) {
    return null;
  }
  return cloneUnfinishedResumeBatchState(unfinishedResumeBatchState);
}

async function markRunningUnfinishedResumeBatchInterruptedOnBoot() {
  const state = await ensureUnfinishedResumeBatchStateReady();
  if (!state || state.status !== 'running') {
    return state;
  }
  const interruptedState = {
    ...state,
    status: 'interrupted',
    finishedAt: Date.now(),
    activeRunId: '',
    error: state.error || 'service_worker_restarted'
  };
  const saved = await setUnfinishedResumeBatchState(interruptedState);
  reportAdminActionEvent('resume_unfinished_batch_completed_with_errors', {
    level: 'warn',
    status: 'interrupted',
    reason: 'service_worker_restarted',
    origin: 'service-worker-boot',
    details: {
      jobId: interruptedState.jobId || '',
      processed: interruptedState?.totals?.processed || 0,
      total: interruptedState?.totals?.total || 0
    }
  });
  return saved;
}

function extractProcessChatUrl(process) {
  const direct = normalizeChatConversationUrl(
    typeof process?.chatUrl === 'string' ? process.chatUrl : ''
  );
  if (direct) return direct;
  const links = Array.isArray(process?.conversationUrls) ? process.conversationUrls : [];
  for (let index = links.length - 1; index >= 0; index -= 1) {
    const normalized = normalizeChatConversationUrl(typeof links[index] === 'string' ? links[index] : '');
    if (normalized) return normalized;
  }
  const sourceUrl = normalizeChatConversationUrl(
    typeof process?.sourceUrl === 'string' ? process.sourceUrl : ''
  );
  if (sourceUrl) return sourceUrl;
  return '';
}

function isFailedProcessStatusForUnfinished(status) {
  const normalized = normalizeProcessStatus(status || '');
  return FAILED_PROCESS_STATUSES.has(normalized);
}

function normalizeUnfinishedSourceFilter(value) {
  const normalized = typeof value === 'string' ? value.trim().toLowerCase() : '';
  if (!normalized || normalized === 'all') return '';
  return normalized;
}

function normalizeUnfinishedProcessSource(rawSourceUrl) {
  const sourceUrl = typeof rawSourceUrl === 'string' ? rawSourceUrl.trim() : '';
  if (!sourceUrl) {
    return {
      sourceKey: 'unknown',
      sourceLabel: 'Unknown'
    };
  }

  const lowered = sourceUrl.toLowerCase();
  if (lowered.startsWith('manual://')) {
    return {
      sourceKey: 'manual',
      sourceLabel: 'Manual'
    };
  }
  if (lowered.startsWith('file://')) {
    return {
      sourceKey: 'file',
      sourceLabel: 'File'
    };
  }

  let hostname = '';
  try {
    hostname = new URL(sourceUrl).hostname || '';
  } catch (error) {
    try {
      hostname = new URL(`https://${sourceUrl}`).hostname || '';
    } catch (innerError) {
      hostname = '';
    }
  }

  const normalizedHost = hostname.trim().toLowerCase().replace(/^www\./, '');
  if (normalizedHost) {
    return {
      sourceKey: normalizedHost,
      sourceLabel: normalizedHost
    };
  }

  return {
    sourceKey: 'unknown',
    sourceLabel: 'Unknown'
  };
}

function buildUnfinishedSourceCatalog(items) {
  const map = new Map();
  (Array.isArray(items) ? items : []).forEach((item) => {
    if (!item || typeof item !== 'object') return;
    const sourceKey = normalizeUnfinishedSourceFilter(item.sourceKey) || 'unknown';
    const sourceLabel = typeof item.sourceLabel === 'string' && item.sourceLabel.trim()
      ? item.sourceLabel.trim()
      : (sourceKey || 'unknown');
    const existing = map.get(sourceKey) || {
      key: sourceKey,
      label: sourceLabel,
      total: 0,
      runnable: 0
    };
    existing.total += 1;
    if (item.hasChatUrl) {
      existing.runnable += 1;
    }
    map.set(sourceKey, existing);
  });
  return Array.from(map.values()).sort((left, right) => {
    const totalDiff = (right.total || 0) - (left.total || 0);
    if (totalDiff !== 0) return totalDiff;
    return String(left.label || '').localeCompare(String(right.label || ''), 'en', { sensitivity: 'base' });
  });
}

function buildUnfinishedProcessListSummary(items = [], availableSources = []) {
  const sourceItems = Array.isArray(items) ? items : [];
  const total = sourceItems.length;
  const runnable = sourceItems.filter((item) => item?.hasChatUrl === true).length;
  const blockedMissingChatUrl = Math.max(0, total - runnable);
  const failedStatuses = sourceItems.filter((item) => item?.isFailedStatus === true).length;
  const needsAction = sourceItems.filter((item) => item?.needsAction === true).length;
  const withStageSnapshot = sourceItems.filter((item) => (
    Number.isInteger(item?.currentPrompt) && item.currentPrompt > 0
  )).length;
  const latestUpdatedAt = sourceItems.reduce((maxTs, item) => {
    const itemTs = Number.isInteger(item?.timestamp) ? item.timestamp : 0;
    return Math.max(maxTs, itemTs);
  }, 0);
  const statusCounts = {};
  sourceItems.forEach((item) => {
    const key = normalizeProcessStatus(item?.status || '') || 'unknown';
    statusCounts[key] = (statusCounts[key] || 0) + 1;
  });
  const sourcePreview = (Array.isArray(availableSources) ? availableSources : [])
    .slice(0, 4)
    .map((source) => ({
      key: typeof source?.key === 'string' ? source.key : '',
      label: typeof source?.label === 'string' ? source.label : '',
      total: toNonNegativeInt(source?.total, 0),
      runnable: toNonNegativeInt(source?.runnable, 0)
    }));

  return {
    total,
    runnable,
    blockedMissingChatUrl,
    failedStatuses,
    needsAction,
    withStageSnapshot,
    latestUpdatedAt,
    runnableSharePct: total > 0 ? Math.round((runnable / total) * 100) : 0,
    statusCounts,
    sourcePreview
  };
}

function buildUnfinishedProcessListLogSignature(summary, options = {}) {
  const safeSummary = summary && typeof summary === 'object' ? summary : {};
  const sourceFilter = normalizeUnfinishedSourceFilter(options?.sourceFilter) || 'all';
  const origin = typeof options?.origin === 'string' ? options.origin.trim() : '';
  const statusSignature = Object.entries(safeSummary.statusCounts || {})
    .sort((left, right) => String(left[0]).localeCompare(String(right[0]), 'en', { sensitivity: 'base' }))
    .map(([status, count]) => `${status}:${count}`)
    .join(',');
  return [
    sourceFilter,
    origin,
    safeSummary.total || 0,
    safeSummary.runnable || 0,
    safeSummary.blockedMissingChatUrl || 0,
    safeSummary.failedStatuses || 0,
    safeSummary.needsAction || 0,
    safeSummary.withStageSnapshot || 0,
    statusSignature
  ].join('|');
}

function maybeReportUnfinishedProcessListSummary(summary, options = {}) {
  const safeSummary = summary && typeof summary === 'object' ? summary : {};
  const nowTs = Date.now();
  const signature = buildUnfinishedProcessListLogSignature(safeSummary, options);
  if (
    signature === unfinishedResumeListLogLastSignature
    && (nowTs - unfinishedResumeListLogLastTs) < UNFINISHED_RESUME_LIST_LOG_COOLDOWN_MS
  ) {
    return;
  }

  unfinishedResumeListLogLastSignature = signature;
  unfinishedResumeListLogLastTs = nowTs;

  const statusPreview = Object.entries(safeSummary.statusCounts || {})
    .sort((left, right) => (right[1] || 0) - (left[1] || 0))
    .slice(0, 4)
    .map(([status, count]) => `${status}:${count}`)
    .join(', ');
  const sourcePreview = (Array.isArray(safeSummary.sourcePreview) ? safeSummary.sourcePreview : [])
    .map((entry) => `${entry.key || 'unknown'}:${entry.total || 0}/${entry.runnable || 0}`)
    .join(', ');
  const sourceFilter = normalizeUnfinishedSourceFilter(options?.sourceFilter) || 'all';
  const origin = typeof options?.origin === 'string' && options.origin.trim()
    ? options.origin.trim()
    : 'unfinished-resume-list';
  const detailPayload = {
    sourceFilter,
    total: safeSummary.total || 0,
    runnable: safeSummary.runnable || 0,
    blockedMissingChatUrl: safeSummary.blockedMissingChatUrl || 0,
    failedStatuses: safeSummary.failedStatuses || 0,
    needsAction: safeSummary.needsAction || 0,
    withStageSnapshot: safeSummary.withStageSnapshot || 0,
    runnableSharePct: safeSummary.runnableSharePct || 0,
    latestUpdatedAt: safeSummary.latestUpdatedAt || 0,
    statusPreview,
    sourcePreview
  };

  console.log('[unfinished-resume] list counted', detailPayload);
  reportAdminActionEvent('unfinished_resume_list_counted', {
    level: 'info',
    status: 'counted',
    reason: 'unfinished_resume_list_counted',
    origin,
    title: 'Unfinished resume list counted',
    message: `unfinished_resume_list_counted | total=${detailPayload.total} | runnable=${detailPayload.runnable} | blocked=${detailPayload.blockedMissingChatUrl} | source=${sourceFilter}`,
    details: detailPayload
  });
}

function normalizeUnfinishedResumeLimit(value) {
  if (value === null || value === undefined) return null;
  const asNumber = Number.parseInt(String(value).trim(), 10);
  if (!Number.isInteger(asNumber) || asNumber <= 0) return null;
  return Math.min(asNumber, 10_000);
}

function hasUnfinishedProcessExecutionEvidence(process) {
  if (!process || typeof process !== 'object') return false;
  const currentPrompt = Number.isInteger(process?.currentPrompt) ? process.currentPrompt : 0;
  const stageIndex = Number.isInteger(process?.stageIndex) ? process.stageIndex : -1;
  if (currentPrompt > 0 || stageIndex >= 0) return true;

  const messages = Array.isArray(process?.messages) ? process.messages : [];
  if (messages.length > 0) {
    return messages.some((entry) => {
      if (!entry || typeof entry !== 'object') return false;
      const text = typeof entry.text === 'string' ? entry.text.trim() : '';
      return text.length > 0;
    });
  }

  return false;
}

function isRecoverableUnfinishedProcess(process) {
  if (!process || typeof process !== 'object') return false;
  const status = normalizeProcessStatus(process?.status || '');
  if (status === 'completed') return false;
  if (!isClosedProcessStatus(status)) return false;
  if (!hasUnfinishedProcessExecutionEvidence(process)) return false;

  const reason = typeof process?.reason === 'string' ? process.reason.trim().toLowerCase() : '';
  if (reason && UNFINISHED_RECOVERY_EXCLUDED_REASONS.has(reason)) {
    return false;
  }
  return true;
}

function getUnfinishedCandidateProgressMeta(candidate) {
  const currentPrompt = Number.isInteger(candidate?.currentPrompt) && candidate.currentPrompt > 0
    ? candidate.currentPrompt
    : 0;
  const totalPrompts = Number.isInteger(candidate?.totalPrompts) && candidate.totalPrompts > 0
    ? candidate.totalPrompts
    : 0;
  const ratio = totalPrompts > 0
    ? Math.max(0, Math.min(1, currentPrompt / totalPrompts))
    : 0;
  const timestamp = Number.isInteger(candidate?.timestamp) ? candidate.timestamp : 0;
  return {
    currentPrompt,
    totalPrompts,
    ratio,
    timestamp
  };
}

function compareUnfinishedCandidatesByProgressDesc(left, right) {
  const leftMeta = getUnfinishedCandidateProgressMeta(left);
  const rightMeta = getUnfinishedCandidateProgressMeta(right);
  if (rightMeta.ratio !== leftMeta.ratio) {
    return rightMeta.ratio - leftMeta.ratio;
  }
  if (rightMeta.currentPrompt !== leftMeta.currentPrompt) {
    return rightMeta.currentPrompt - leftMeta.currentPrompt;
  }
  if (leftMeta.totalPrompts !== rightMeta.totalPrompts) {
    return leftMeta.totalPrompts - rightMeta.totalPrompts;
  }
  if (rightMeta.timestamp !== leftMeta.timestamp) {
    return rightMeta.timestamp - leftMeta.timestamp;
  }
  const leftRunId = typeof left?.runId === 'string' ? left.runId : '';
  const rightRunId = typeof right?.runId === 'string' ? right.runId : '';
  return leftRunId.localeCompare(rightRunId, 'en', { sensitivity: 'base' });
}

function resolveUnfinishedProcessStageName(process) {
  const stageName = typeof process?.stageName === 'string' ? process.stageName.trim() : '';
  if (stageName) return stageName;
  const currentPrompt = Number.isInteger(process?.currentPrompt) ? process.currentPrompt : null;
  if (Number.isInteger(currentPrompt) && currentPrompt > 0) {
    return STAGE_NAMES_COMPANY[currentPrompt - 1] || `Prompt ${currentPrompt}`;
  }
  return '';
}

function buildUnfinishedProcessItem(process) {
  const chatUrl = extractProcessChatUrl(process);
  const runId = typeof process?.id === 'string' ? process.id : '';
  const status = normalizeProcessStatus(process?.status || '');
  const sourceUrl = typeof process?.sourceUrl === 'string' ? process.sourceUrl : '';
  const sourceMeta = normalizeUnfinishedProcessSource(sourceUrl);
  const currentPrompt = Number.isInteger(process?.currentPrompt) ? process.currentPrompt : 0;
  const totalPrompts = Number.isInteger(process?.totalPrompts) ? process.totalPrompts : 0;
  const progressShare = totalPrompts > 0 && currentPrompt > 0
    ? Math.max(0, Math.min(1, currentPrompt / totalPrompts))
    : 0;
  return {
    runId,
    title: typeof process?.title === 'string' ? process.title : '',
    status,
    isFailedStatus: isFailedProcessStatusForUnfinished(status),
    needsAction: process?.needsAction === true,
    currentPrompt,
    totalPrompts,
    progressShare,
    stageName: resolveUnfinishedProcessStageName(process),
    timestamp: Number.isInteger(process?.timestamp) ? process.timestamp : 0,
    chatUrl,
    hasChatUrl: !!chatUrl,
    sourceUrl,
    sourceKey: sourceMeta.sourceKey,
    sourceLabel: sourceMeta.sourceLabel,
    reason: typeof process?.reason === 'string' ? process.reason : '',
    statusText: typeof process?.statusText === 'string' ? process.statusText : '',
    lastError: typeof process?.error === 'string' ? process.error : '',
    hasExecutionEvidence: hasUnfinishedProcessExecutionEvidence(process)
  };
}

async function listUnfinishedProcessesForResume(options = {}) {
  const includeNonCompleted = options?.includeNonCompleted !== false;
  const recoverOnly = options?.recoverOnly !== false;
  const sourceFilter = normalizeUnfinishedSourceFilter(options?.sourceFilter);
  const origin = typeof options?.origin === 'string' ? options.origin : 'unfinished-resume-list';
  const snapshot = await getProcessSnapshot();
  const allItems = (Array.isArray(snapshot) ? snapshot : [])
    .filter((process) => process && typeof process === 'object')
    .filter((process) => {
      if (recoverOnly) {
        return isRecoverableUnfinishedProcess(process);
      }
      const status = normalizeProcessStatus(process?.status || '');
      if (includeNonCompleted) {
        return status !== 'completed';
      }
      return !isClosedProcessStatus(status);
    })
    .map((process) => buildUnfinishedProcessItem(process))
    .sort((a, b) => (b.timestamp || 0) - (a.timestamp || 0));
  const availableSources = buildUnfinishedSourceCatalog(allItems);
  const items = sourceFilter
    ? allItems.filter((item) => item.sourceKey === sourceFilter)
    : allItems;
  const sourceFilterMatched = sourceFilter
    ? availableSources.some((source) => source.key === sourceFilter)
    : true;

  const runnable = items.filter((item) => item.hasChatUrl).length;
  const skippedMissingUrl = items.length - runnable;
  const summary = buildUnfinishedProcessListSummary(items, sourceFilter ? availableSources.filter((entry) => entry?.key === sourceFilter) : availableSources);
  maybeReportUnfinishedProcessListSummary(summary, {
    origin,
    sourceFilter
  });

  return {
    success: true,
    generatedAt: Date.now(),
    total: items.length,
    runnable,
    skippedMissingUrl,
    sourceFilter: sourceFilter || 'all',
    sourceFilterApplied: !!sourceFilter,
    sourceFilterMatched,
    recoverOnly,
    countingModel: {
      listSource: 'process_monitor_state',
      listStageMeaning: 'snapshot_saved_progress',
      resumeStageMeaning: 'live_recalculation_on_chat_tab',
      batchLimitMeaning: 'top_progress_snapshot_then_live_verify'
    },
    summary,
    availableSources,
    items
  };
}

function getUnfinishedRowLogLevel(outcome) {
  if (outcome === 'resumed') return 'info';
  if (outcome === 'failed') return 'error';
  return 'warn';
}

function getUnfinishedRowActionName(outcome) {
  if (outcome === 'resumed') return 'resume_unfinished_process_resumed';
  if (outcome === 'skipped_missing_chat_url') return 'resume_unfinished_process_skipped_missing_chat_url';
  if (outcome === 'skipped_not_found') return 'resume_unfinished_process_skipped_not_found';
  if (outcome === 'failed') return 'resume_unfinished_process_failed';
  return 'resume_unfinished_process_skipped_already_completed';
}

function getUnfinishedRowStatus(outcome) {
  if (outcome === 'resumed') return 'completed';
  if (outcome === 'failed') return 'failed';
  return 'skipped';
}

async function logUnfinishedResumeRow(row, context = {}) {
  const actionName = getUnfinishedRowActionName(row?.outcome);
  const level = getUnfinishedRowLogLevel(row?.outcome);
  const status = getUnfinishedRowStatus(row?.outcome);
  reportAdminActionEvent(actionName, {
    level,
    status,
    reason: row?.reason || row?.outcome || 'unfinished_resume',
    origin: context?.origin || 'unfinished-resume',
    error: typeof row?.error === 'string' ? row.error : '',
    details: {
      jobId: context?.jobId || '',
      runId: row?.runId || '',
      title: row?.title || '',
      detectedPromptNumber: Number.isInteger(row?.detectedPromptNumber) ? row.detectedPromptNumber : null,
      startPromptNumber: Number.isInteger(row?.startPromptNumber) ? row.startPromptNumber : null,
      detectedMethod: row?.detectedMethod || '',
      retrySamePrompt: row?.retrySamePrompt === true,
      retryReason: row?.retryReason || ''
    }
  });
  try {
    await appendProblemLog({
      timestamp: Date.now(),
      level,
      source: 'unfinished-resume-batch',
      category: 'recovery',
      analysisType: 'admin',
      runId: typeof row?.runId === 'string' ? row.runId : '',
      title: typeof row?.title === 'string' ? row.title : '',
      status,
      reason: typeof row?.reason === 'string' ? row.reason : '',
      error: typeof row?.error === 'string' ? row.error : '',
      statusText: `job=${context?.jobId || ''} outcome=${row?.outcome || ''}`,
      message: actionName,
      signature: [
        'unfinished-resume-row',
        context?.jobId || '',
        row?.runId || '',
        row?.outcome || '',
        row?.reason || '',
        Number.isInteger(row?.startedAt) ? row.startedAt : Date.now()
      ].join('|')
    });
  } catch (error) {
    console.warn('[unfinished-resume] row log append failed:', error?.message || String(error));
  }
}

async function resumeSingleUnfinishedProcess(candidate, context = {}) {
  const startedAt = Date.now();
  const baseRow = {
    runId: typeof candidate?.runId === 'string' ? candidate.runId : '',
    title: typeof candidate?.title === 'string' ? candidate.title : '',
    startedAt,
    finishedAt: Date.now(),
    outcome: 'failed',
    reason: 'unknown',
    error: '',
    detectedPromptNumber: null,
    startPromptNumber: null,
    detectedMethod: '',
    retrySamePrompt: false,
    retryReason: '',
    chatUrl: typeof candidate?.chatUrl === 'string' ? candidate.chatUrl : ''
  };
  if (!baseRow.runId) {
    const row = {
      ...baseRow,
      finishedAt: Date.now(),
      outcome: 'skipped_not_found',
      reason: 'missing_run_id'
    };
    await logUnfinishedResumeRow(row, context);
    return row;
  }

  await ensureProcessRegistryReady();
  const latest = processRegistry.get(baseRow.runId);
  if (!latest) {
    const row = {
      ...baseRow,
      finishedAt: Date.now(),
      outcome: 'skipped_not_found',
      reason: 'process_not_found'
    };
    await logUnfinishedResumeRow(row, context);
    return row;
  }

  const latestStatus = normalizeProcessStatus(latest.status || '');
  if (latestStatus === 'completed') {
    const row = {
      ...baseRow,
      title: typeof latest?.title === 'string' ? latest.title : baseRow.title,
      finishedAt: Date.now(),
      outcome: 'skipped_already_completed',
      reason: 'already_completed'
    };
    await logUnfinishedResumeRow(row, context);
    return row;
  }

  const chatUrl = extractProcessChatUrl(latest);
  if (!chatUrl) {
    const row = {
      ...baseRow,
      title: typeof latest?.title === 'string' ? latest.title : baseRow.title,
      finishedAt: Date.now(),
      outcome: 'skipped_missing_chat_url',
      reason: 'missing_chat_url'
    };
    await logUnfinishedResumeRow(row, context);
    return row;
  }

  try {
    const resumeResult = await handleProcessResumeNextStageMessage({
      runId: baseRow.runId,
      tabId: Number.isInteger(latest?.tabId) ? latest.tabId : null,
      windowId: Number.isInteger(latest?.windowId) ? latest.windowId : null,
      title: typeof latest?.title === 'string' ? latest.title : '',
      chatUrl,
      origin: context?.origin || 'unfinished-resume-batch',
      preferFreshTab: true
    });

    const detectedPromptNumber = Number.isInteger(resumeResult?.detectedPromptNumber)
      ? resumeResult.detectedPromptNumber
      : null;
    const startPromptNumber = Number.isInteger(resumeResult?.startPromptNumber)
      ? resumeResult.startPromptNumber
      : null;
    const detectedMethod = typeof resumeResult?.detectedMethod === 'string'
      ? resumeResult.detectedMethod
      : '';
    const retrySamePrompt = resumeResult?.retrySamePrompt === true;
    const retryReason = typeof resumeResult?.retryReason === 'string' ? resumeResult.retryReason : '';

    if (resumeResult?.success === true) {
      const row = {
        ...baseRow,
        title: typeof latest?.title === 'string' ? latest.title : baseRow.title,
        finishedAt: Date.now(),
        outcome: 'resumed',
        reason: 'resume_dispatched',
        detectedPromptNumber,
        startPromptNumber,
        detectedMethod,
        retrySamePrompt,
        retryReason,
        chatUrl
      };
      await logUnfinishedResumeRow(row, context);
      return row;
    }

    const normalizedError = typeof resumeResult?.error === 'string'
      ? resumeResult.error.trim()
      : 'resume_failed';
    if (normalizedError === 'already_at_last_prompt') {
      const row = {
        ...baseRow,
        title: typeof latest?.title === 'string' ? latest.title : baseRow.title,
        finishedAt: Date.now(),
        outcome: 'skipped_already_completed',
        reason: 'already_at_last_prompt',
        detectedPromptNumber,
        startPromptNumber,
        detectedMethod,
        retrySamePrompt,
        retryReason,
        chatUrl
      };
      await logUnfinishedResumeRow(row, context);
      return row;
    }

    const row = {
      ...baseRow,
      title: typeof latest?.title === 'string' ? latest.title : baseRow.title,
      finishedAt: Date.now(),
      outcome: 'failed',
      reason: normalizedError || 'resume_failed',
      error: normalizedError || 'resume_failed',
      detectedPromptNumber,
      startPromptNumber,
      detectedMethod,
      retrySamePrompt,
      retryReason,
      chatUrl
    };
    await logUnfinishedResumeRow(row, context);
    return row;
  } catch (error) {
    const errorText = error?.message || String(error);
    const row = {
      ...baseRow,
      title: typeof latest?.title === 'string' ? latest.title : baseRow.title,
      finishedAt: Date.now(),
      outcome: 'failed',
      reason: 'resume_exception',
      error: errorText,
      chatUrl
    };
    await logUnfinishedResumeRow(row, context);
    return row;
  }
}

function applyUnfinishedResumeOutcomeToTotals(totals, row) {
  const nextTotals = normalizeUnfinishedResumeBatchTotals(totals);
  nextTotals.processed += 1;
  const outcome = typeof row?.outcome === 'string' ? row.outcome : '';
  if (outcome === 'resumed') nextTotals.resumed += 1;
  if (outcome === 'skipped_missing_chat_url') nextTotals.skipped_missing_chat_url += 1;
  if (outcome === 'skipped_not_found') nextTotals.skipped_not_found += 1;
  if (outcome === 'skipped_already_completed') nextTotals.skipped_already_completed += 1;
  if (outcome === 'failed') nextTotals.failed += 1;
  return nextTotals;
}

async function runResumeUnfinishedProcessesBatch(jobId, options = {}) {
  const safeJobId = typeof jobId === 'string' ? jobId.trim() : '';
  if (!safeJobId) return null;
  const context = {
    jobId: safeJobId,
    origin: typeof options?.origin === 'string' && options.origin.trim()
      ? options.origin.trim()
      : 'unfinished-resume'
  };

  try {
    const providedCandidates = Array.isArray(options?.candidates) ? options.candidates : null;
    const listing = providedCandidates
      ? null
      : await listUnfinishedProcessesForResume({
        includeNonCompleted: true,
        recoverOnly: true
      });
    const candidates = providedCandidates || (Array.isArray(listing?.items) ? listing.items : []);
    let state = await getUnfinishedResumeBatchState(safeJobId);
    if (!state || state.status !== 'running') {
      return state;
    }

    for (const candidate of candidates) {
      state = await getUnfinishedResumeBatchState(safeJobId);
      if (!state || state.status !== 'running') {
        break;
      }
      state.activeRunId = typeof candidate?.runId === 'string' ? candidate.runId : '';
      await setUnfinishedResumeBatchState(state);

      const row = await resumeSingleUnfinishedProcess(candidate, context);
      const nextRows = (Array.isArray(state.rows) ? state.rows : []).concat([row]).slice(-UNFINISHED_RESUME_BATCH_MAX_ROWS);
      const nextTotals = applyUnfinishedResumeOutcomeToTotals(state.totals, row);

      state = {
        ...state,
        rows: nextRows,
        totals: nextTotals,
        activeRunId: ''
      };
      await setUnfinishedResumeBatchState(state);
    }

    state = await getUnfinishedResumeBatchState(safeJobId);
    if (!state) return null;
    if (state.status !== 'running') {
      return state;
    }

    const totalIssues = (state?.totals?.failed || 0)
      + (state?.totals?.skipped_missing_chat_url || 0)
      + (state?.totals?.skipped_not_found || 0);
    const completedStatus = totalIssues > 0 ? 'completed_with_errors' : 'completed';
    const finishedState = {
      ...state,
      status: completedStatus,
      activeRunId: '',
      finishedAt: Date.now()
    };
    const saved = await setUnfinishedResumeBatchState(finishedState);
    reportAdminActionEvent(
      completedStatus === 'completed'
        ? 'resume_unfinished_batch_completed'
        : 'resume_unfinished_batch_completed_with_errors',
      {
        level: completedStatus === 'completed' ? 'info' : 'warn',
        status: completedStatus,
        reason: completedStatus === 'completed' ? 'batch_completed' : 'batch_completed_with_errors',
        origin: context.origin,
        details: {
          jobId: safeJobId,
          totals: saved?.totals || {}
        },
        error: completedStatus === 'completed' ? '' : (saved?.error || '')
      }
    );
    return saved;
  } catch (error) {
    const current = await getUnfinishedResumeBatchState(safeJobId);
    if (!current) {
      unfinishedResumeBatchInProgress = false;
      unfinishedResumeBatchActiveJobId = '';
      throw error;
    }
    const failedState = await setUnfinishedResumeBatchState({
      ...current,
      status: 'completed_with_errors',
      activeRunId: '',
      finishedAt: Date.now(),
      error: error?.message || String(error)
    });
    reportAdminActionEvent('resume_unfinished_batch_completed_with_errors', {
      level: 'error',
      status: 'failed',
      reason: 'batch_exception',
      origin: context.origin,
      error: error?.message || String(error),
      details: {
        jobId: safeJobId,
        totals: failedState?.totals || {}
      }
    });
    return failedState;
  } finally {
    if (unfinishedResumeBatchActiveJobId === safeJobId) {
      unfinishedResumeBatchInProgress = false;
      unfinishedResumeBatchActiveJobId = '';
    }
  }
}

async function startResumeUnfinishedProcessesBatch(options = {}) {
  const origin = typeof options?.origin === 'string' && options.origin.trim()
    ? options.origin.trim()
    : 'runtime-message';
  const forceRestartIfRunning = options?.forceRestartIfRunning === true;
  const sourceFilter = normalizeUnfinishedSourceFilter(options?.sourceFilter);
  const limitRequested = normalizeUnfinishedResumeLimit(options?.limit);
  const current = await getUnfinishedResumeBatchState();
  if (current?.status === 'running') {
    if (!forceRestartIfRunning) {
      return {
        success: true,
        started: false,
        jobId: current.jobId || '',
        alreadyRunning: true,
        state: current
      };
    }
    await setUnfinishedResumeBatchState({
      ...current,
      status: 'interrupted',
      finishedAt: Date.now(),
      activeRunId: '',
      error: current.error || 'force_restarted'
    });
  }

  const listing = await listUnfinishedProcessesForResume({
    includeNonCompleted: true,
    recoverOnly: true,
    sourceFilter,
    origin: `${origin}:selection`
  });
  const allCandidates = Array.isArray(listing?.items) ? listing.items : [];
  const rankingStrategy = Number.isInteger(limitRequested)
    ? 'most_advanced_incomplete_first'
    : 'latest_update_first';
  const rankedCandidates = Number.isInteger(limitRequested)
    ? allCandidates.slice().sort(compareUnfinishedCandidatesByProgressDesc)
    : allCandidates.slice();
  const limitApplied = Number.isInteger(limitRequested)
    ? Math.min(limitRequested, rankedCandidates.length)
    : null;
  const candidates = Number.isInteger(limitApplied)
    ? rankedCandidates.slice(0, limitApplied)
    : rankedCandidates;
  const selectedRunnable = candidates.filter((item) => item?.hasChatUrl === true).length;
  const selectedSkippedMissingUrl = candidates.length - selectedRunnable;
  const selectedSource = sourceFilter
    ? (Array.isArray(listing?.availableSources)
      ? listing.availableSources.find((entry) => entry?.key === sourceFilter)
      : null)
    : null;
  const selection = {
    sourceFilter: sourceFilter || 'all',
    sourceLabel: selectedSource?.label || '',
    strategy: rankingStrategy,
    limitRequested,
    limitApplied,
    filteredTotal: Number.isInteger(listing?.total) ? listing.total : rankedCandidates.length
  };
  const candidatePreview = candidates.slice(0, 5).map((item) => ({
    runId: typeof item?.runId === 'string' ? item.runId : '',
    currentPrompt: Number.isInteger(item?.currentPrompt) ? item.currentPrompt : 0,
    totalPrompts: Number.isInteger(item?.totalPrompts) ? item.totalPrompts : 0,
    hasChatUrl: item?.hasChatUrl === true
  }));
  console.log('[unfinished-resume] batch selection', {
    origin,
    sourceFilter: selection.sourceFilter,
    strategy: rankingStrategy,
    filteredTotal: selection.filteredTotal,
    selectedTotal: candidates.length,
    runnableSelected: selectedRunnable,
    blockedSelected: selectedSkippedMissingUrl,
    candidatePreview
  });
  reportAdminActionEvent('unfinished_resume_candidates_selected', {
    level: 'info',
    status: 'selected',
    reason: 'unfinished_resume_candidates_selected',
    origin,
    title: 'Unfinished resume candidates selected',
    message: `unfinished_resume_candidates_selected | selected=${candidates.length}/${selection.filteredTotal} | runnable=${selectedRunnable} | blocked=${selectedSkippedMissingUrl} | strategy=${rankingStrategy}`,
    details: {
      sourceFilter: selection.sourceFilter,
      sourceLabel: selection.sourceLabel,
      strategy: rankingStrategy,
      filteredTotal: selection.filteredTotal,
      selectedTotal: candidates.length,
      runnableSelected: selectedRunnable,
      blockedSelected: selectedSkippedMissingUrl,
      candidatePreview
    }
  });

  const jobId = createUnfinishedResumeBatchJobId('unfinished-resume');
  const initialState = {
    jobId,
    status: 'running',
    startedAt: Date.now(),
    finishedAt: null,
    origin,
    selection,
    totals: normalizeUnfinishedResumeBatchTotals({
      total: candidates.length,
      runnable: selectedRunnable,
      skippedMissingUrl: selectedSkippedMissingUrl,
      processed: 0,
      resumed: 0,
      skipped_missing_chat_url: 0,
      skipped_not_found: 0,
      skipped_already_completed: 0,
      failed: 0
    }),
    rows: [],
    activeRunId: '',
    error: ''
  };
  await setUnfinishedResumeBatchState(initialState);
  reportAdminActionEvent('resume_unfinished_batch_started', {
    level: 'info',
    status: 'started',
    reason: 'batch_started',
    origin,
    details: {
      jobId,
      total: candidates.length,
      runnable: selectedRunnable,
      skippedMissingUrl: selectedSkippedMissingUrl,
      sourceFilter: selection.sourceFilter,
      sourceLabel: selection.sourceLabel,
      strategy: selection.strategy,
      limitRequested: selection.limitRequested,
      limitApplied: selection.limitApplied,
      filteredTotal: selection.filteredTotal
    }
  });
  void runResumeUnfinishedProcessesBatch(jobId, {
    origin,
    candidates
  });
  return {
    success: true,
    started: true,
    jobId,
    alreadyRunning: false,
    state: await getUnfinishedResumeBatchState(jobId)
  };
}

function trimProblemLogText(value, maxLength = PROBLEM_LOG_MAX_TEXT_LENGTH) {
  const safeValue = typeof value === 'string' ? value.trim() : '';
  if (!safeValue) return '';
  if (!Number.isInteger(maxLength) || maxLength <= 0) return safeValue;
  if (safeValue.length <= maxLength) return safeValue;
  return `${safeValue.slice(0, Math.max(0, maxLength - 3))}...`;
}

function normalizeProblemLogLevel(value) {
  const normalized = typeof value === 'string' ? value.trim().toLowerCase() : '';
  if (normalized === 'error') return 'error';
  if (normalized === 'warn' || normalized === 'warning') return 'warn';
  return 'info';
}

function extractSupportIdFromProblemLogSource(sourceText) {
  const source = typeof sourceText === 'string' ? sourceText : '';
  if (!source) return '';
  const match = source.match(/(?:^|\|)support:([^|]+)/i);
  return trimProblemLogText(match?.[1] || '', 120);
}

function inferSupportIdFromRunId(runId, sourceText = '') {
  const normalizedRunId = trimProblemLogText(runId || '', 120);
  if (!normalizedRunId) return '';
  const normalizedSource = String(sourceText || '').toLowerCase();
  if (/^run-e2e-/i.test(normalizedRunId) && normalizedSource.includes('origin:test')) {
    return trimProblemLogText(`ext-${normalizedRunId.slice(4)}`, 120);
  }
  return '';
}

function inferProblemLogTitle(rawTitle, reason, message = '') {
  const explicitTitle = trimProblemLogText(rawTitle || '', 160);
  if (explicitTitle) return explicitTitle;

  const normalizedReason = trimProblemLogText(reason || '', 140).toLowerCase();
  if (normalizedReason === 'post_restore_check') return 'Post-restore check';
  if (normalizedReason === 'integration_test') return 'Integration test';
  if (normalizedReason.includes('data_gap')) return 'Data gap';
  if (normalizedReason.includes('dispatch')) return 'Dispatch issue';
  if (normalizedReason.includes('runtime')) return 'Runtime issue';

  const messageText = trimProblemLogText(message || '', 160);
  if (!messageText) return '';
  return messageText;
}

function inferProblemLogStageName(rawStageName, reason, fallbackTitle = '') {
  const explicitStageName = trimProblemLogText(rawStageName || '', 120);
  if (explicitStageName) return explicitStageName;

  const normalizedReason = trimProblemLogText(reason || '', 140).toLowerCase();
  if (normalizedReason === 'integration_test') return 'Stage E2E';
  if (normalizedReason === 'post_restore_check') return 'Post-restore';
  if (normalizedReason.includes('data_gap')) return 'Data gap';

  const title = trimProblemLogText(fallbackTitle || '', 120);
  return title || '';
}

function toProblemLogNonNegativeInteger(value) {
  if (Number.isInteger(value)) {
    return value >= 0 ? value : null;
  }
  if (typeof value === 'number' && Number.isFinite(value)) {
    const normalized = Math.trunc(value);
    return normalized >= 0 ? normalized : null;
  }
  return null;
}

function resolveProblemLogStageProgress({
  status = '',
  reason = '',
  error = '',
  statusText = '',
  currentPrompt = null,
  totalPrompts = null,
  stageIndex = null,
  stageName = ''
} = {}) {
  let normalizedCurrentPrompt = toProblemLogNonNegativeInteger(currentPrompt);
  let normalizedTotalPrompts = toProblemLogNonNegativeInteger(totalPrompts);
  let normalizedStageIndex = toProblemLogNonNegativeInteger(stageIndex);
  const normalizedStageName = trimProblemLogText(stageName || '', 120);

  if (normalizedCurrentPrompt !== null && normalizedCurrentPrompt <= 0) {
    normalizedCurrentPrompt = null;
  }
  if (normalizedTotalPrompts !== null && normalizedTotalPrompts <= 0) {
    normalizedTotalPrompts = null;
  }

  if (normalizedCurrentPrompt === null && normalizedStageIndex !== null) {
    normalizedCurrentPrompt = normalizedStageIndex + 1;
  }
  if (normalizedStageIndex === null && normalizedCurrentPrompt !== null) {
    normalizedStageIndex = normalizedCurrentPrompt - 1;
  }
  if (
    normalizedTotalPrompts !== null
    && normalizedCurrentPrompt !== null
    && normalizedCurrentPrompt > normalizedTotalPrompts
  ) {
    normalizedCurrentPrompt = normalizedTotalPrompts;
  }
  if (
    normalizedTotalPrompts !== null
    && normalizedStageIndex !== null
    && normalizedStageIndex >= normalizedTotalPrompts
  ) {
    normalizedStageIndex = normalizedTotalPrompts - 1;
  }

  const normalizedStatus = normalizeProcessStatus(status);
  const signalBlob = [reason, error, statusText]
    .map((value) => (typeof value === 'string' ? value.toLowerCase() : ''))
    .join(' ');
  const hasBlockingSignal = /needs_action|missing_assistant_reply|invalid_response|timeout|send_failed|save_failed|data[_\s-]?gap|failed|error/.test(signalBlob);
  const canAdvance = !isClosedProcessStatus(normalizedStatus)
    && !hasBlockingSignal
    && (normalizedStatus === 'running' || normalizedStatus === 'starting' || normalizedStatus === 'started' || normalizedStatus === 'queued');

  let nextPrompt = null;
  if (normalizedCurrentPrompt !== null) {
    nextPrompt = canAdvance ? (normalizedCurrentPrompt + 1) : normalizedCurrentPrompt;
  } else if (normalizedStageIndex !== null) {
    nextPrompt = canAdvance ? (normalizedStageIndex + 2) : (normalizedStageIndex + 1);
  }
  if (normalizedTotalPrompts !== null && nextPrompt !== null && nextPrompt > normalizedTotalPrompts) {
    nextPrompt = normalizedTotalPrompts;
  }
  if (nextPrompt !== null && nextPrompt <= 0) {
    nextPrompt = null;
  }

  let nextStageIndex = null;
  if (nextPrompt !== null) {
    nextStageIndex = Math.max(0, nextPrompt - 1);
    if (normalizedTotalPrompts !== null && nextStageIndex >= normalizedTotalPrompts) {
      nextStageIndex = normalizedTotalPrompts - 1;
    }
  }

  let nextStageName = '';
  if (nextPrompt !== null) {
    nextStageName = `Prompt ${nextPrompt}`;
  } else if (normalizedStageName) {
    nextStageName = normalizedStageName;
  }

  return {
    currentPrompt: normalizedCurrentPrompt,
    totalPrompts: normalizedTotalPrompts,
    stageIndex: normalizedStageIndex,
    stageName: normalizedStageName,
    nextPrompt,
    nextStageIndex,
    nextStageName: trimProblemLogText(nextStageName, 120),
    canAdvance
  };
}

function inferProblemLogDataGapState({
  status = '',
  reason = '',
  error = '',
  statusText = '',
  message = '',
  explicitDetected = false,
  explicitSignal = '',
  explicitMissingInputs = ''
} = {}) {
  const parsed = parseDataGapsStopFromText([
    typeof statusText === 'string' ? statusText : '',
    typeof error === 'string' ? error : '',
    typeof message === 'string' ? message : ''
  ].filter(Boolean).join('\n'));
  const markerDetected = [
    status,
    reason,
    error,
    statusText,
    message
  ].some((value) => looksLikeDataGapMarker(typeof value === 'string' ? value : ''));

  const detected = explicitDetected || parsed.detected || markerDetected;
  const signal = trimProblemLogText(
    explicitSignal
      || (parsed.detected ? 'system_command' : (markerDetected ? 'marker' : '')),
    80
  );
  const missingInputs = trimProblemLogText(
    explicitMissingInputs || parsed.missingInputsText || '',
    320
  );

  return {
    detected,
    signal,
    missingInputs
  };
}

function classifyProblemLogCategory({
  analysisType = '',
  level = 'info',
  reason = '',
  source = '',
  status = '',
  title = '',
  message = ''
} = {}) {
  const normalizedLevel = normalizeProblemLogLevel(level);
  const blob = [
    analysisType,
    reason,
    source,
    status,
    title,
    message
  ].join(' ').toLowerCase();

  if (blob.includes('integration_test') || blob.includes('e2e')) return 'test';
  if (blob.includes('post_restore')) return 'recovery';
  if (blob.includes('data_gap')) return 'data_gap';
  if (blob.includes('dispatch')) return 'dispatch';
  if (blob.includes('runtime') || blob.includes('unhandledrejection')) return 'runtime';

  if (normalizedLevel === 'error') return 'error';
  if (normalizedLevel === 'warn') return 'warning';
  return 'info';
}

function createExtensionInstallationId() {
  if (typeof globalThis?.crypto?.randomUUID === 'function') {
    return `ext-${globalThis.crypto.randomUUID()}`;
  }
  return `ext-${Date.now().toString(36)}-${Math.random().toString(36).slice(2, 10)}`;
}

async function ensureExtensionInstallationId() {
  if (typeof extensionInstallationId === 'string' && extensionInstallationId.trim()) {
    return extensionInstallationId.trim();
  }
  if (!extensionInstallationIdReady) {
    extensionInstallationIdReady = (async () => {
      try {
        const result = await chrome.storage.local.get([EXTENSION_INSTALLATION_ID_STORAGE_KEY]);
        const stored = typeof result?.[EXTENSION_INSTALLATION_ID_STORAGE_KEY] === 'string'
          ? result[EXTENSION_INSTALLATION_ID_STORAGE_KEY].trim()
          : '';
        if (stored) {
          extensionInstallationId = stored;
          return extensionInstallationId;
        }
        const generated = createExtensionInstallationId();
        await chrome.storage.local.set({ [EXTENSION_INSTALLATION_ID_STORAGE_KEY]: generated });
        extensionInstallationId = generated;
        return extensionInstallationId;
      } catch (error) {
        console.warn('[problem-log] install-id load failed:', error?.message || String(error));
        const fallback = createExtensionInstallationId();
        extensionInstallationId = fallback;
        return extensionInstallationId;
      }
    })();
  }
  const resolved = await extensionInstallationIdReady;
  return typeof resolved === 'string' ? resolved : '';
}

function buildProblemLogMessage(entry) {
  if (!entry || typeof entry !== 'object') return '';
  const parts = [];
  const status = typeof entry.status === 'string' ? entry.status.trim() : '';
  const reason = typeof entry.reason === 'string' ? entry.reason.trim() : '';
  const error = typeof entry.error === 'string' ? entry.error.trim() : '';
  const statusText = typeof entry.statusText === 'string' ? entry.statusText.trim() : '';
  const stageName = typeof entry.stageName === 'string' ? entry.stageName.trim() : '';
  const title = trimProblemLogText(typeof entry.title === 'string' ? entry.title.trim() : '', 120);
  const sourceUrl = normalizeProblemLogSourceUrl(
    typeof entry.sourceUrl === 'string'
      ? entry.sourceUrl
      : (typeof entry.source_url === 'string' ? entry.source_url : '')
  );
  const chatUrl = normalizeChatConversationUrl(
    typeof entry.chatUrl === 'string'
      ? entry.chatUrl
      : (typeof entry.conversationUrl === 'string' ? entry.conversationUrl : '')
  );
  const stageProgress = resolveProblemLogStageProgress({
    status,
    reason,
    error,
    statusText,
    currentPrompt: entry.currentPrompt,
    totalPrompts: entry.totalPrompts,
    stageIndex: entry.stageIndex,
    stageName
  });
  const dataGapState = inferProblemLogDataGapState({
    status,
    reason,
    error,
    statusText,
    message: typeof entry.message === 'string' ? entry.message : '',
    explicitDetected: entry.dataGapDetected === true,
    explicitSignal: typeof entry.dataGapSignal === 'string' ? entry.dataGapSignal : '',
    explicitMissingInputs: typeof entry.dataGapMissingInputs === 'string' ? entry.dataGapMissingInputs : ''
  });

  if (title) parts.push(`title=${title}`);
  if (status) parts.push(`status=${status}`);
  if (reason) parts.push(`reason=${reason}`);
  if (error) parts.push(`error=${error}`);
  if (statusText) parts.push(`statusText=${statusText}`);

  if (stageProgress.currentPrompt !== null || stageProgress.totalPrompts !== null) {
    parts.push(
      `prompt=${stageProgress.currentPrompt ?? '?'}${stageProgress.totalPrompts !== null ? `/${stageProgress.totalPrompts}` : ''}`
    );
  }
  if (stageProgress.stageName) {
    parts.push(`stage=${stageProgress.stageName}`);
  }
  if (stageProgress.nextPrompt !== null) {
    parts.push(`next_prompt=${stageProgress.nextPrompt}`);
  }
  if (stageProgress.nextStageName) {
    parts.push(`next_stage=${stageProgress.nextStageName}`);
  }
  if (dataGapState.detected) {
    parts.push('data_gap=1');
    if (dataGapState.signal) parts.push(`data_gap_signal=${dataGapState.signal}`);
    if (dataGapState.missingInputs) parts.push(`data_gap_missing_inputs=${dataGapState.missingInputs}`);
  }
  if (sourceUrl) {
    parts.push(`sourceUrl=${sourceUrl}`);
  }
  if (chatUrl) {
    parts.push(`chatUrl=${chatUrl}`);
  }

  const content = parts.join(' | ');
  return trimProblemLogText(content || 'problem_detected');
}

function normalizeProblemLogSourceUrl(rawUrl) {
  const value = typeof rawUrl === 'string' ? rawUrl.trim() : '';
  if (!value) return '';
  if (/^manual:\/\//i.test(value)) return trimProblemLogText(value, 320);
  try {
    return new URL(value).toString();
  } catch {
    return trimProblemLogText(value, 320);
  }
}

function sanitizeProblemLogEntry(rawEntry) {
  if (!rawEntry || typeof rawEntry !== 'object') return null;
  const timestamp = Number.isInteger(rawEntry.timestamp) && rawEntry.timestamp > 0
    ? rawEntry.timestamp
    : Date.now();
  const level = normalizeProblemLogLevel(rawEntry.level);
  const runId = typeof rawEntry.runId === 'string' ? rawEntry.runId.trim() : '';
  const source = trimProblemLogText(rawEntry.source || 'process', 80) || 'process';
  const status = trimProblemLogText(rawEntry.status || '', 40);
  const reason = trimProblemLogText(rawEntry.reason || '', 140);
  const error = trimProblemLogText(rawEntry.error || '', 200);
  const statusText = trimProblemLogText(rawEntry.statusText || '', 240);
  const title = inferProblemLogTitle(rawEntry.title || '', reason, rawEntry.message || '');
  const analysisType = trimProblemLogText(rawEntry.analysisType || '', 40);
  const stageName = inferProblemLogStageName(rawEntry.stageName || '', reason, title);
  const stageProgress = resolveProblemLogStageProgress({
    status,
    reason,
    error,
    statusText,
    currentPrompt: rawEntry.currentPrompt,
    totalPrompts: rawEntry.totalPrompts,
    stageIndex: rawEntry.stageIndex,
    stageName
  });
  const supportId = trimProblemLogText(
    rawEntry.supportId
      || extractSupportIdFromProblemLogSource(source)
      || inferSupportIdFromRunId(runId, source)
      || '',
    120
  );
  const category = trimProblemLogText(
    rawEntry.category || classifyProblemLogCategory({
      analysisType,
      level,
      reason,
      source,
      status,
      title,
      message: rawEntry.message || ''
    }),
    80
  );
  const chatUrl = normalizeChatConversationUrl(
    typeof rawEntry.chatUrl === 'string'
      ? rawEntry.chatUrl
      : (typeof rawEntry.conversationUrl === 'string' ? rawEntry.conversationUrl : '')
  );
  const sourceUrl = normalizeProblemLogSourceUrl(
    typeof rawEntry.sourceUrl === 'string'
      ? rawEntry.sourceUrl
      : (typeof rawEntry.source_url === 'string' ? rawEntry.source_url : '')
  );
  const heartbeat = rawEntry.heartbeat === true;
  const dataGapState = inferProblemLogDataGapState({
    status,
    reason,
    error,
    statusText,
    message: typeof rawEntry.message === 'string' ? rawEntry.message : '',
    explicitDetected: rawEntry.dataGapDetected === true,
    explicitSignal: typeof rawEntry.dataGapSignal === 'string' ? rawEntry.dataGapSignal : '',
    explicitMissingInputs: typeof rawEntry.dataGapMissingInputs === 'string'
      ? rawEntry.dataGapMissingInputs
      : ''
  });
  const message = trimProblemLogText(rawEntry.message || buildProblemLogMessage(rawEntry));
  const signature = trimProblemLogText(rawEntry.signature || '', 380);
  const entryId = typeof rawEntry.id === 'string' && rawEntry.id.trim()
    ? rawEntry.id.trim()
    : `plog-${timestamp}-${Math.random().toString(36).slice(2, 8)}`;

  return {
    id: entryId,
    timestamp,
    level,
    source,
    runId,
    supportId,
    title,
    category,
    analysisType,
    status,
    reason,
    error,
    statusText,
    message: message || 'problem_detected',
    signature,
    currentPrompt: stageProgress.currentPrompt,
    totalPrompts: stageProgress.totalPrompts,
    stageIndex: stageProgress.stageIndex,
    stageName: stageProgress.stageName,
    nextPrompt: stageProgress.nextPrompt,
    nextStageIndex: stageProgress.nextStageIndex,
    nextStageName: stageProgress.nextStageName,
    dataGapDetected: dataGapState.detected,
    dataGapSignal: dataGapState.signal,
    dataGapMissingInputs: dataGapState.missingInputs,
    tabId: Number.isInteger(rawEntry.tabId) ? rawEntry.tabId : null,
    windowId: Number.isInteger(rawEntry.windowId) ? rawEntry.windowId : null,
    sourceUrl: sourceUrl || '',
    chatUrl: chatUrl || '',
    conversationUrl: chatUrl || '',
    heartbeat
  };
}

function normalizeProblemLogEntries(rawEntries) {
  const normalized = (Array.isArray(rawEntries) ? rawEntries : [])
    .map(sanitizeProblemLogEntry)
    .filter(Boolean);
  if (normalized.length <= PROBLEM_LOG_MAX_ITEMS) return normalized;
  return normalized.slice(normalized.length - PROBLEM_LOG_MAX_ITEMS);
}

async function ensureProblemLogReady() {
  if (!problemLogReady) {
    problemLogReady = (async () => {
      try {
        const stored = await chrome.storage.local.get([PROBLEM_LOG_STORAGE_KEY]);
        problemLogEntries = normalizeProblemLogEntries(stored?.[PROBLEM_LOG_STORAGE_KEY]);
      } catch (error) {
        console.warn('[problem-log] load failed:', error?.message || error);
        problemLogEntries = [];
      }
    })();
  }
  await problemLogReady;
  return problemLogEntries;
}

async function persistProblemLogEntries() {
  await chrome.storage.local.set({
    [PROBLEM_LOG_STORAGE_KEY]: problemLogEntries
  });
}

function cloneProblemLogEntries(entries) {
  try {
    return structuredClone(Array.isArray(entries) ? entries : []);
  } catch (error) {
    return JSON.parse(JSON.stringify(Array.isArray(entries) ? entries : []));
  }
}

async function getProblemLogSnapshot(limit = 120) {
  await ensureProblemLogReady();
  const safeLimit = Number.isInteger(limit) && limit > 0
    ? Math.min(limit, PROBLEM_LOG_MAX_ITEMS)
    : 120;
  const normalized = Array.isArray(problemLogEntries) ? problemLogEntries : [];
  const sliced = normalized.slice(Math.max(0, normalized.length - safeLimit));
  return cloneProblemLogEntries(sliced).reverse();
}

async function clearProblemLogs() {
  await ensureProblemLogReady();
  problemLogEntries = [];
  problemLogLastSignatureByRunId.clear();
  processLogLastEmitTsByRunId.clear();
  processStaleWarnLastEmitTsByRunId.clear();
  await persistProblemLogEntries();
  try {
    await chrome.runtime.sendMessage({
      type: 'PROBLEM_LOGS_UPDATED',
      changed: 'clear'
    });
  } catch (error) {
    // Ignore when no listeners are attached.
  }
  return true;
}

async function appendProblemLog(rawEntry) {
  const normalized = sanitizeProblemLogEntry(rawEntry);
  if (!normalized) return null;
  await ensureProblemLogReady();

  const latest = problemLogEntries.length > 0 ? problemLogEntries[problemLogEntries.length - 1] : null;
  if (
    latest
    && latest.signature
    && normalized.signature
    && latest.signature === normalized.signature
    && Math.abs((normalized.timestamp || 0) - (latest.timestamp || 0)) <= PROBLEM_LOG_BURST_DEDUPE_MS
  ) {
    return latest;
  }

  problemLogEntries.push(normalized);
  if (problemLogEntries.length > PROBLEM_LOG_MAX_ITEMS) {
    problemLogEntries = problemLogEntries.slice(problemLogEntries.length - PROBLEM_LOG_MAX_ITEMS);
  }
  await persistProblemLogEntries();

  try {
    await chrome.runtime.sendMessage({
      type: 'PROBLEM_LOGS_UPDATED',
      changed: 'append',
      entry: normalized
    });
  } catch (error) {
    // Ignore when no listeners are attached.
  }

  if (shouldDispatchProblemLogRemotely(normalized)) {
    void enqueueProblemLogDispatch(normalized)
      .then((dispatchResult) => {
        if (dispatchResult?.queued) {
          flushWatchlistDispatchOutbox('problem_log_append').catch(() => {});
        }
      })
      .catch((error) => {
        console.warn('[problem-log] remote dispatch queue failed:', error?.message || String(error));
      });
  }

  return normalized;
}

function normalizeConversationLogSnapshotEntry(rawEntry) {
  if (!rawEntry || typeof rawEntry !== 'object') return null;
  const normalized = sanitizeProblemLogEntry(rawEntry);
  if (!normalized) return null;

  const chatUrl = normalizeChatConversationUrl(
    typeof normalized.chatUrl === 'string'
      ? normalized.chatUrl
      : (typeof normalized.conversationUrl === 'string' ? normalized.conversationUrl : '')
  );

  return {
    id: typeof normalized.id === 'string' ? normalized.id : '',
    timestamp: Number.isInteger(normalized.timestamp) ? normalized.timestamp : Date.now(),
    level: normalizeProblemLogLevel(normalized.level),
    source: trimProblemLogText(normalized.source || '', 80),
    title: trimProblemLogText(normalized.title || '', 120),
    category: trimProblemLogText(normalized.category || '', 80),
    status: trimProblemLogText(normalized.status || '', 40),
    reason: trimProblemLogText(normalized.reason || '', 140),
    stageName: trimProblemLogText(normalized.stageName || '', 120),
    message: trimProblemLogText(normalized.message || '', RESPONSE_CONVERSATION_LOG_MESSAGE_MAX_LENGTH),
    runId: trimProblemLogText(normalized.runId || '', 120),
    currentPrompt: Number.isInteger(normalized.currentPrompt) ? normalized.currentPrompt : null,
    totalPrompts: Number.isInteger(normalized.totalPrompts) ? normalized.totalPrompts : null,
    nextPrompt: Number.isInteger(normalized.nextPrompt) ? normalized.nextPrompt : null,
    nextStageName: trimProblemLogText(normalized.nextStageName || '', 120),
    dataGapDetected: normalized.dataGapDetected === true,
    dataGapSignal: trimProblemLogText(normalized.dataGapSignal || '', 80),
    dataGapMissingInputs: trimProblemLogText(normalized.dataGapMissingInputs || '', 320),
    chatUrl: chatUrl || ''
  };
}

function normalizeConversationLogSnapshot(rawLogs, limit = RESPONSE_CONVERSATION_LOG_MAX_ITEMS) {
  const safeLimit = Number.isInteger(limit) && limit > 0
    ? Math.min(limit, RESPONSE_CONVERSATION_LOG_MAX_ITEMS)
    : RESPONSE_CONVERSATION_LOG_MAX_ITEMS;
  const normalized = (Array.isArray(rawLogs) ? rawLogs : [])
    .map(normalizeConversationLogSnapshotEntry)
    .filter(Boolean);
  if (normalized.length <= safeLimit) return normalized;
  return normalized.slice(normalized.length - safeLimit);
}

async function buildConversationLogSnapshotForResponse({ runId = '', conversationUrl = '', limit = RESPONSE_CONVERSATION_LOG_MAX_ITEMS } = {}) {
  const normalizedRunId = typeof runId === 'string' ? runId.trim() : '';
  const normalizedConversationUrl = normalizeChatConversationUrl(
    typeof conversationUrl === 'string' ? conversationUrl : ''
  );
  if (!normalizedRunId && !normalizedConversationUrl) return [];

  await ensureProblemLogReady();
  const sourceEntries = Array.isArray(problemLogEntries) ? problemLogEntries : [];
  const matched = sourceEntries.filter((entry) => {
    if (!entry || typeof entry !== 'object') return false;

    const entryRunId = typeof entry.runId === 'string' ? entry.runId.trim() : '';
    if (normalizedRunId && entryRunId === normalizedRunId) {
      return true;
    }

    if (!normalizedConversationUrl) return false;
    const entryChatUrl = normalizeChatConversationUrl(
      typeof entry.chatUrl === 'string'
        ? entry.chatUrl
        : (typeof entry.conversationUrl === 'string' ? entry.conversationUrl : '')
    );
    return !!entryChatUrl && entryChatUrl === normalizedConversationUrl;
  });

  return normalizeConversationLogSnapshot(matched, limit);
}

async function enrichWatchlistDispatchPayloadConversationSnapshot(payload, copyTrace = 'no-run/no-response') {
  const basePayload = payload && typeof payload === 'object' ? payload : null;
  const baseConversationLogCount = Number.isInteger(basePayload?.conversationLogCount) && basePayload.conversationLogCount >= 0
    ? basePayload.conversationLogCount
    : null;
  const baseHasConversationUrl = !!normalizeChatConversationUrl(
    typeof basePayload?.conversationUrl === 'string' ? basePayload.conversationUrl : ''
  );
  if (!basePayload) {
    return {
      payload,
      analysis: {
        conversationLogCount: baseConversationLogCount,
        hasConversationUrl: baseHasConversationUrl,
        snapshotRefreshed: false,
        snapshotSource: 'invalid_payload'
      }
    };
  }

  const schema = typeof basePayload.schema === 'string' ? basePayload.schema.trim().toLowerCase() : '';
  if (schema !== 'economist.response.v1') {
    return {
      payload: basePayload,
      analysis: {
        conversationLogCount: baseConversationLogCount,
        hasConversationUrl: baseHasConversationUrl,
        snapshotRefreshed: false,
        snapshotSource: 'schema_skip'
      }
    };
  }

  const runId = typeof basePayload.runId === 'string' ? basePayload.runId.trim() : '';
  const responseId = typeof basePayload.responseId === 'string' ? basePayload.responseId.trim() : '';
  const conversationUrl = normalizeChatConversationUrl(
    typeof basePayload.conversationUrl === 'string' ? basePayload.conversationUrl : ''
  );
  if (!runId && !conversationUrl) {
    return {
      payload: basePayload,
      analysis: {
        conversationLogCount: baseConversationLogCount,
        hasConversationUrl: baseHasConversationUrl,
        snapshotRefreshed: false,
        snapshotSource: 'missing_scope'
      }
    };
  }

  try {
    const conversationLogs = await buildConversationLogSnapshotForResponse({
      runId,
      conversationUrl,
      limit: RESPONSE_CONVERSATION_LOG_MAX_ITEMS
    });
    if (conversationLogs.length === 0) {
      return {
        payload: basePayload,
        analysis: {
          conversationLogCount: baseConversationLogCount,
          hasConversationUrl: !!conversationUrl || baseHasConversationUrl,
          snapshotRefreshed: false,
          snapshotSource: 'no_matches'
        }
      };
    }

    const nextPayload = {
      ...basePayload,
      conversationLogs,
      conversationLogCount: conversationLogs.length
    };
    if (conversationUrl) {
      nextPayload.conversationUrl = conversationUrl;
    }

    console.log('[copy-flow] [dispatch:conversation-snapshot-refreshed]', {
      trace: copyTrace,
      runId,
      responseId,
      conversationLogCount: conversationLogs.length
    });
    return {
      payload: nextPayload,
      analysis: {
        conversationLogCount: conversationLogs.length,
        hasConversationUrl: !!conversationUrl || baseHasConversationUrl,
        snapshotRefreshed: true,
        snapshotSource: 'problem_log_snapshot'
      }
    };
  } catch (error) {
    console.warn('[copy-flow] [dispatch:conversation-snapshot-refresh-failed]', {
      trace: copyTrace,
      runId,
      responseId,
      error: error?.message || String(error)
    });
    return {
      payload: basePayload,
      analysis: {
        conversationLogCount: baseConversationLogCount,
        hasConversationUrl: !!conversationUrl || baseHasConversationUrl,
        snapshotRefreshed: false,
        snapshotSource: 'refresh_failed'
      }
    };
  }
}

function problemLogSourceMatches(sourceText, token) {
  const source = typeof sourceText === 'string' ? sourceText.trim().toLowerCase() : '';
  const normalizedToken = typeof token === 'string' ? token.trim().toLowerCase() : '';
  if (!source || !normalizedToken) return false;
  if (source === normalizedToken) return true;
  if (source.includes(`origin:${normalizedToken}`)) return true;
  return false;
}

function isLowSignalProblemLogEntry(entry) {
  if (!entry || typeof entry !== 'object') return false;
  const level = normalizeProblemLogLevel(entry.level);
  const source = typeof entry.source === 'string' ? entry.source.trim().toLowerCase() : '';
  const reason = typeof entry.reason === 'string' ? entry.reason.trim().toLowerCase() : '';
  const category = typeof entry.category === 'string' ? entry.category.trim().toLowerCase() : '';
  const error = typeof entry.error === 'string' ? entry.error.trim().toLowerCase() : '';
  const message = typeof entry.message === 'string' ? entry.message.trim().toLowerCase() : '';
  const noiseBlob = `${reason} ${error} ${message}`;

  if (reason === 'remote_connection_configured') return true;
  if (problemLogSourceMatches(source, 'dispatch-connection')) return true;
  if (problemLogSourceMatches(source, 'process-monitor-heartbeat')) return true;
  if (problemLogSourceMatches(source, 'process-monitor') && category === 'process_stream') {
    return entry.heartbeat === true;
  }
  if (
    problemLogSourceMatches(source, 'youtube-content-window')
    && noiseBlob.includes('resizeobserver loop completed with undelivered notifications')
  ) {
    return true;
  }
  if (level === 'info' && problemLogSourceMatches(source, 'youtube-content-window')) return true;
  return false;
}

function isLowSignalProblemLogPayload(payload) {
  if (!payload || typeof payload !== 'object') return false;
  const schema = typeof payload.schema === 'string' ? payload.schema.trim().toLowerCase() : '';
  const analysisType = typeof payload.analysisType === 'string' ? payload.analysisType.trim().toLowerCase() : '';
  if (schema !== PROBLEM_LOG_REMOTE_SCHEMA && !analysisType.startsWith('problem_log:')) return false;
  const stage = payload.stage && typeof payload.stage === 'object' ? payload.stage : {};
  const levelFromAnalysisType = analysisType.startsWith('problem_log:')
    ? analysisType.slice('problem_log:'.length)
    : '';
  return isLowSignalProblemLogEntry({
    level: stage.level || levelFromAnalysisType || 'info',
    source: stage.source || payload.source || '',
    reason: stage.reason || '',
    category: stage.category || '',
    error: stage.error || '',
    message: payload.text || ''
  });
}

function shouldDispatchProblemLogRemotely(entry) {
  if (!entry || typeof entry !== 'object') return false;
  if (entry.forceRemoteDispatch === true) return true;
  if (isLowSignalProblemLogEntry(entry)) return false;

  const level = normalizeProblemLogLevel(entry.level);
  if (level === 'error' || level === 'warn') return true;

  const source = typeof entry.source === 'string' ? entry.source.trim().toLowerCase() : '';
  const category = typeof entry.category === 'string' ? entry.category.trim().toLowerCase() : '';
  if (problemLogSourceMatches(source, 'process-monitor') && category === 'process_stream') {
    return entry.heartbeat !== true;
  }
  if (category === 'process_state' || category === 'data_gap' || category === 'recovery') return true;
  return false;
}

function shouldRecordIssueForProcess(process) {
  if (!process || typeof process !== 'object') return false;
  const status = normalizeProcessStatus(process.status);
  if (isFailedProcessStatus(status)) return true;
  if (process.needsAction === true) return true;
  const reason = typeof process.reason === 'string' ? process.reason.toLowerCase() : '';
  const error = typeof process.error === 'string' ? process.error.toLowerCase() : '';
  const statusText = typeof process.statusText === 'string' ? process.statusText.toLowerCase() : '';
  const markers = ['error', 'fail', 'timeout', 'invalid', 'not_ready', 'needs_action', 'critical'];
  return markers.some((marker) => reason.includes(marker) || error.includes(marker) || statusText.includes(marker));
}

function shouldRecordSuccessForProcess(process, status, stage) {
  if (!process || typeof process !== 'object') return false;
  if (shouldRecordIssueForProcess(process)) return false;
  if (isClosedProcessStatus(status) && status !== 'completed') return false;

  const currentPrompt = Number.isInteger(stage?.currentPrompt) ? stage.currentPrompt : null;
  const hasPromptProgress = currentPrompt !== null && currentPrompt > 0;
  if (status === 'completed') return true;
  if (status === 'starting' || status === 'started' || status === 'queued') return true;
  return hasPromptProgress;
}

function buildProcessSuccessReason(status, stage) {
  if (status === 'completed') return 'ok_completed';
  const currentPrompt = Number.isInteger(stage?.currentPrompt) ? stage.currentPrompt : null;
  if (currentPrompt !== null && currentPrompt > 0) return 'ok_progress';
  return 'ok_started';
}

function buildProcessSuccessStatusText(reason, stage) {
  const currentPrompt = Number.isInteger(stage?.currentPrompt) ? stage.currentPrompt : null;
  const totalPrompts = Number.isInteger(stage?.totalPrompts) ? stage.totalPrompts : null;
  const promptText = (currentPrompt !== null || totalPrompts !== null)
    ? `${currentPrompt !== null ? currentPrompt : '?'}/${totalPrompts !== null ? totalPrompts : '?'}`
    : '';
  if (reason === 'ok_completed') return promptText ? `completed ${promptText}` : 'completed';
  if (reason === 'ok_progress') return promptText ? `progress ${promptText}` : 'progress';
  return 'started';
}

function buildProcessStateReason(status, stage) {
  const normalizedStatus = normalizeProcessStatus(status);
  const currentPrompt = Number.isInteger(stage?.currentPrompt) ? stage.currentPrompt : null;
  if (normalizedStatus === 'running' && currentPrompt !== null && currentPrompt > 0) {
    return 'state_progress';
  }
  if (normalizedStatus === 'running') return 'state_running';
  return `state_${normalizedStatus || 'running'}`;
}

function buildProcessStateStatusText(status, stage) {
  const normalizedStatus = normalizeProcessStatus(status);
  const currentPrompt = Number.isInteger(stage?.currentPrompt) ? stage.currentPrompt : null;
  const totalPrompts = Number.isInteger(stage?.totalPrompts) ? stage.totalPrompts : null;
  if (currentPrompt !== null || totalPrompts !== null) {
    return `${normalizedStatus} ${currentPrompt !== null ? currentPrompt : '?'}/${totalPrompts !== null ? totalPrompts : '?'}`;
  }
  return normalizedStatus || 'running';
}

function resolveProcessStageSnapshot(process) {
  const totalPrompts = Number.isInteger(process?.totalPrompts) ? process.totalPrompts : null;
  let currentPrompt = Number.isInteger(process?.currentPrompt) ? process.currentPrompt : null;
  let stageIndex = Number.isInteger(process?.stageIndex) ? process.stageIndex : null;

  if (currentPrompt === null && stageIndex !== null && stageIndex >= 0) {
    currentPrompt = stageIndex + 1;
  }
  if (stageIndex === null && currentPrompt !== null && currentPrompt > 0) {
    stageIndex = currentPrompt - 1;
  }
  if (currentPrompt !== null && stageIndex !== null) {
    const promptFromStage = stageIndex + 1;
    if (currentPrompt < promptFromStage) currentPrompt = promptFromStage;
    const stageFromPrompt = currentPrompt - 1;
    if (stageIndex < stageFromPrompt) stageIndex = stageFromPrompt;
  }
  if (totalPrompts !== null && currentPrompt !== null && currentPrompt > totalPrompts) {
    currentPrompt = totalPrompts;
  }
  if (totalPrompts !== null && stageIndex !== null && stageIndex >= totalPrompts) {
    stageIndex = totalPrompts - 1;
  }

  const stageName = typeof process?.stageName === 'string' && process.stageName.trim()
    ? process.stageName.trim()
    : (currentPrompt !== null ? `Prompt ${currentPrompt}` : '');

  return {
    currentPrompt,
    totalPrompts,
    stageIndex,
    stageName
  };
}

function buildProcessProblemLogEntry(runId, process, options = {}) {
  if (!runId || !process || typeof process !== 'object') return null;

  const status = normalizeProcessStatus(process.status);
  const stage = resolveProcessStageSnapshot(process);
  const processChatUrl = extractProcessChatUrl(process);
  const processSourceUrl = normalizeProblemLogSourceUrl(
    typeof process.sourceUrl === 'string' ? process.sourceUrl : ''
  );
  const chatUrlSignature = trimProblemLogText(processChatUrl || '', 180);
  const sourceUrlSignature = trimProblemLogText(processSourceUrl || '', 180);
  const issueDetected = shouldRecordIssueForProcess(process);
  const successDetected = shouldRecordSuccessForProcess(process, status, stage);
  const stateDetected = !issueDetected && !successDetected;

  const reasonRaw = typeof process.reason === 'string' ? process.reason.trim() : '';
  const errorRaw = typeof process.error === 'string' ? process.error.trim() : '';
  const statusTextRaw = typeof process.statusText === 'string' ? process.statusText.trim() : '';
  const reason = issueDetected
    ? (reasonRaw || (isFailedProcessStatus(status) ? 'failed_status' : (process.needsAction ? 'needs_action' : 'process_issue')))
    : successDetected
      ? buildProcessSuccessReason(status, stage)
      : (reasonRaw || buildProcessStateReason(status, stage));
  const error = issueDetected ? errorRaw : '';
  const statusText = issueDetected
    ? (statusTextRaw || '')
    : successDetected
      ? buildProcessSuccessStatusText(reason, stage)
      : (statusTextRaw || buildProcessStateStatusText(status, stage));
  const message = issueDetected
    ? trimProblemLogText(statusTextRaw || reasonRaw || errorRaw || status || 'process_issue', 260)
    : successDetected
      ? trimProblemLogText(statusText || reason, 260)
      : trimProblemLogText(statusTextRaw || statusText || reason || status || 'process_state', 260);
  const signatureStatusText = trimProblemLogText(statusText || '', 120);

  const signature = [
    runId,
    issueDetected ? 'issue' : (successDetected ? 'ok' : 'state'),
    reason,
    status,
    error,
    Number.isInteger(stage.currentPrompt) ? stage.currentPrompt : '',
    Number.isInteger(stage.totalPrompts) ? stage.totalPrompts : '',
    Number.isInteger(stage.stageIndex) ? stage.stageIndex : '',
    stage.stageName || '',
    signatureStatusText,
    chatUrlSignature,
    sourceUrlSignature
  ].join('|');

  const level = issueDetected
    ? (isFailedProcessStatus(status) ? 'error' : 'warn')
    : (stateDetected && process.needsAction ? 'warn' : 'info');

  return {
    timestamp: Number.isInteger(process.timestamp) ? process.timestamp : Date.now(),
    level,
    source: 'process-monitor',
    category: isClosedProcessStatus(status) ? 'process_state' : 'process_stream',
    runId,
    title: process.title || '',
    analysisType: process.analysisType || '',
    status,
    reason,
    error,
    statusText,
    message,
    currentPrompt: Number.isInteger(stage.currentPrompt) ? stage.currentPrompt : null,
    totalPrompts: Number.isInteger(stage.totalPrompts) ? stage.totalPrompts : null,
    stageIndex: Number.isInteger(stage.stageIndex) ? stage.stageIndex : null,
    stageName: stage.stageName || '',
    tabId: Number.isInteger(process.tabId) ? process.tabId : null,
    windowId: Number.isInteger(process.windowId) ? process.windowId : null,
    sourceUrl: processSourceUrl || '',
    chatUrl: processChatUrl || '',
    conversationUrl: processChatUrl || '',
    heartbeat: options?.heartbeat === true,
    signature
  };
}

function shouldEmitProcessProblemHeartbeat(runId, process) {
  if (!runId || !process || typeof process !== 'object') return false;
  const status = normalizeProcessStatus(process.status);
  if (isClosedProcessStatus(status)) return false;
  const now = Date.now();
  const previous = processLogLastEmitTsByRunId.get(runId);
  const lastEmitTs = Number.isInteger(previous) ? previous : 0;
  return (now - lastEmitTs) >= PROCESS_STREAM_HEARTBEAT_MS;
}

function summarizeProblemErrorValue(rawValue) {
  if (rawValue == null) return '';
  if (typeof rawValue === 'string') return rawValue.trim();
  if (rawValue instanceof Error) return rawValue.message || rawValue.name || 'error';
  try {
    return JSON.stringify(rawValue);
  } catch {
    return String(rawValue);
  }
}

function buildConsoleProblemLogMessage(args = []) {
  const normalizedArgs = Array.isArray(args) ? args : [];
  const parts = [];
  for (let index = 0; index < normalizedArgs.length; index += 1) {
    const value = normalizedArgs[index];
    if (value == null) continue;
    if (typeof value === 'string') {
      const trimmed = value.trim();
      if (trimmed) parts.push(trimmed);
      continue;
    }
    if (value instanceof Error) {
      const text = (value.stack || value.message || value.name || '').trim();
      if (text) parts.push(text);
      continue;
    }
    if (typeof value === 'object') {
      try {
        const serialized = JSON.stringify(value);
        if (serialized && serialized.trim()) {
          parts.push(serialized.trim());
          continue;
        }
      } catch {
        // Fallback to string coercion below.
      }
    }
    const coerced = String(value).trim();
    if (coerced) parts.push(coerced);
  }
  const merged = parts.join(' | ');
  return trimProblemLogText(merged, PROBLEM_LOG_CONSOLE_CAPTURE_MESSAGE_MAX_LENGTH);
}

function pruneConsoleProblemDedupMap(nowTs) {
  if (problemLogConsoleErrorDedup.size <= PROBLEM_LOG_CONSOLE_CAPTURE_MAX_KEYS) return;
  const staleThreshold = nowTs - (PROBLEM_LOG_CONSOLE_CAPTURE_DEDUPE_MS * 4);
  for (const [key, timestamp] of problemLogConsoleErrorDedup.entries()) {
    if (!Number.isInteger(timestamp) || timestamp < staleThreshold) {
      problemLogConsoleErrorDedup.delete(key);
    }
    if (problemLogConsoleErrorDedup.size <= PROBLEM_LOG_CONSOLE_CAPTURE_MAX_KEYS) {
      return;
    }
  }
  while (problemLogConsoleErrorDedup.size > PROBLEM_LOG_CONSOLE_CAPTURE_MAX_KEYS) {
    const firstKey = problemLogConsoleErrorDedup.keys().next().value;
    if (!firstKey) break;
    problemLogConsoleErrorDedup.delete(firstKey);
  }
}

function shouldCaptureConsoleProblemMessage(message) {
  const normalized = typeof message === 'string' ? message.trim() : '';
  if (!normalized) return false;
  const lowered = normalized.toLowerCase();
  // Avoid feedback loops when dispatch itself is failing.
  if (
    lowered.includes('[db-dispatch]')
    || lowered.includes('[copy-flow] [dispatch')
    || lowered.includes('[problem-log]')
  ) {
    return false;
  }
  const nowTs = Date.now();
  const dedupKey = `console_error:${textFingerprint(normalized)}`;
  const previousTs = problemLogConsoleErrorDedup.get(dedupKey);
  if (Number.isInteger(previousTs) && (nowTs - previousTs) <= PROBLEM_LOG_CONSOLE_CAPTURE_DEDUPE_MS) {
    return false;
  }
  problemLogConsoleErrorDedup.set(dedupKey, nowTs);
  pruneConsoleProblemDedupMap(nowTs);
  return true;
}

function installBackgroundConsoleProblemCapture() {
  if (!PROBLEM_LOG_CONSOLE_CAPTURE_ENABLED) return;
  if (problemLogConsoleCaptureInstalled) return;
  if (!globalThis?.console || typeof globalThis.console.error !== 'function') return;

  const originalConsoleError = globalThis.console.error.bind(globalThis.console);
  try {
    globalThis.console.error = (...args) => {
      originalConsoleError(...args);
      if (problemLogConsoleCaptureInProgress) return;
      const message = buildConsoleProblemLogMessage(args);
      if (!shouldCaptureConsoleProblemMessage(message)) return;

      problemLogConsoleCaptureInProgress = true;
      try {
        reportRuntimeProblemEvent({
          level: 'error',
          source: 'background-console',
          title: 'Background console error',
          reason: 'console_error',
          error: trimProblemLogText(message, 240),
          message: trimProblemLogText(message, 260),
          signature: ['background-console-error', textFingerprint(message)].join('|')
        });
      } catch {
        // Ignore capture-side failures to avoid affecting runtime.
      } finally {
        problemLogConsoleCaptureInProgress = false;
      }
    };
    problemLogConsoleCaptureInstalled = true;
  } catch (error) {
    originalConsoleError('[problem-log] console capture install failed:', error?.message || String(error));
  }
}

function buildRuntimeProblemLogEntry(rawEntry = {}) {
  if (!rawEntry || typeof rawEntry !== 'object') return null;
  const source = trimProblemLogText(rawEntry.source || 'runtime', 80) || 'runtime';
  const reason = trimProblemLogText(rawEntry.reason || '', 140);
  const errorText = trimProblemLogText(rawEntry.error || '', 200);
  const message = trimProblemLogText(rawEntry.message || '', 260);
  const signature = trimProblemLogText(
    rawEntry.signature || [
      'runtime',
      source,
      normalizeProblemLogLevel(rawEntry.level),
      reason,
      errorText,
      message
    ].join('|'),
    380
  );
  return {
    timestamp: Number.isInteger(rawEntry.timestamp) ? rawEntry.timestamp : Date.now(),
    level: normalizeProblemLogLevel(rawEntry.level),
    source,
    title: trimProblemLogText(rawEntry.title || '', 160),
    status: trimProblemLogText(rawEntry.status || '', 40),
    reason,
    error: errorText,
    statusText: trimProblemLogText(rawEntry.statusText || '', 240),
    message: message || 'runtime_problem',
    tabId: Number.isInteger(rawEntry.tabId) ? rawEntry.tabId : null,
    windowId: Number.isInteger(rawEntry.windowId) ? rawEntry.windowId : null,
    signature
  };
}

function reportRuntimeProblemEvent(rawEntry = {}) {
  const prepared = buildRuntimeProblemLogEntry(rawEntry);
  if (!prepared) return;
  void appendProblemLog(prepared).catch((error) => {
    console.warn('[problem-log] runtime event append failed:', error?.message || String(error));
  });
}

function summarizeAdminActionDetails(rawDetails) {
  if (rawDetails == null) return '';
  if (typeof rawDetails === 'string') return trimProblemLogText(rawDetails, 240);
  try {
    return trimProblemLogText(JSON.stringify(rawDetails), 240);
  } catch {
    return '';
  }
}

function reportAdminActionEvent(actionName, options = {}) {
  const action = trimProblemLogText(actionName || '', 80) || 'admin_action';
  const level = normalizeProblemLogLevel(options?.level || 'info');
  const status = trimProblemLogText(options?.status || '', 40)
    || (level === 'error' ? 'failed' : 'ok');
  const reason = trimProblemLogText(options?.reason || '', 140)
    || (level === 'error' ? `${action}_failed` : action);
  const origin = trimProblemLogText(options?.origin || '', 80);
  const details = summarizeAdminActionDetails(options?.details);
  const errorText = trimProblemLogText(options?.error || '', 200);
  const statusText = [origin ? `origin=${origin}` : '', details]
    .filter(Boolean)
    .join(' | ');
  const message = trimProblemLogText(
    options?.message
      || [action, status, statusText].filter(Boolean).join(' | '),
    260
  ) || 'admin_action';
  const signature = trimProblemLogText(
    [
      'admin-action',
      action,
      status,
      reason,
      origin,
      Date.now(),
      Math.random().toString(36).slice(2, 8)
    ].join('|'),
    380
  );

  void appendProblemLog({
    timestamp: Date.now(),
    level,
    source: 'admin-action',
    title: trimProblemLogText(options?.title || `Admin action: ${action}`, 160),
    category: 'admin',
    analysisType: 'admin',
    status,
    reason,
    error: errorText,
    statusText,
    message,
    signature
  }).catch((error) => {
    console.warn('[problem-log] admin action append failed:', error?.message || String(error));
  });
}

installBackgroundConsoleProblemCapture();

async function upsertProcess(runId, patch = {}) {
  if (!runId) return null;
  await ensureProcessRegistryReady();
  const patchData = (patch && typeof patch === 'object')
    ? { ...patch }
    : {};

  const existing = processRegistry.get(runId) || {
    id: runId,
    title: 'Bez tytulu',
    analysisType: 'company',
    status: 'starting',
    currentPrompt: 0,
    totalPrompts: 0,
    startedAt: Date.now(),
    timestamp: Date.now(),
    needsAction: false,
    messages: []
  };

  const existingStatus = normalizeProcessStatus(existing.status);
  if (existingStatus === 'stopped' && !patchData.forceStatusOverride) {
    const requestedStatus = typeof patchData.status === 'string'
      ? normalizeProcessStatus(patchData.status)
      : '';
    if (!requestedStatus || requestedStatus !== 'stopped') {
      patchData.status = 'stopped';
    }
    patchData.needsAction = false;
    if (!patchData.reason && typeof existing.reason === 'string') {
      patchData.reason = existing.reason;
    }
    if (!patchData.statusText && typeof existing.statusText === 'string') {
      patchData.statusText = existing.statusText;
    }
  }
  delete patchData.forceStatusOverride;

  const next = normalizeProcessRecord({
    ...existing,
    ...patchData,
    id: runId,
    startedAt: existing.startedAt || Date.now(),
    timestamp: Number.isInteger(patchData.timestamp) ? patchData.timestamp : Date.now()
  });

  if (!next) return null;
  mergeProcessConversationUrls(existing, next);
  const problemEntry = buildProcessProblemLogEntry(runId, next);
  const knownSignature = problemLogLastSignatureByRunId.get(runId) || '';
  const signatureChanged = !!(problemEntry?.signature && problemEntry.signature !== knownSignature);
  const heartbeatDue = !!(problemEntry?.signature && !signatureChanged && shouldEmitProcessProblemHeartbeat(runId, next));
  if (problemEntry && heartbeatDue && !signatureChanged) {
    problemEntry.heartbeat = true;
  }
  if (problemEntry?.signature && (signatureChanged || heartbeatDue)) {
    const emittedEntry = await appendProblemLog(problemEntry);
    if (emittedEntry) {
      processLogLastEmitTsByRunId.set(runId, Date.now());
    }
    problemLogLastSignatureByRunId.set(runId, problemEntry.signature);
  } else if (!problemEntry) {
    problemLogLastSignatureByRunId.delete(runId);
    processLogLastEmitTsByRunId.delete(runId);
    processStaleWarnLastEmitTsByRunId.delete(runId);
  } else if (isClosedProcessStatus(next.status)) {
    processLogLastEmitTsByRunId.delete(runId);
    processStaleWarnLastEmitTsByRunId.delete(runId);
  }
  processRegistry.set(runId, next);
  logProcessTransition(runId, next, patchData);
  await persistProcessRegistry();
  await broadcastProcessUpdate();
  return next;
}

async function markInterruptedProcessesForClosedTab(tabId) {
  if (!Number.isInteger(tabId)) {
    return { matched: 0, marked: 0 };
  }
  await ensureProcessRegistryReady();
  const candidates = Array.from(processRegistry.values()).filter((process) => (
    process
    && !isClosedProcessStatus(process.status)
    && Number.isInteger(process.tabId)
    && process.tabId === tabId
  ));
  if (candidates.length === 0) {
    return { matched: 0, marked: 0 };
  }

  let marked = 0;
  for (const process of candidates) {
    if (!hasUnfinishedProcessExecutionEvidence(process)) {
      continue;
    }
    await upsertProcess(process.id, {
      status: 'stopped',
      statusText: 'Karta ChatGPT zamknieta - proces przerwany',
      reason: 'tab_closed',
      needsAction: false,
      tabId: null,
      windowId: null,
      finishedAt: Date.now(),
      timestamp: Date.now()
    });
    marked += 1;
  }

  if (marked > 0) {
    reportAdminActionEvent('processes_marked_stopped_on_tab_close', {
      level: 'warn',
      status: 'updated',
      reason: 'tab_closed',
      origin: 'tabs.onRemoved',
      details: {
        tabId,
        matched: candidates.length,
        marked
      }
    });
  }

  return {
    matched: candidates.length,
    marked
  };
}

function resolveProcessConversationUrlFromMessage(message, sender) {
  const candidates = [
    typeof message?.chatUrl === 'string' ? message.chatUrl : '',
    typeof message?.conversationUrl === 'string' ? message.conversationUrl : '',
    getTabEffectiveUrl(sender?.tab)
  ];
  for (const candidate of candidates) {
    const normalized = normalizeChatConversationUrl(candidate);
    if (normalized) return normalized;
  }
  return '';
}

async function findProcessIdByTabId(tabId) {
  if (!Number.isInteger(tabId)) return null;
  await ensureProcessRegistryReady();

  for (const process of processRegistry.values()) {
    if (process.tabId === tabId && !isClosedProcessStatus(process.status)) {
      return process.id;
    }
  }
  for (const process of processRegistry.values()) {
    if (process.tabId === tabId) {
      return process.id;
    }
  }
  return null;
}

async function resolveProcessId(message, sender) {
  if (typeof message?.runId === 'string' && message.runId.trim()) {
    return message.runId;
  }
  const messageTabId = Number.isInteger(message?.tabId) ? message.tabId : null;
  const senderTabId = Number.isInteger(sender?.tab?.id) ? sender.tab.id : null;
  const tabId = messageTabId ?? senderTabId;
  return findProcessIdByTabId(tabId);
}

async function hasActiveProcessForTab(tabId) {
  if (!Number.isInteger(tabId)) return false;
  const process = await getActiveProcessForTab(tabId);
  return !!process;
}

async function getActiveProcessForTab(tabId) {
  if (!Number.isInteger(tabId)) return null;
  await ensureProcessRegistryReady();
  let latest = null;
  let latestTs = -1;
  for (const process of processRegistry.values()) {
    if (!process || process.tabId !== tabId) continue;
    if (isClosedProcessStatus(process.status)) continue;
    const ts = Number.isInteger(process.timestamp)
      ? process.timestamp
      : (Number.isInteger(process.startedAt) ? process.startedAt : 0);
    if (ts >= latestTs) {
      latestTs = ts;
      latest = process;
    }
  }
  return latest;
}

function removeWindowSafe(windowId) {
  return new Promise((resolve) => {
    if (!Number.isInteger(windowId)) {
      resolve(false);
      return;
    }
    try {
      chrome.windows.remove(windowId, () => {
        if (chrome.runtime.lastError) {
          resolve(false);
          return;
        }
        resolve(true);
      });
    } catch (error) {
      resolve(false);
    }
  });
}

function removeTabSafe(tabId) {
  return new Promise((resolve) => {
    if (!Number.isInteger(tabId)) {
      resolve(false);
      return;
    }
    try {
      chrome.tabs.remove(tabId, () => {
        if (chrome.runtime.lastError) {
          resolve(false);
          return;
        }
        resolve(true);
      });
    } catch (error) {
      resolve(false);
    }
  });
}

function getTabGroupIdNone() {
  return Number.isInteger(chrome?.tabGroups?.TAB_GROUP_ID_NONE)
    ? chrome.tabGroups.TAB_GROUP_ID_NONE
    : -1;
}

async function ungroupTabsById(tabIds, options = {}) {
  const requestedTabIds = Array.from(
    new Set(
      (Array.isArray(tabIds) ? tabIds : [tabIds])
        .map((value) => (Number.isInteger(value) ? value : null))
        .filter((value) => value !== null)
    )
  );

  const baseResult = {
    ok: false,
    reason: 'unknown',
    requested: requestedTabIds.length,
    groupedCount: 0,
    ungroupedCount: 0,
    skippedCount: 0,
    error: '',
    requestedTabIds,
    groupedTabIds: [],
    origin: typeof options?.origin === 'string' ? options.origin : ''
  };

  if (requestedTabIds.length === 0) {
    return {
      ...baseResult,
      reason: 'no_tab_ids',
      ok: true,
      skippedCount: 0
    };
  }

  if (!chrome?.tabs?.ungroup) {
    return {
      ...baseResult,
      reason: 'ungroup_api_unavailable',
      error: 'chrome.tabs.ungroup is not available'
    };
  }

  const noneGroupId = getTabGroupIdNone();
  const tabLookups = await Promise.all(requestedTabIds.map((tabId) => getTabByIdSafe(tabId)));
  const groupedTabIds = tabLookups
    .map((tab) => (Number.isInteger(tab?.id) && Number.isInteger(tab?.groupId) && tab.groupId !== noneGroupId ? tab.id : null))
    .filter((tabId) => Number.isInteger(tabId));
  const uniqueGroupedTabIds = Array.from(new Set(groupedTabIds));

  if (uniqueGroupedTabIds.length === 0) {
    return {
      ...baseResult,
      reason: 'already_ungrouped',
      ok: true,
      groupedCount: 0,
      ungroupedCount: 0,
      skippedCount: requestedTabIds.length,
      groupedTabIds: []
    };
  }

  const ungroupResult = await new Promise((resolve) => {
    try {
      chrome.tabs.ungroup(uniqueGroupedTabIds, () => {
        if (chrome.runtime.lastError) {
          resolve({
            ok: false,
            reason: 'ungroup_runtime_error',
            error: chrome.runtime.lastError.message || 'ungroup_runtime_error'
          });
          return;
        }
        resolve({
          ok: true,
          reason: 'ungrouped',
          error: ''
        });
      });
    } catch (error) {
      resolve({
        ok: false,
        reason: 'ungroup_exception',
        error: error?.message || String(error)
      });
    }
  });

  return {
    ...baseResult,
    ...ungroupResult,
    groupedCount: uniqueGroupedTabIds.length,
    ungroupedCount: ungroupResult.ok ? uniqueGroupedTabIds.length : 0,
    skippedCount: requestedTabIds.length - uniqueGroupedTabIds.length,
    groupedTabIds: uniqueGroupedTabIds
  };
}

async function ungroupChatGptTabsInWindow(windowId, options = {}) {
  const origin = typeof options?.origin === 'string' ? options.origin : '';
  if (!Number.isInteger(windowId)) {
    return {
      ok: false,
      reason: 'invalid_window_id',
      windowId: null,
      requested: 0,
      groupedCount: 0,
      ungroupedCount: 0,
      skippedCount: 0,
      error: '',
      origin
    };
  }

  const queryResult = await queryTabsInWindowSafe(windowId);
  if (!queryResult.ok) {
    return {
      ok: false,
      reason: queryResult.reason || 'query_tabs_failed',
      windowId,
      requested: 0,
      groupedCount: 0,
      ungroupedCount: 0,
      skippedCount: 0,
      error: queryResult.reason || '',
      origin
    };
  }

  const tabs = Array.isArray(queryResult.tabs) ? queryResult.tabs : [];
  const chatTabIds = tabs
    .filter((tab) => isChatGptUrl(getTabEffectiveUrl(tab)))
    .map((tab) => (Number.isInteger(tab?.id) ? tab.id : null))
    .filter((tabId) => Number.isInteger(tabId));

  if (chatTabIds.length === 0) {
    return {
      ok: true,
      reason: 'no_chat_tabs',
      windowId,
      requested: 0,
      groupedCount: 0,
      ungroupedCount: 0,
      skippedCount: 0,
      error: '',
      origin
    };
  }

  const ungroupResult = await ungroupTabsById(chatTabIds, { origin });
  return {
    ...ungroupResult,
    windowId,
    requested: chatTabIds.length,
    reason: ungroupResult.reason || 'ungroup_result_missing_reason',
    origin
  };
}

function matchesWindowScope(process, windowId) {
  if (!Number.isInteger(windowId)) return true;
  if (!process || typeof process !== 'object') return false;
  return (
    process.windowId === windowId ||
    process.invocationWindowId === windowId ||
    process.sourceWindowId === windowId
  );
}

function requestProcessForceStopOnTab(tabId, payload = {}, timeoutMs = 1200) {
  return new Promise((resolve) => {
    if (!Number.isInteger(tabId)) {
      resolve({
        sent: false,
        acknowledged: false,
        reason: 'invalid_tab_id'
      });
      return;
    }

    let settled = false;
    const finish = (result) => {
      if (settled) return;
      settled = true;
      resolve(result);
    };

    const timer = setTimeout(() => {
      finish({
        sent: false,
        acknowledged: false,
        reason: 'timeout'
      });
    }, Math.max(200, timeoutMs));

    try {
      const forceStopMessage = {
        type: 'PROCESS_FORCE_STOP',
        reason: typeof payload.reason === 'string' ? payload.reason : 'manual_stop',
        origin: typeof payload.origin === 'string' ? payload.origin : 'background'
      };
      if (typeof payload.runId === 'string' && payload.runId.trim()) {
        forceStopMessage.runId = payload.runId.trim();
      }

      chrome.tabs.sendMessage(
        tabId,
        forceStopMessage,
        (response) => {
          clearTimeout(timer);
          if (chrome.runtime.lastError) {
            finish({
              sent: false,
              acknowledged: false,
              reason: chrome.runtime.lastError.message || 'runtime_error'
            });
            return;
          }

          const acknowledged = !!(
            response?.acknowledged ||
            response?.success ||
            response?.stopped
          );

          finish({
            sent: true,
            acknowledged,
            reason: acknowledged ? 'ack' : 'no_ack'
          });
        }
      );
    } catch (error) {
      clearTimeout(timer);
      finish({
        sent: false,
        acknowledged: false,
        reason: error?.message || String(error)
      });
    }
  });
}

function extractResponseIdFromCopyTrace(copyTrace, expectedRunId = '') {
  if (typeof copyTrace !== 'string' || !copyTrace.trim()) return '';
  const trimmed = copyTrace.trim();
  const separator = trimmed.lastIndexOf('/');
  if (separator < 0 || separator >= trimmed.length - 1) return '';
  const runPart = trimmed.slice(0, separator).trim();
  const responsePart = trimmed.slice(separator + 1).trim();
  if (!responsePart || responsePart === 'no-response') return '';
  if (typeof expectedRunId === 'string' && expectedRunId.trim() && runPart && runPart !== expectedRunId.trim()) {
    return '';
  }
  return responsePart;
}

function collectKnownProcessResponseIds(process, expectedRunId = '') {
  const ids = new Set();
  if (!process || typeof process !== 'object') return ids;

  const runId = typeof expectedRunId === 'string' ? expectedRunId.trim() : '';
  const traces = [];

  if (typeof process?.completedResponseSaveTrace === 'string' && process.completedResponseSaveTrace.trim()) {
    traces.push(process.completedResponseSaveTrace.trim());
  }
  if (typeof process?.persistenceStatus?.copyTrace === 'string' && process.persistenceStatus.copyTrace.trim()) {
    traces.push(process.persistenceStatus.copyTrace.trim());
  }
  if (typeof process?.restartReplay?.copyTrace === 'string' && process.restartReplay.copyTrace.trim()) {
    traces.push(process.restartReplay.copyTrace.trim());
  }

  for (const trace of traces) {
    const responseId = extractResponseIdFromCopyTrace(trace, runId);
    if (responseId) ids.add(responseId);
  }

  const directIds = [
    process?.finalStagePersistence?.responseId,
    process?.restartReplay?.responseId
  ];
  for (const candidate of directIds) {
    if (typeof candidate !== 'string') continue;
    const normalized = candidate.trim();
    if (normalized) ids.add(normalized);
  }

  return ids;
}

function createDeliveredDispatchSnapshot(previousDispatch = {}, responseId = '', details = {}) {
  const prev = previousDispatch && typeof previousDispatch === 'object'
    ? previousDispatch
    : {};
  const sent = Number.isInteger(prev.sent) ? Math.max(prev.sent, 1) : 1;
  const failed = Number.isInteger(prev.failed) ? Math.max(0, prev.failed) : 0;
  const normalizedResponseId = typeof responseId === 'string' ? responseId.trim() : '';
  const dbVerification = normalizeWatchlistDbVerification(details?.dbVerification || prev.dbVerification);
  const nextState = isWatchlistDbVerificationSuccessful(dbVerification)
    ? 'dispatch_confirmed'
    : 'dispatch_accepted_unverified';
  return {
    ...prev,
    queued: true,
    queueSize: 0,
    queueSkipped: false,
    queueSkipReason: '',
    flushSkipped: false,
    flushSkipReason: '',
    flushFollowUpScheduled: false,
    sent,
    failed,
    deferred: 0,
    remaining: 0,
    firstFailure: '',
    failureStage: '',
    failureReason: '',
    failureStatus: null,
    failureRequestId: '',
    failureIntakeUrl: '',
    state: nextState,
    responseId: normalizedResponseId || (typeof prev.responseId === 'string' ? prev.responseId : ''),
    dbVerification
  };
}

function getProcessSuccessfulDbVerification(process, expectedResponseId = '') {
  const normalizedExpectedResponseId = typeof expectedResponseId === 'string' ? expectedResponseId.trim() : '';
  const candidates = [
    process?.persistenceStatus?.dispatch?.dbVerification,
    process?.completedResponseDispatch?.dbVerification,
    process?.finalStagePersistence?.dbVerification
  ];
  for (const candidate of candidates) {
    const verification = normalizeWatchlistDbVerification(candidate);
    if (!isWatchlistDbVerificationSuccessful(verification)) continue;
    if (
      normalizedExpectedResponseId
      && typeof verification?.responseId === 'string'
      && verification.responseId.trim()
      && verification.responseId.trim() !== normalizedExpectedResponseId
    ) {
      continue;
    }
    return verification;
  }
  return null;
}

async function maybeAutoCloseProcessAfterDbVerify(runId = '', options = {}) {
  const normalizedRunId = typeof runId === 'string' ? runId.trim() : '';
  if (!normalizedRunId) {
    return { closed: false, reason: 'missing_run_id' };
  }

  await ensureProcessRegistryReady();
  const process = processRegistry.get(normalizedRunId) || null;
  if (!process || typeof process !== 'object') {
    return { closed: false, reason: 'process_missing' };
  }

  const status = normalizeProcessStatus(process.status);
  if (status !== 'completed' && status !== 'completed_with_errors') {
    return { closed: false, reason: 'process_not_completed' };
  }
  if (Number.isInteger(process?.autoClosedAfterDbVerifyAt)) {
    return { closed: false, reason: 'already_auto_closed' };
  }

  const verification = getProcessSuccessfulDbVerification(process, options?.responseId || '');
  if (!verification) {
    return { closed: false, reason: 'db_verify_not_confirmed' };
  }

  const processTabId = Number.isInteger(options?.tabId)
    ? options.tabId
    : (Number.isInteger(process?.tabId) ? process.tabId : null);
  const processWindowId = Number.isInteger(options?.windowId)
    ? options.windowId
    : (Number.isInteger(process?.windowId) ? process.windowId : null);

  let closed = false;
  if (processTabId !== null) {
    closed = await removeTabSafe(processTabId);
  }
  if (!closed && processWindowId !== null) {
    const tabsInWindow = await queryTabsInWindowSafe(processWindowId);
    const validTabs = Array.isArray(tabsInWindow?.tabs)
      ? tabsInWindow.tabs.filter((tab) => Number.isInteger(tab?.id))
      : [];
    const hasOnlyProcessTab = validTabs.length === 1
      && processTabId !== null
      && validTabs[0].id === processTabId;
    if (hasOnlyProcessTab) {
      closed = await removeWindowSafe(processWindowId);
    }
  }

  const now = Date.now();
  const origin = typeof options?.origin === 'string' && options.origin.trim()
    ? options.origin.trim()
    : 'db_verify';
  const patch = {
    autoCloseAfterDbVerifyAttemptedAt: now,
    autoCloseAfterDbVerifyState: closed ? 'closed' : 'close_failed',
    autoCloseAfterDbVerifyOrigin: origin,
    timestamp: now
  };
  if (closed) {
    patch.autoClosedAfterDbVerifyAt = now;
    patch.tabId = null;
    patch.windowId = null;
  }
  await upsertProcess(normalizedRunId, patch);

  console.log('[copy-flow] [process:auto-close-after-db-verify]', {
    runId: normalizedRunId,
    responseId: verification.responseId || '',
    eventId: verification.eventId ?? null,
    origin,
    closed
  });
  return {
    closed,
    reason: closed ? 'closed' : 'close_failed'
  };
}

async function updateProcessDispatchAfterSendSuccess(runId = '', responseId = '', details = {}) {
  const normalizedRunId = typeof runId === 'string' ? runId.trim() : '';
  if (!normalizedRunId) return false;

  const normalizedResponseId = typeof responseId === 'string' ? responseId.trim() : '';
  const process = processRegistry.get(normalizedRunId) || null;
  if (!process || typeof process !== 'object') return false;

  if (normalizedResponseId) {
    const knownResponseIds = collectKnownProcessResponseIds(process, normalizedRunId);
    if (knownResponseIds.size > 0 && !knownResponseIds.has(normalizedResponseId)) {
      return false;
    }
  }

  const now = Date.now();
  const previousPersistenceStatus = process?.persistenceStatus && typeof process.persistenceStatus === 'object'
    ? process.persistenceStatus
    : {};
  const previousDispatch = previousPersistenceStatus?.dispatch && typeof previousPersistenceStatus.dispatch === 'object'
    ? previousPersistenceStatus.dispatch
    : (process?.completedResponseDispatch && typeof process.completedResponseDispatch === 'object'
      ? process.completedResponseDispatch
      : {});

  const normalizedDbVerification = normalizeWatchlistDbVerification(details?.dbVerification);
  const nextDispatch = createDeliveredDispatchSnapshot(previousDispatch, normalizedResponseId, {
    dbVerification: normalizedDbVerification
  });
  const dispatchSummary = formatDispatchUiSummary(nextDispatch);
  const previousLog = Array.isArray(previousPersistenceStatus?.dispatchProcessLog)
    ? previousPersistenceStatus.dispatchProcessLog
    : [];
  const deliveryLogEntry = [
    'dispatch_delivery',
    'ok',
    `responseId=${normalizedResponseId || 'n/a'}`,
    `status=${Number.isInteger(details?.status) ? details.status : 'n/a'}`,
    `eventId=${Number.isInteger(details?.eventId) ? details.eventId : (typeof details?.eventId === 'string' && details.eventId.trim() ? details.eventId.trim() : 'n/a')}`,
    `requestId=${typeof details?.requestId === 'string' && details.requestId.trim() ? details.requestId.trim() : 'n/a'}`,
    `dbVerify=${normalizedDbVerification?.success ? 'ok' : (normalizedDbVerification?.state || 'n/a')}`
  ].join('|');
  const nextLog = [...previousLog.slice(-15), deliveryLogEntry];

  const patch = {
    completedResponseDispatch: nextDispatch,
    completedResponseDispatchSummary: dispatchSummary,
    completedResponseDispatchProcessLog: nextLog.slice(-16),
    persistenceStatus: {
      ...previousPersistenceStatus,
      hasResponse: true,
      saveOk: true,
      saveError: '',
      dispatch: nextDispatch,
      dispatchSummary,
      dispatchProcessLog: nextLog.slice(-16),
      updatedAt: now
    },
    timestamp: now
  };

  const previousFinalStagePersistence = process?.finalStagePersistence && typeof process.finalStagePersistence === 'object'
    ? process.finalStagePersistence
    : null;
  if (previousFinalStagePersistence && previousFinalStagePersistence.success === true) {
    const previousFinalSent = Number.isInteger(previousFinalStagePersistence.sent)
      ? previousFinalStagePersistence.sent
      : 0;
    const previousFinalFailed = Number.isInteger(previousFinalStagePersistence.failed)
      ? previousFinalStagePersistence.failed
      : 0;
    patch.finalStagePersistence = {
      ...previousFinalStagePersistence,
      sent: Math.max(previousFinalSent, nextDispatch.sent || 0),
      failed: Math.max(previousFinalFailed, nextDispatch.failed || 0),
      deferred: 0,
      remaining: 0,
      pending: 0,
      queueSkipped: false,
      queueSkipReason: '',
      flushSkipped: false,
      flushSkipReason: '',
      failureStage: '',
      failureReason: '',
      failureStatus: null,
      failureRequestId: '',
      failureIntakeUrl: '',
      state: nextDispatch.state,
      dispatchSummary,
      dbVerification: normalizedDbVerification || previousFinalStagePersistence?.dbVerification || null,
      updatedAt: now
    };
  }

  await upsertProcess(normalizedRunId, patch);
  await maybeAutoCloseProcessAfterDbVerify(normalizedRunId, {
    responseId: normalizedResponseId,
    origin: 'dispatch_delivery'
  }).catch(() => {});
  return true;
}

function buildRestartReplayResponseId(runId = '', responseText = '', promptNumber = 0) {
  const safeRunId = typeof runId === 'string' && runId.trim()
    ? runId.trim().replace(/[^a-zA-Z0-9._-]/g, '_')
    : 'run';
  const safePromptNumber = Number.isInteger(promptNumber) && promptNumber > 0 ? promptNumber : 0;
  const fp = textFingerprint(responseText || '');
  return `${safeRunId}_restart_p${safePromptNumber}_${fp}`;
}

function extractAssistantTextFromProcess(process) {
  if (!process || typeof process !== 'object') return '';
  if (typeof process.completedResponseText === 'string' && process.completedResponseText.trim()) {
    return process.completedResponseText.trim();
  }
  const messages = Array.isArray(process.messages) ? process.messages : [];
  for (let i = messages.length - 1; i >= 0; i -= 1) {
    const message = messages[i];
    if (!message || message.role !== 'assistant') continue;
    const text = typeof message.text === 'string' ? message.text.trim() : '';
    if (text) return text;
  }
  return '';
}

async function extractLastAssistantResponseFromTab(tabId, maxWaitMs = 1800) {
  if (!Number.isInteger(tabId)) return '';
  try {
    const results = await chrome.scripting.executeScript({
      target: { tabId },
      function: async (waitMs) => {
        const sleep = (ms) => new Promise((resolve) => setTimeout(resolve, ms));
        const compact = (text) => (text || '').replace(/\s+/g, ' ').trim();

        function extractTextFromNode(node) {
          if (!node) return '';
          const clone = node.cloneNode(true);
          const removableSelectors = [
            '[data-testid="copy-turn-action-button"]',
            '[data-testid="message-actions"]',
            'button',
            'svg',
            'aside',
            'nav',
            'footer'
          ];
          removableSelectors.forEach((selector) => {
            clone.querySelectorAll(selector).forEach((child) => child.remove());
          });
          return compact(clone.innerText || clone.textContent || '');
        }

        function readAssistantText() {
          const byRole = Array.from(document.querySelectorAll('[data-message-author-role="assistant"]'));
          for (let i = byRole.length - 1; i >= 0; i -= 1) {
            const text = extractTextFromNode(byRole[i]);
            if (text) return text;
          }
          const conversationTurns = Array.from(document.querySelectorAll('[data-testid^="conversation-turn-"]'));
          for (let i = conversationTurns.length - 1; i >= 0; i -= 1) {
            const turn = conversationTurns[i];
            const candidate = turn.querySelector('[data-message-author-role="assistant"]') || turn;
            const text = extractTextFromNode(candidate);
            if (text) return text;
          }
          const articles = Array.from(document.querySelectorAll('article'));
          for (let i = articles.length - 1; i >= 0; i -= 1) {
            const text = extractTextFromNode(articles[i]);
            if (text) return text;
          }
          return '';
        }

        const startedAt = Date.now();
        let best = '';
        while ((Date.now() - startedAt) <= waitMs) {
          const candidate = readAssistantText();
          if (candidate.length > best.length) {
            best = candidate;
          }
          if (best.length >= 50) break;
          await sleep(220);
        }
        return best;
      },
      args: [Math.max(500, Math.min(maxWaitMs, 12000))]
    });
    const text = typeof results?.[0]?.result === 'string' ? results[0].result.trim() : '';
    return text;
  } catch (error) {
    return '';
  }
}

async function replayCompletedResponseForProcess(process, options = {}) {
  if (!process || typeof process !== 'object') {
    return { attempted: false, success: false, reason: 'invalid_process' };
  }

  const currentPrompt = Number.isInteger(process.currentPrompt) ? process.currentPrompt : 0;
  const totalPrompts = Number.isInteger(process.totalPrompts) ? process.totalPrompts : 0;
  const statusText = typeof process.statusText === 'string' ? process.statusText.toLowerCase() : '';
  const hasCompletedPayload = typeof process.completedResponseText === 'string' && process.completedResponseText.trim().length > 0;
  const likelyFinalStage = hasCompletedPayload
    || (Number.isInteger(process.completedResponseLength) && process.completedResponseLength > 0)
    || (totalPrompts > 0 && currentPrompt >= totalPrompts)
    || statusText.includes('trwa zapis do bazy')
    || statusText.includes('zakonczony');
  if (!likelyFinalStage && options?.force !== true) {
    return { attempted: false, success: false, reason: 'not_final_stage' };
  }

  const alreadySaved = process?.completedResponseSaved === true || process?.persistenceStatus?.saveOk === true;
  if (alreadySaved && options?.force !== true) {
    return { attempted: false, success: true, reason: 'already_saved' };
  }

  const runId = typeof process.id === 'string' ? process.id : '';
  const analysisType = typeof process.analysisType === 'string' && process.analysisType.trim()
    ? process.analysisType.trim()
    : 'company';
  const source = typeof process.title === 'string' && process.title.trim()
    ? process.title.trim()
    : 'Restart replay';

  let responseText = extractAssistantTextFromProcess(process);
  if (!responseText && Number.isInteger(options?.tabId)) {
    responseText = await extractLastAssistantResponseFromTab(options.tabId, options?.tabReadTimeoutMs || 1800);
  }
  if (!responseText) {
    return { attempted: false, success: false, reason: 'missing_response_text' };
  }

  const existingTrace = typeof process.completedResponseSaveTrace === 'string' && process.completedResponseSaveTrace.trim()
    ? process.completedResponseSaveTrace.trim()
    : (typeof process?.persistenceStatus?.copyTrace === 'string' ? process.persistenceStatus.copyTrace.trim() : '');
  const responseIdFromTrace = extractResponseIdFromCopyTrace(existingTrace, runId);
  const promptNumber = Number.isInteger(process.currentPrompt) && process.currentPrompt > 0
    ? process.currentPrompt
    : (Number.isInteger(process.stageIndex) && process.stageIndex >= 0 ? (process.stageIndex + 1) : 0);
  const responseId = responseIdFromTrace || buildRestartReplayResponseId(runId, responseText, promptNumber);

  const stageMeta = {};
  if (promptNumber > 0) {
    stageMeta.selected_response_prompt = promptNumber;
  }
  if (Number.isInteger(process.stageIndex) && process.stageIndex >= 0) {
    stageMeta.selected_response_stage_index = process.stageIndex;
  } else if (promptNumber > 0) {
    stageMeta.selected_response_stage_index = promptNumber - 1;
  }
  stageMeta.selected_response_reason = 'restart_replay';

  const conversationUrl = normalizeChatConversationUrl(process.chatUrl)
    || normalizeChatConversationUrl(process.sourceUrl)
    || null;

  const saveResult = await saveResponse(
    responseText,
    source,
    analysisType,
    runId || null,
    responseId,
    stageMeta,
    conversationUrl
  );

  if (!saveResult?.success) {
    return {
      attempted: true,
      success: false,
      reason: 'save_response_failed',
      responseId,
      responseLength: responseText.length
    };
  }

  const dispatchSummary = formatDispatchUiSummary(saveResult.dispatch);
  return {
    attempted: true,
    success: true,
    reason: 'saved',
    responseId,
    responseLength: responseText.length,
    verifiedCount: Number.isInteger(saveResult?.verifiedCount) ? saveResult.verifiedCount : null,
    copyTrace: typeof saveResult.copyTrace === 'string' ? saveResult.copyTrace : '',
    dispatch: saveResult.dispatch && typeof saveResult.dispatch === 'object'
      ? saveResult.dispatch
      : null,
    dispatchProcessLog: Array.isArray(saveResult.dispatchProcessLog) ? saveResult.dispatchProcessLog.slice(-16) : [],
    conversationAnalysis: saveResult.conversationAnalysis && typeof saveResult.conversationAnalysis === 'object'
      ? saveResult.conversationAnalysis
      : null,
    dispatchSummary
  };
}

function summarizeFinalStagePersistence(result) {
  if (!result || typeof result !== 'object') return null;
  const dispatch = result?.dispatch && typeof result.dispatch === 'object'
    ? result.dispatch
    : null;
  const sent = Number.isInteger(dispatch?.sent) ? dispatch.sent : null;
  const failed = Number.isInteger(dispatch?.failed) ? dispatch.failed : null;
  const deferred = Number.isInteger(dispatch?.deferred) ? dispatch.deferred : null;
  const remaining = Number.isInteger(dispatch?.remaining) ? dispatch.remaining : null;
  const failureStage = typeof dispatch?.failureStage === 'string' && dispatch.failureStage.trim()
    ? dispatch.failureStage.trim()
    : '';
  const failureReason = typeof dispatch?.failureReason === 'string' && dispatch.failureReason.trim()
    ? dispatch.failureReason.trim()
    : '';
  const failureStatus = Number.isInteger(dispatch?.failureStatus) ? dispatch.failureStatus : null;
  const failureRequestId = typeof dispatch?.failureRequestId === 'string' && dispatch.failureRequestId.trim()
    ? dispatch.failureRequestId.trim()
    : '';
  const failureIntakeUrl = typeof dispatch?.failureIntakeUrl === 'string' && dispatch.failureIntakeUrl.trim()
    ? dispatch.failureIntakeUrl.trim()
    : '';
  const conversationAnalysis = result?.conversationAnalysis && typeof result.conversationAnalysis === 'object'
    ? result.conversationAnalysis
    : null;
  const conversationLogCountRaw = Number.isInteger(dispatch?.conversationLogCount)
    ? dispatch.conversationLogCount
    : (Number.isInteger(conversationAnalysis?.conversationLogCount) ? conversationAnalysis.conversationLogCount : null);
  const conversationLogCount = Number.isInteger(conversationLogCountRaw)
    ? Math.max(0, conversationLogCountRaw)
    : null;
  const hasConversationUrl = dispatch?.hasConversationUrl === true || conversationAnalysis?.hasConversationUrl === true;
  const conversationSnapshotRefreshed = dispatch?.conversationSnapshotRefreshed === true
    || conversationAnalysis?.snapshotRefreshedBeforeSend === true;
  const conversationSnapshotSource = (typeof dispatch?.conversationSnapshotSource === 'string' && dispatch.conversationSnapshotSource.trim())
    ? dispatch.conversationSnapshotSource.trim()
    : (typeof conversationAnalysis?.snapshotSource === 'string' ? conversationAnalysis.snapshotSource.trim() : '');
  const state = typeof dispatch?.state === 'string' && dispatch.state.trim()
    ? dispatch.state.trim()
    : '';
  const dbVerification = normalizeWatchlistDbVerification(dispatch?.dbVerification);
  return {
    attempted: result.attempted === true,
    success: result.success === true,
    reason: typeof result.reason === 'string' ? result.reason : '',
    responseId: typeof result.responseId === 'string' ? result.responseId : '',
    copyTrace: typeof result.copyTrace === 'string' ? result.copyTrace : '',
    dispatchSummary: typeof result.dispatchSummary === 'string' ? result.dispatchSummary : '',
    verifiedCount: Number.isInteger(result?.verifiedCount) ? result.verifiedCount : null,
    sent,
    failed,
    deferred,
    remaining,
    pending: (deferred ?? 0) + (remaining ?? 0),
    queueSkipped: dispatch?.queueSkipped === true,
    queueSkipReason: typeof dispatch?.queueSkipReason === 'string' ? dispatch.queueSkipReason : '',
    flushSkipped: dispatch?.flushSkipped === true,
    flushSkipReason: typeof dispatch?.flushSkipReason === 'string' ? dispatch.flushSkipReason : '',
    flushFollowUpScheduled: dispatch?.flushFollowUpScheduled === true,
    failureStage,
    failureReason,
    failureStatus,
    failureRequestId,
    failureIntakeUrl,
    conversationLogCount,
    hasConversationUrl,
    conversationSnapshotRefreshed,
    conversationSnapshotSource,
    state,
    dbVerification
  };
}

async function ensureCompletedProcessResponsePersisted(process, options = {}) {
  if (!process || typeof process !== 'object') {
    return { attempted: false, success: false, reason: 'invalid_process' };
  }

  const runId = typeof process?.id === 'string' ? process.id.trim() : '';
  const tabId = Number.isInteger(options?.tabId)
    ? options.tabId
    : (Number.isInteger(process?.tabId) ? process.tabId : null);
  const force = options?.force === true;
  const origin = typeof options?.origin === 'string' && options.origin.trim()
    ? options.origin.trim()
    : 'resume_final_stage_persist_check';

  let replayResult = null;
  try {
    replayResult = await replayCompletedResponseForProcess(process, {
      force,
      tabId,
      tabReadTimeoutMs: Number.isInteger(options?.tabReadTimeoutMs) ? options.tabReadTimeoutMs : 2200
    });
  } catch (error) {
    replayResult = {
      attempted: false,
      success: false,
      reason: error?.message || String(error)
    };
  }

  if (!runId) {
    return replayResult;
  }

  const now = Date.now();
  const patch = {
    finalStagePersistence: {
      ...summarizeFinalStagePersistence(replayResult),
      origin,
      forced: force,
      updatedAt: now
    },
    timestamp: now
  };

  if (replayResult?.attempted && replayResult?.success) {
    patch.completedResponseSaved = true;
    if (typeof replayResult.copyTrace === 'string' && replayResult.copyTrace.trim()) {
      patch.completedResponseSaveTrace = replayResult.copyTrace.trim();
    }
    if (replayResult.dispatch && typeof replayResult.dispatch === 'object') {
      patch.completedResponseDispatch = replayResult.dispatch;
      patch.completedResponseDispatchSummary = replayResult.dispatchSummary || formatDispatchUiSummary(replayResult.dispatch);
      patch.completedResponseDispatchProcessLog = Array.isArray(replayResult.dispatchProcessLog)
        ? replayResult.dispatchProcessLog.slice(-16)
        : [];
    }
    const previousStatus = process?.persistenceStatus && typeof process.persistenceStatus === 'object'
      ? process.persistenceStatus
      : {};
    patch.persistenceStatus = {
      ...previousStatus,
      hasResponse: true,
      saveOk: true,
      dispatchSummary: replayResult.dispatchSummary || formatDispatchUiSummary(replayResult.dispatch),
      copyTrace: replayResult.copyTrace || '',
      saveError: '',
      dispatch: replayResult.dispatch || null,
      dispatchProcessLog: Array.isArray(replayResult.dispatchProcessLog)
        ? replayResult.dispatchProcessLog.slice(-16)
        : [],
      updatedAt: now
    };
  }

  await upsertProcess(runId, patch);
  return replayResult;
}

async function stopSingleProcess(process, options = {}) {
  if (!process || isClosedProcessStatus(process.status)) return false;

  const runId = process.id;
  if (!runId) return false;

  const reason = typeof options.reason === 'string' && options.reason.trim()
    ? options.reason.trim()
    : 'manual_stop';
  const statusText = typeof options.statusText === 'string' && options.statusText.trim()
    ? options.statusText.trim()
    : 'Przerwano przez uzytkownika';
  const now = Date.now();

  const preserveWindowId = Number.isInteger(options.preserveWindowId)
    ? options.preserveWindowId
    : null;
  const processWindowId = Number.isInteger(process.windowId) ? process.windowId : null;
  const processTabId = Number.isInteger(process.tabId) ? process.tabId : null;
  const replayOnRestart = options?.replayLatestResponse === true
    || reason === 'restarted_in_same_window';
  const forceReplayLatestResponse = options?.forceReplayLatestResponse === true;
  let replayResult = null;

  if (reason === 'restarted_in_same_window' && processTabId !== null) {
    const restartUngroup = await ungroupTabsById([processTabId], {
      origin: 'restart-stop-single-process'
    });
    if (!restartUngroup.ok && restartUngroup.reason !== 'already_ungrouped') {
      console.warn('[restart] ungroup process tab failed:', {
        runId,
        tabId: processTabId,
        reason: restartUngroup.reason,
        error: restartUngroup.error || ''
      });
    }
  }

  if (replayOnRestart) {
    replayResult = await replayCompletedResponseForProcess(process, {
      force: forceReplayLatestResponse,
      tabId: processTabId,
      tabReadTimeoutMs: 1800
    });
    console.log('[restart] replay-last-response', {
      runId,
      attempted: replayResult?.attempted === true,
      success: replayResult?.success === true,
      reason: replayResult?.reason || '',
      responseId: replayResult?.responseId || '',
      copyTrace: replayResult?.copyTrace || ''
    });
  }

  if (processTabId !== null) {
    await requestProcessForceStopOnTab(processTabId, {
      runId,
      reason,
      origin: options.origin || 'background'
    });
  }

  let tabClosed = false;
  if (processTabId !== null) {
    tabClosed = await removeTabSafe(processTabId);
  }

  // Fallback: close the whole window only when it is a dedicated process window
  // with no extra tabs (to avoid closing source/info windows).
  if (!tabClosed && processWindowId !== null && processWindowId !== preserveWindowId) {
    const tabsInWindow = await queryTabsInWindowSafe(processWindowId);
    const validTabs = Array.isArray(tabsInWindow?.tabs)
      ? tabsInWindow.tabs.filter((tab) => Number.isInteger(tab?.id))
      : [];
    const hasOnlyProcessTab = validTabs.length === 1
      && processTabId !== null
      && validTabs[0].id === processTabId;
    if (hasOnlyProcessTab) {
      await removeWindowSafe(processWindowId);
    }
  }

  const stopPatch = {
    status: 'stopped',
    statusText,
    reason,
    needsAction: false,
    finishedAt: now,
    timestamp: now
  };

  if (replayResult?.attempted) {
    stopPatch.restartReplay = {
      attempted: true,
      success: replayResult?.success === true,
      reason: replayResult?.reason || '',
      responseId: replayResult?.responseId || '',
      copyTrace: replayResult?.copyTrace || '',
      updatedAt: now
    };
  }

  if (replayResult?.attempted && replayResult?.success) {
    stopPatch.completedResponseSaved = true;
    if (typeof replayResult.copyTrace === 'string' && replayResult.copyTrace.trim()) {
      stopPatch.completedResponseSaveTrace = replayResult.copyTrace.trim();
    }
    if (replayResult.dispatch && typeof replayResult.dispatch === 'object') {
      stopPatch.completedResponseDispatch = replayResult.dispatch;
      stopPatch.completedResponseDispatchSummary = replayResult.dispatchSummary || formatDispatchUiSummary(replayResult.dispatch);
    }
    const previousStatus = process?.persistenceStatus && typeof process.persistenceStatus === 'object'
      ? process.persistenceStatus
      : {};
    stopPatch.persistenceStatus = {
      ...previousStatus,
      hasResponse: true,
      saveOk: true,
      dispatchSummary: replayResult.dispatchSummary || formatDispatchUiSummary(replayResult.dispatch),
      copyTrace: replayResult.copyTrace || '',
      saveError: '',
      dispatch: replayResult.dispatch || null,
      updatedAt: now
    };
  }

  await upsertProcess(runId, stopPatch);

  return true;
}

async function stopActiveProcesses(options = {}) {
  await ensureProcessRegistryReady();
  const targetWindowId = Number.isInteger(options.windowId) ? options.windowId : null;
  const preserveWindowId = Number.isInteger(options.preserveWindowId) ? options.preserveWindowId : null;

  const candidates = Array.from(processRegistry.values()).filter((process) => {
    if (!process || isClosedProcessStatus(process.status)) return false;
    return matchesWindowScope(process, targetWindowId);
  });

  let stopped = 0;
  for (const process of candidates) {
    const didStop = await stopSingleProcess(process, {
      reason: options.reason,
      statusText: options.statusText,
      origin: options.origin,
      preserveWindowId,
      replayLatestResponse: options?.replayLatestResponse === true,
      forceReplayLatestResponse: options?.forceReplayLatestResponse === true
    });
    if (didStop) stopped += 1;
  }

  return {
    matched: candidates.length,
    stopped,
    windowId: targetWindowId
  };
}

function queryTabsInWindowSafe(windowId) {
  return new Promise((resolve) => {
    if (!Number.isInteger(windowId)) {
      resolve({ ok: false, tabs: [], reason: 'invalid_window_id' });
      return;
    }

    try {
      chrome.tabs.query({ windowId }, (tabs) => {
        if (chrome.runtime.lastError) {
          resolve({
            ok: false,
            tabs: [],
            reason: chrome.runtime.lastError.message || 'runtime_error'
          });
          return;
        }
        resolve({
          ok: true,
          tabs: Array.isArray(tabs) ? tabs : [],
          reason: ''
        });
      });
    } catch (error) {
      resolve({
        ok: false,
        tabs: [],
        reason: error?.message || String(error)
      });
    }
  });
}

async function forceReloadWindowTabs(windowId, options = {}) {
  const timeoutMs = Number.isInteger(options.timeoutMs) && options.timeoutMs > 0
    ? options.timeoutMs
    : 15000;
  const bypassCache = options.bypassCache !== false;
  const skipTabIds = options?.skipTabIds instanceof Set ? options.skipTabIds : new Set();
  const queryResult = await queryTabsInWindowSafe(windowId);

  if (!queryResult.ok) {
    return {
      ok: false,
      windowId,
      totalTabs: 0,
      attemptedTabIds: [],
      reloadedTabs: 0,
      failedTabs: 0,
      reason: queryResult.reason || 'query_tabs_failed'
    };
  }

  const tabs = Array.isArray(queryResult.tabs) ? queryResult.tabs : [];
  const attemptedTabIds = [];
  let reloadedTabs = 0;
  let failedTabs = 0;

  for (const tab of tabs) {
    const tabId = Number.isInteger(tab?.id) ? tab.id : null;
    if (tabId === null || skipTabIds.has(tabId)) continue;

    attemptedTabIds.push(tabId);
    const reloadResult = await forceReloadTab(tabId, { timeoutMs, bypassCache });
    if (reloadResult?.ok) {
      reloadedTabs += 1;
    } else {
      failedTabs += 1;
    }
  }

  return {
    ok: true,
    windowId,
    totalTabs: tabs.length,
    attemptedTabIds,
    reloadedTabs,
    failedTabs,
    reason: ''
  };
}

async function forceStopAndReloadProcessContext(process, options = {}) {
  const timeoutMs = Number.isInteger(options.timeoutMs) && options.timeoutMs > 0
    ? options.timeoutMs
    : 15000;
  const bypassCache = options.bypassCache !== false;
  const reloadedWindowIds = options?.reloadedWindowIds instanceof Set
    ? options.reloadedWindowIds
    : new Set();
  const seenTabIds = new Set();
  const processTabId = Number.isInteger(process?.tabId) ? process.tabId : null;
  const processWindowId = Number.isInteger(process?.windowId) ? process.windowId : null;

  let tabReloads = 0;
  let tabReloadFailures = 0;
  let windowReloads = 0;
  let windowReloadFailures = 0;

  if (processTabId !== null) {
    seenTabIds.add(processTabId);
    const reloadResult = await forceReloadTab(processTabId, { timeoutMs, bypassCache });
    if (reloadResult?.ok) {
      tabReloads += 1;
    } else {
      tabReloadFailures += 1;
    }
  }

  if (processWindowId !== null && !reloadedWindowIds.has(processWindowId)) {
    reloadedWindowIds.add(processWindowId);

    const windowReloadResult = await forceReloadWindowTabs(processWindowId, {
      timeoutMs,
      bypassCache,
      skipTabIds: seenTabIds
    });

    if (windowReloadResult.ok) {
      windowReloads += 1;
      tabReloads += windowReloadResult.reloadedTabs;
      tabReloadFailures += windowReloadResult.failedTabs;
    } else {
      windowReloadFailures += 1;
    }
  }

  return {
    tabReloads,
    tabReloadFailures,
    windowReloads,
    windowReloadFailures
  };
}

async function resetTrackedProcessesForBulkRun(options = {}) {
  await ensureProcessRegistryReady();

  const clearHistory = options?.clearHistory !== false;
  const reason = typeof options?.reason === 'string' && options.reason.trim()
    ? options.reason.trim()
    : 'bulk_reset_before_detect_resume';
  const statusText = typeof options?.statusText === 'string' && options.statusText.trim()
    ? options.statusText.trim()
    : 'Reset przed globalnym uruchomieniem';
  const origin = typeof options?.origin === 'string' && options.origin.trim()
    ? options.origin.trim()
    : 'bulk-reset';
  const now = Date.now();

  const currentRecords = pruneProcessRecords(Array.from(processRegistry.values()));
  const nextRecords = [];

  let activeBefore = 0;
  let resetCount = 0;
  let historyRetained = 0;
  let stopSignalsSent = 0;
  let stopSignalsAcked = 0;
  let tabReloads = 0;
  let tabReloadFailures = 0;
  let windowReloads = 0;
  let windowReloadFailures = 0;
  const reloadedWindowIds = new Set();

  for (const process of currentRecords) {
    if (!process || typeof process !== 'object') continue;
    const isActive = !isClosedProcessStatus(process.status);

    if (isActive) {
      activeBefore += 1;

      // Try graceful stop first; fallback to tab reload to hard-stop injected execution.
      if (Number.isInteger(process.tabId)) {
        const stopResult = await requestProcessForceStopOnTab(process.tabId, {
          runId: process.id,
          reason,
          origin
        });
        if (stopResult.sent) {
          stopSignalsSent += 1;
        }
        if (stopResult.acknowledged) {
          stopSignalsAcked += 1;
        }
      }

      // Always force a reload of process context during reset.
      // This guarantees that in-tab execution is interrupted even when force-stop was acknowledged.
      const reloadSummary = await forceStopAndReloadProcessContext(process, {
        timeoutMs: 15000,
        bypassCache: true,
        reloadedWindowIds
      });
      tabReloads += reloadSummary.tabReloads;
      tabReloadFailures += reloadSummary.tabReloadFailures;
      windowReloads += reloadSummary.windowReloads;
      windowReloadFailures += reloadSummary.windowReloadFailures;

      const resetRecord = normalizeProcessRecord({
        ...process,
        status: 'stopped',
        statusText,
        reason,
        needsAction: false,
        autoRecovery: null,
        finishedAt: Number.isInteger(process.finishedAt) ? process.finishedAt : now,
        timestamp: now
      });
      if (resetRecord) {
        nextRecords.push(resetRecord);
        resetCount += 1;
      }
      continue;
    }

    if (!clearHistory) {
      nextRecords.push(process);
      historyRetained += 1;
    }
  }

  processRegistry.clear();
  nextRecords.forEach((record) => {
    if (record?.id) processRegistry.set(record.id, record);
  });

  await persistProcessRegistry();
  await broadcastProcessUpdate();

  return {
    clearHistory,
    activeBefore,
    resetCount,
    historyRetained,
    stopSignalsSent,
    stopSignalsAcked,
    tabReloads,
    tabReloadFailures,
    windowReloads,
    windowReloadFailures,
    uniqueWindowsReloaded: reloadedWindowIds.size,
    totalAfter: nextRecords.length
  };
}

function applyMonotonicProcessPatch(existing, patch, message = null) {
  if (!patch || typeof patch !== 'object') return patch;
  if (!existing || typeof existing !== 'object') return patch;

  const next = { ...patch };
  const incomingStatus = normalizeProcessStatus(next.status || existing.status);
  const incomingClosed = isClosedProcessStatus(incomingStatus);
  const existingClosed = isClosedProcessStatus(existing.status);
  const allowLowerProgress = !!message?.allowLowerProgress || incomingClosed;

  if (existingClosed && !incomingClosed) {
    next.status = existing.status;
    next.needsAction = false;
  }

  if (Number.isInteger(existing.totalPrompts) && Number.isInteger(next.totalPrompts)) {
    if (next.totalPrompts < existing.totalPrompts && !incomingClosed) {
      next.totalPrompts = existing.totalPrompts;
    }
  }

  if (Number.isInteger(existing.currentPrompt) && Number.isInteger(next.currentPrompt)) {
    if (next.currentPrompt < existing.currentPrompt && !allowLowerProgress) {
      next.currentPrompt = existing.currentPrompt;
    }
  }

  if (Number.isInteger(existing.stageIndex) && Number.isInteger(next.stageIndex)) {
    if (next.stageIndex < existing.stageIndex && !allowLowerProgress) {
      next.stageIndex = existing.stageIndex;
    }
  }

  if (!Number.isInteger(next.currentPrompt) && Number.isInteger(next.stageIndex) && next.stageIndex >= 0) {
    next.currentPrompt = next.stageIndex + 1;
  }
  if (!Number.isInteger(next.stageIndex) && Number.isInteger(next.currentPrompt) && next.currentPrompt > 0) {
    next.stageIndex = next.currentPrompt - 1;
  }
  if (Number.isInteger(next.currentPrompt) && Number.isInteger(next.stageIndex)) {
    const promptFromStage = next.stageIndex + 1;
    if (next.currentPrompt < promptFromStage) {
      next.currentPrompt = promptFromStage;
    }
    const stageFromPrompt = next.currentPrompt - 1;
    if (next.stageIndex < stageFromPrompt) {
      next.stageIndex = stageFromPrompt;
    }
  }
  if (Number.isInteger(next.currentPrompt) && next.currentPrompt > 0) {
    const normalizedPromptStageName = `Prompt ${next.currentPrompt}`;
    if (typeof next.stageName !== 'string' || /^Prompt\s+\d+/i.test(next.stageName.trim())) {
      next.stageName = normalizedPromptStageName;
    }
  }

  return next;
}

async function handleProcessProgressMessage(message, sender) {
  const runId = await resolveProcessId(message, sender);
  if (!runId) return false;

  const patch = {
    timestamp: Date.now(),
    needsAction: !!message?.needsAction
  };

  if (typeof message?.status === 'string' && message.status.trim()) {
    patch.status = message.status;
  } else {
    patch.status = 'running';
  }
  if (Number.isInteger(message?.currentPrompt)) patch.currentPrompt = message.currentPrompt;
  if (Number.isInteger(message?.totalPrompts)) patch.totalPrompts = message.totalPrompts;
  if (typeof message?.statusText === 'string') patch.statusText = message.statusText;
  if (typeof message?.reason === 'string') patch.reason = message.reason;
  if (Number.isInteger(message?.stageIndex)) patch.stageIndex = message.stageIndex;
  if (typeof message?.stageName === 'string') patch.stageName = message.stageName;
  const conversationUrl = resolveProcessConversationUrlFromMessage(message, sender);
  if (conversationUrl) patch.chatUrl = conversationUrl;
  if (typeof message?.sourceUrl === 'string') patch.sourceUrl = message.sourceUrl;
  if (typeof message?.analysisType === 'string' && message.analysisType.trim()) patch.analysisType = message.analysisType.trim();
  if (typeof message?.title === 'string' && message.title.trim()) patch.title = message.title.trim();
  if (Number.isInteger(message?.tabId)) patch.tabId = message.tabId;
  if (Number.isInteger(message?.windowId)) patch.windowId = message.windowId;

  await ensureProcessRegistryReady();
  const existing = processRegistry.get(runId) || null;
  const safePatch = applyMonotonicProcessPatch(existing, patch, message);
  await upsertProcess(runId, safePatch);
  return true;
}

async function handleProcessNeedsActionMessage(message, sender) {
  const runId = await resolveProcessId(message, sender);
  if (!runId) return false;
  const patch = {
    status: 'running',
    needsAction: true,
    timestamp: Date.now()
  };
  if (Number.isInteger(message?.currentPrompt)) patch.currentPrompt = message.currentPrompt;
  if (Number.isInteger(message?.totalPrompts)) patch.totalPrompts = message.totalPrompts;
  if (Number.isInteger(message?.stageIndex)) patch.stageIndex = message.stageIndex;
  if (typeof message?.stageName === 'string') patch.stageName = message.stageName;
  if (typeof message?.statusText === 'string') patch.statusText = message.statusText;
  if (typeof message?.reason === 'string') patch.reason = message.reason;
  const conversationUrl = resolveProcessConversationUrlFromMessage(message, sender);
  if (conversationUrl) patch.chatUrl = conversationUrl;
  if (typeof message?.analysisType === 'string' && message.analysisType.trim()) patch.analysisType = message.analysisType.trim();
  if (typeof message?.title === 'string' && message.title.trim()) patch.title = message.title.trim();
  if (Number.isInteger(message?.tabId)) patch.tabId = message.tabId;
  if (Number.isInteger(message?.windowId)) patch.windowId = message.windowId;
  await ensureProcessRegistryReady();
  const existing = processRegistry.get(runId) || null;
  const safePatch = applyMonotonicProcessPatch(existing, patch, message);
  await upsertProcess(runId, safePatch);
  return true;
}

function getDecisionResolvedStatusText(decision) {
  return decision === 'skip' ? 'Pominieto czekanie' : 'Wznowiono czekanie';
}

async function handleProcessActionResolvedMessage(message, sender) {
  const runId = await resolveProcessId(message, sender);
  if (!runId) return false;
  const decision = message?.decision === 'skip' ? 'skip' : 'wait';
  const patch = {
    status: 'running',
    needsAction: false,
    reason: '',
    statusText: getDecisionResolvedStatusText(decision),
    timestamp: Date.now()
  };
  const conversationUrl = resolveProcessConversationUrlFromMessage(message, sender);
  if (conversationUrl) patch.chatUrl = conversationUrl;
  if (typeof message?.analysisType === 'string' && message.analysisType.trim()) patch.analysisType = message.analysisType.trim();
  if (typeof message?.title === 'string' && message.title.trim()) patch.title = message.title.trim();
  if (Number.isInteger(message?.tabId)) patch.tabId = message.tabId;
  if (Number.isInteger(message?.windowId)) patch.windowId = message.windowId;
  await upsertProcess(runId, patch);
  return true;
}

async function handleProcessDecisionMessage(message) {
  const runId = await resolveProcessId(message, { tab: { id: message?.tabId } });
  if (!runId) return false;

  await ensureProcessRegistryReady();
  const process = processRegistry.get(runId) || null;
  const decision = message?.decision === 'skip' ? 'skip' : 'wait';

  const targetTabId = Number.isInteger(message?.tabId)
    ? message.tabId
    : (Number.isInteger(process?.tabId) ? process.tabId : null);

  let forwarded = false;
  if (Number.isInteger(targetTabId)) {
    try {
      await chrome.tabs.sendMessage(targetTabId, {
        type: 'PROCESS_DECISION',
        runId,
        decision,
        origin: message?.origin || 'panel'
      });
      forwarded = true;
    } catch (error) {
      console.warn('[monitor] Unable to forward PROCESS_DECISION to tab:', targetTabId, error?.message || error);
    }
  }

  if (forwarded) {
    const patch = {
      status: isClosedProcessStatus(process?.status) ? process.status : 'running',
      needsAction: false,
      reason: '',
      statusText: getDecisionResolvedStatusText(decision),
      timestamp: Date.now()
    };
    if (typeof message?.analysisType === 'string' && message.analysisType.trim()) patch.analysisType = message.analysisType.trim();
    if (typeof message?.title === 'string' && message.title.trim()) patch.title = message.title.trim();
    if (Number.isInteger(message?.tabId)) patch.tabId = message.tabId;
    if (Number.isInteger(message?.windowId)) patch.windowId = message.windowId;
    await upsertProcess(runId, patch);
    return true;
  }

  await upsertProcess(runId, {
    status: isClosedProcessStatus(process?.status) ? process.status : 'running',
    needsAction: true,
    statusText: 'Panel: decyzja niedostarczona (brak aktywnej karty)',
    timestamp: Date.now()
  });
  return false;
}

async function handleProcessDecisionAllMessage(message) {
  await ensureProcessRegistryReady();
  const decision = message?.decision === 'skip' ? 'skip' : 'wait';
  const candidates = Array.from(processRegistry.values()).filter((process) => (
    process &&
    !isClosedProcessStatus(process.status) &&
    !!process.needsAction
  ));

  let delivered = 0;
  for (const process of candidates) {
    const handled = await handleProcessDecisionMessage({
      runId: process.id,
      decision,
      origin: message?.origin || 'panel-bulk',
      tabId: Number.isInteger(process.tabId) ? process.tabId : null,
      windowId: Number.isInteger(process.windowId) ? process.windowId : null
    });
    if (handled) delivered += 1;
  }

  return {
    matched: candidates.length,
    delivered
  };
}

// Zmienne globalne dla promptów
