if (typeof globalThis?.addEventListener === 'function') {
  globalThis.addEventListener('error', (event) => {
    const fileName = trimProblemLogText(event?.filename || '', 180);
    const lineNo = Number.isInteger(event?.lineno) ? event.lineno : null;
    const colNo = Number.isInteger(event?.colno) ? event.colno : null;
    const locationSuffix = fileName
      ? `${fileName}${lineNo !== null ? `:${lineNo}` : ''}${colNo !== null ? `:${colNo}` : ''}`
      : '';
    const eventError = summarizeProblemErrorValue(event?.error || event?.message || '');
    reportRuntimeProblemEvent({
      level: 'error',
      source: 'background-runtime',
      title: 'Background runtime error',
      reason: locationSuffix || 'service_worker_error',
      error: eventError,
      message: trimProblemLogText(event?.message || eventError || 'runtime_error', 260),
      signature: [
        'background-runtime-error',
        locationSuffix,
        event?.message || '',
        eventError
      ].join('|')
    });
  });

  globalThis.addEventListener('unhandledrejection', (event) => {
    const reasonText = summarizeProblemErrorValue(event?.reason);
    reportRuntimeProblemEvent({
      level: 'error',
      source: 'background-runtime',
      title: 'Unhandled promise rejection',
      reason: 'unhandledrejection',
      error: trimProblemLogText(reasonText, 240),
      message: trimProblemLogText(reasonText || 'unhandled_promise_rejection', 260),
      signature: ['background-runtime-rejection', reasonText].join('|')
    });
  });
}

if (chrome?.runtime?.onConnect) {
  chrome.runtime.onConnect.addListener((port) => {
    const providerId = extractManualPdfProviderIdFromPort(port);
    if (!providerId) return;

    manualPdfProviderPorts.set(providerId, {
      port,
      lastSeenAt: Date.now()
    });
    console.log('[manual-pdf] provider keepalive connected:', {
      providerId
    });

    if (port?.onMessage?.addListener) {
      port.onMessage.addListener((message) => {
        const incomingProviderId = typeof message?.providerId === 'string'
          ? message.providerId.trim()
          : '';
        if (!incomingProviderId || incomingProviderId !== providerId) return;
        const record = manualPdfProviderPorts.get(providerId);
        if (!record || record.port !== port) return;
        record.lastSeenAt = Date.now();
        manualPdfProviderPorts.set(providerId, record);
      });
    }

    if (port?.onDisconnect?.addListener) {
      port.onDisconnect.addListener(() => {
        const record = manualPdfProviderPorts.get(providerId);
        if (record && record.port === port) {
          manualPdfProviderPorts.delete(providerId);
        }
        console.log('[manual-pdf] provider keepalive disconnected:', {
          providerId
        });
      });
    }
  });
}

if (chrome?.alarms?.onAlarm) {
  chrome.alarms.onAlarm.addListener((alarm) => {
    if (!alarm || typeof alarm.name !== 'string') return;

    if (alarm.name === WATCHLIST_DISPATCH.alarmName) {
      logWatchlistDispatchStatusSnapshot('alarm:before_flush', false, { alarmName: alarm.name }).catch(() => {});
      flushWatchlistDispatchOutbox('alarm').catch((error) => {
        console.warn('[copy-flow] [dispatch:flush-error] reason=alarm', error);
      });
      return;
    }

    if (alarm.name === PROCESS_MONITOR_HEARTBEAT.alarmName) {
      runProcessMonitorHeartbeatSweep('alarm').catch((error) => {
        console.warn('[monitor] process heartbeat alarm failed:', error);
      });
      return;
    }

    if (alarm.name === AUTO_RESTORE_WINDOWS.alarmName) {
      runAutoRestoreWindowsCycle({ origin: 'auto_restore_alarm' }).catch((error) => {
        console.warn('[auto-restore] cycle failed:', error);
      });
      return;
    }

    if (alarm.name === REMOTE_RUNNER.alarmName) {
      runRemoteRunnerMaintenance('alarm').catch((error) => {
        console.warn('[remote-runner] maintenance alarm failed:', error);
      });
    }
  });
}
